insert into questions (tech, category, difficulty, prompt, options, correct, explanation) values
  ('GitHub Copilot', 'AI Tooling', 'easy', 'What is GitHub Copilot?', '["An AI pair-programmer that suggests code","A version control system","A CI pipeline","A bundler"]'::jsonb, 0, 'Copilot suggests code completions and snippets inside your editor.'),
  ('GitHub Copilot', 'AI Tooling', 'easy', 'Where does Copilot integrate?', '["In the editor/IDE","In the database","In the CI runner","In the browser only"]'::jsonb, 0, 'It runs as an extension in editors like VS Code and JetBrains IDEs.'),
  ('GitHub Copilot', 'AI Tooling', 'easy', 'What primarily drives its suggestions?', '["Your surrounding code and comments (context)","Random sampling","Your git history only","The CI logs"]'::jsonb, 0, 'Copilot uses the current file context and prompts to predict completions.'),
  ('GitHub Copilot', 'AI Tooling', 'easy', 'Besides code, what can it help generate?', '["Tests, comments, and boilerplate","Database backups","Container images","DNS records"]'::jsonb, 0, 'It can draft tests, docs, and repetitive boilerplate.'),
  ('GitHub Copilot', 'AI Tooling', 'easy', 'What is Copilot Chat?', '["A conversational coding assistant in the IDE","A team chat app","A log viewer","A terminal emulator"]'::jsonb, 0, 'Copilot Chat lets you ask questions and request changes conversationally.'),
  ('GitHub Copilot', 'AI Tooling', 'mid', 'Why should you review Copilot''s suggestions?', '["They can be wrong, insecure, or outdated","They are always correct","They are compiler-verified","They never repeat public code"]'::jsonb, 0, 'Suggestions are predictions, not verified facts, so review is essential.'),
  ('GitHub Copilot', 'AI Tooling', 'mid', 'What context does Copilot mainly use?', '["Open/related files and the surrounding code","The entire internet live","Only the function name","Your terminal history"]'::jsonb, 0, 'It draws on nearby code and open files within its context limits.'),
  ('GitHub Copilot', 'AI Tooling', 'mid', 'What improves suggestion quality?', '["Clear names, comments, and types","Obfuscated code","Removing all comments","Longer files only"]'::jsonb, 0, 'Descriptive context guides the model toward relevant completions.'),
  ('GitHub Copilot', 'AI Tooling', 'mid', 'What licensing concern can arise?', '["Suggestions may resemble public code with its license","It deletes licenses","It requires GPL for all code","It encrypts your repo"]'::jsonb, 0, 'Generated code can echo training data, so policies/filters matter.'),
  ('GitHub Copilot', 'AI Tooling', 'mid', 'How do you accept a suggestion in most editors?', '["Press Tab","Press Escape","Press Ctrl+C","Right-click only"]'::jsonb, 0, 'Tab typically accepts the inline suggestion (Esc dismisses it).'),
  ('GitHub Copilot', 'AI Tooling', 'high', 'Why can Copilot hallucinate APIs that don''t exist?', '["It predicts plausible tokens rather than verifying facts","It reads stale docs only","It guesses random strings","It copies the README"]'::jsonb, 0, 'Language models generate likely code, which may reference non-existent functions.'),
  ('GitHub Copilot', 'AI Tooling', 'high', 'What is a healthy workflow with Copilot?', '["Treat output as a draft to verify, test, and review","Merge suggestions without reading","Disable tests","Trust it for security code"]'::jsonb, 0, 'Use it to accelerate drafting, then validate as you would any code.'),
  ('GitHub Copilot', 'AI Tooling', 'high', 'How do you reduce insecure suggestions?', '["Review for injection/secrets and run security tooling","Accept everything quickly","Remove input validation","Disable linters"]'::jsonb, 0, 'Human review plus SAST/secret scanning catches risky generated code.'),
  ('GitHub Copilot', 'AI Tooling', 'high', 'Why does the context window matter for completions?', '["Limited context means it may miss distant but relevant code","It controls typing speed","It encrypts files","It picks the language"]'::jsonb, 0, 'Code outside the model''s context isn''t considered, affecting relevance.'),
  ('GitHub Copilot', 'AI Tooling', 'high', 'What is a risk of over-reliance?', '["Skill atrophy and merging unreviewed bugs","Faster compilation","Smaller bundles","Fewer dependencies"]'::jsonb, 0, 'Blindly accepting suggestions can hide defects and erode understanding.'),
  ('GitHub Copilot', 'AI Tooling', 'ultra', 'Why must AI-generated code still be tested and reviewed?', '["Models produce plausible but unverified output that can be subtly wrong","It is always insecure","It never compiles","Reviews are legally required"]'::jsonb, 0, 'Correct-looking code may contain subtle logic or security flaws.'),
  ('GitHub Copilot', 'AI Tooling', 'ultra', 'How does context quality affect Copilot''s output?', '["Better, clearer context yields more relevant and correct completions","Context is ignored","More context always slows typing","It only affects color"]'::jsonb, 0, 'Well-structured surrounding code steers the model toward useful suggestions.'),
  ('GitHub Copilot', 'AI Tooling', 'ultra', 'What mitigates license/IP exposure from suggestions?', '["Code-referencing filters and organizational policy review","Disabling the editor","Removing comments","Using only one language"]'::jsonb, 0, 'Duplication filters and policy guardrails reduce IP risk.'),
  ('GitHub Copilot', 'AI Tooling', 'ultra', 'Why can it confidently produce wrong code?', '["It optimizes token likelihood, with no ground-truth verification","It intentionally errs","It lacks training data","It only copies tests"]'::jsonb, 0, 'There''s no fact-checking step; fluency does not imply correctness.'),
  ('GitHub Copilot', 'AI Tooling', 'ultra', 'What is the security risk of trusting suggestions blindly?', '["Injected vulnerabilities or secrets slipping into the codebase","Slower builds","Larger images","More merge conflicts"]'::jsonb, 0, 'Unreviewed AI code can introduce insecure patterns or leak secrets.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'easy', 'What is an LLM?', '["A large language model trained to predict text","A database engine","A compiler","A container"]'::jsonb, 0, 'Large language models generate text by predicting likely tokens.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'easy', 'What is a token?', '["A chunk of text the model processes","A security key","A network packet","A git commit"]'::jsonb, 0, 'Models read and produce text as tokens (subword units).'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'easy', 'What is a prompt?', '["The input/instructions you give the model","The model''s weights","A training dataset","An output filter"]'::jsonb, 0, 'The prompt is the text/instructions guiding the model''s response.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'easy', 'What is the context window?', '["The maximum tokens the model can consider at once","The UI panel size","The training duration","The output length only"]'::jsonb, 0, 'It''s the limit on combined input/output tokens the model handles.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'easy', 'What is a system prompt?', '["Instructions that set the model''s overall behavior","The user''s last message","A code comment","A log line"]'::jsonb, 0, 'System instructions establish role, tone, and constraints.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'mid', 'What does the temperature parameter control?', '["Randomness/creativity of the output","The token limit","The model size","The latency"]'::jsonb, 0, 'Higher temperature increases variability; lower makes output more focused.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'mid', 'What is a hallucination?', '["Confident but false or fabricated output","A network error","A training epoch","A token overflow"]'::jsonb, 0, 'Models can state plausible-sounding but incorrect information.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'mid', 'What does few-shot prompting provide?', '["Examples that guide the desired format/behavior","A larger model","More training data","A faster GPU"]'::jsonb, 0, 'In-context examples steer the model without retraining.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'mid', 'What does fine-tuning do?', '["Adapts a model to a task/domain using extra training data","Increases the context window","Lowers temperature","Caches prompts"]'::jsonb, 0, 'Fine-tuning specializes a base model on additional examples.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'mid', 'What is tool/function calling?', '["Letting the model invoke external functions/APIs","Compiling the model","A type of token","A prompt template"]'::jsonb, 0, 'The model can call defined tools and use their results in its response.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'high', 'Why does the context window limit matter?', '["Long inputs get truncated, so relevant info can be dropped","It sets the temperature","It picks the model","It encrypts data"]'::jsonb, 0, 'Exceeding the window forces truncation, risking loss of important context.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'high', 'What does RAG add to an LLM?', '["Grounding in retrieved external knowledge","A bigger model","Lower latency always","A new tokenizer"]'::jsonb, 0, 'Retrieval-Augmented Generation supplies relevant documents to ground answers.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'high', 'What does a lower temperature favor?', '["More deterministic, focused output","More creative output","Longer output","Faster training"]'::jsonb, 0, 'Low temperature reduces randomness, good for factual/consistent tasks.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'high', 'Why request structured (JSON/schema) output?', '["For reliable parsing and integration into systems","To increase creativity","To use fewer tokens always","To avoid prompts"]'::jsonb, 0, 'Structured outputs are machine-parseable and integrate predictably.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'high', 'What is the tradeoff of a larger context?', '["More information but higher cost and latency","Less accuracy always","Smaller models","No tradeoff"]'::jsonb, 0, 'Bigger prompts can help but increase token cost and response time.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'ultra', 'Why can LLMs hallucinate even when the facts exist in training?', '["They generate likely tokens rather than retrieving verified facts","They lack memory entirely","They only copy prompts","They run out of tokens"]'::jsonb, 0, 'Generation is probabilistic; the model may produce a plausible wrong answer.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'ultra', 'What does prompt caching optimize?', '["Reusing repeated prompt prefixes to cut cost and latency","Model accuracy","The context window size","Output randomness"]'::jsonb, 0, 'Caching a stable prefix avoids reprocessing it on each call.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'ultra', 'How does tool use ground a model in real data?', '["It calls functions/APIs and uses the results instead of guessing","It enlarges the model","It lowers temperature","It compresses tokens"]'::jsonb, 0, 'Letting the model fetch live data reduces reliance on memorized (possibly wrong) facts.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'ultra', 'What is the risk of putting secrets in prompts?', '["They may be logged or retained by the provider","They speed up responses","They improve accuracy","They reduce tokens"]'::jsonb, 0, 'Sensitive data in prompts can be stored/logged; avoid sending secrets.'),
  ('Claude / OpenAI Codex', 'AI Tooling', 'ultra', 'Why evaluate LLM features with systematic tests/evals?', '["Non-determinism and model drift require measuring quality over time","Models never change","Tests are legally required","It lowers latency"]'::jsonb, 0, 'Because outputs vary and models update, evals quantify and track quality.'),
  ('RAG Pipelines', 'AI Tooling', 'easy', 'What does RAG stand for?', '["Retrieval-Augmented Generation","Rapid Application Gateway","Recursive Async Graph","Remote Access Grid"]'::jsonb, 0, 'RAG augments generation with retrieved external context.'),
  ('RAG Pipelines', 'AI Tooling', 'easy', 'What does the retrieval step fetch?', '["Relevant documents/passages","Random text","The model weights","User passwords"]'::jsonb, 0, 'Retrieval finds context relevant to the query to feed the model.'),
  ('RAG Pipelines', 'AI Tooling', 'easy', 'What is an embedding?', '["A numeric vector representing text meaning","A compressed image","A SQL row","A git tag"]'::jsonb, 0, 'Embeddings map text to vectors so similar meanings are near each other.'),
  ('RAG Pipelines', 'AI Tooling', 'easy', 'Where are embeddings typically stored?', '["A vector database/index","A relational table only","A log file","The prompt"]'::jsonb, 0, 'Vector stores index embeddings for similarity search.'),
  ('RAG Pipelines', 'AI Tooling', 'easy', 'Why use RAG?', '["To ground answers in your data and reduce hallucination","To make the model bigger","To remove the need for prompts","To speed up training"]'::jsonb, 0, 'Grounding responses in retrieved facts improves accuracy.'),
  ('RAG Pipelines', 'AI Tooling', 'mid', 'What is chunking?', '["Splitting documents into passages for retrieval","Compressing the model","Caching prompts","Encrypting data"]'::jsonb, 0, 'Documents are divided into chunks that can be embedded and retrieved.'),
  ('RAG Pipelines', 'AI Tooling', 'mid', 'What is semantic search?', '["Finding results by meaning via embedding similarity","Exact keyword matching only","Sorting alphabetically","Full-text regex"]'::jsonb, 0, 'Semantic search ranks by vector similarity rather than literal terms.'),
  ('RAG Pipelines', 'AI Tooling', 'mid', 'Which similarity metric is common for embeddings?', '["Cosine similarity","Levenshtein distance","MD5 match","Alphabetical order"]'::jsonb, 0, 'Cosine similarity measures the angle between embedding vectors.'),
  ('RAG Pipelines', 'AI Tooling', 'mid', 'What does the retriever pass to the LLM?', '["The top-k relevant chunks as context","The entire corpus","Only the query","The model weights"]'::jsonb, 0, 'The most relevant chunks are added to the prompt as grounding context.'),
  ('RAG Pipelines', 'AI Tooling', 'mid', 'What is a vector index for?', '["Fast nearest-neighbor similarity search","Storing SQL rows","Caching prompts","Compressing text"]'::jsonb, 0, 'An index (e.g. HNSW) accelerates finding the closest vectors.'),
  ('RAG Pipelines', 'AI Tooling', 'high', 'Why does chunk size matter?', '["Too big dilutes relevance/overflows context; too small loses meaning","It changes the model","It sets temperature","It has no effect"]'::jsonb, 0, 'Chunk size balances retrieval precision against preserving enough context.'),
  ('RAG Pipelines', 'AI Tooling', 'high', 'What is hybrid search?', '["Combining keyword (BM25) and vector search for better recall","Two LLMs voting","Search across two databases","Caching plus search"]'::jsonb, 0, 'Hybrid retrieval blends lexical and semantic matching.'),
  ('RAG Pipelines', 'AI Tooling', 'high', 'What is re-ranking?', '["Reordering retrieved candidates with a stronger model","Re-embedding the query","Sorting by date","Caching results"]'::jsonb, 0, 'A re-ranker (often a cross-encoder) scores candidates for better precision.'),
  ('RAG Pipelines', 'AI Tooling', 'high', 'What does citing sources/grounding reduce?', '["Hallucination, by tying answers to retrieved evidence","Latency","Token cost","Index size"]'::jsonb, 0, 'Grounding and citations make answers verifiable and reduce fabrication.'),
  ('RAG Pipelines', 'AI Tooling', 'high', 'What is ANN (approximate nearest neighbor)?', '["Fast approximate vector search (e.g. HNSW)","A neural network type","Exact brute-force search","A tokenizer"]'::jsonb, 0, 'ANN trades a little accuracy for much faster similarity search at scale.'),
  ('RAG Pipelines', 'AI Tooling', 'ultra', 'Why can RAG still hallucinate?', '["The LLM may ignore/misread context, or retrieval misses the right docs","It always copies the docs verbatim","Vectors are encrypted","Embeddings are random"]'::jsonb, 0, 'Poor retrieval or the model overriding context can still yield wrong answers.'),
  ('RAG Pipelines', 'AI Tooling', 'ultra', 'What does chunk overlap mitigate?', '["Losing context that spans chunk boundaries","High latency","Large indexes","Token cost"]'::jsonb, 0, 'Overlapping windows keep adjacent context together for better retrieval.'),
  ('RAG Pipelines', 'AI Tooling', 'ultra', 'What is the tradeoff of re-ranking?', '["Higher precision at the cost of added latency","Lower recall always","No effect on quality","Cheaper compute"]'::jsonb, 0, 'Cross-encoder re-ranking is more accurate but slower per candidate.'),
  ('RAG Pipelines', 'AI Tooling', 'ultra', 'What is the ANN-versus-exact-search tradeoff?', '["Speed/memory efficiency versus perfect recall","Accuracy versus security","Cost versus color","There is none"]'::jsonb, 0, 'Approximate search is far faster but may miss some true nearest neighbors.'),
  ('RAG Pipelines', 'AI Tooling', 'ultra', 'How do you evaluate a RAG system?', '["Retrieval metrics (recall@k) plus answer faithfulness/groundedness evals","Only by latency","By model size","By index size"]'::jsonb, 0, 'Measure both whether the right context was retrieved and whether answers stay grounded in it.'),
  ('Node.js', 'Backend', 'easy', 'What is Node.js?', '["A JavaScript runtime built on V8 for server-side code","A web browser","A database","A CSS framework"]'::jsonb, 0, 'Node.js runs JavaScript outside the browser using the V8 engine.'),
  ('Node.js', 'Backend', 'easy', 'What I/O model does Node use?', '["Non-blocking, event-driven","Blocking, thread-per-request","Polling only","Synchronous batch"]'::jsonb, 0, 'Node uses non-blocking I/O with an event loop.'),
  ('Node.js', 'Backend', 'easy', 'What is npm?', '["Node''s default package manager","A bundler","A test runner","A web server"]'::jsonb, 0, 'npm installs and manages Node packages.'),
  ('Node.js', 'Backend', 'easy', 'Which built-in module reads files?', '["fs","http","path","os"]'::jsonb, 0, 'The fs module provides file system operations.'),
  ('Node.js', 'Backend', 'easy', 'How do you import a module in CommonJS?', '["require()","import {}","include()","use()"]'::jsonb, 0, 'CommonJS uses require(); ESM uses import.'),
  ('Node.js', 'Backend', 'mid', 'What is the event loop?', '["The mechanism that schedules async callbacks on a single thread","A CPU scheduler","A database connection pool","A bundler step"]'::jsonb, 0, 'The event loop processes callbacks/phases, enabling non-blocking concurrency.'),
  ('Node.js', 'Backend', 'mid', 'What does the libuv thread pool handle?', '["Offloading blocking ops like fs and crypto","Rendering HTML","Garbage collection","HTTP routing"]'::jsonb, 0, 'libuv runs certain blocking operations on a thread pool so the loop stays free.'),
  ('Node.js', 'Backend', 'mid', 'What is a Stream?', '["An interface for reading/writing data in chunks","A database cursor","A logging format","A type of Promise"]'::jsonb, 0, 'Streams process data incrementally instead of loading it all in memory.'),
  ('Node.js', 'Backend', 'mid', 'How do CommonJS and ESM differ?', '["require (dynamic) vs import (static/async)","They are identical","ESM is synchronous only","CommonJS supports top-level await"]'::jsonb, 0, 'ESM uses static import/export with async loading; CommonJS uses dynamic require.'),
  ('Node.js', 'Backend', 'mid', 'What does the Buffer class represent?', '["Raw binary data","A string pool","A network socket","A timer"]'::jsonb, 0, 'Buffers hold fixed-length binary data, e.g. file or network bytes.'),
  ('Node.js', 'Backend', 'high', 'Why is single-threaded Node still scalable for I/O?', '["Non-blocking I/O plus the event loop; blocking work is offloaded to libuv","It secretly uses many threads for JS","It blocks per request efficiently","It compiles to native"]'::jsonb, 0, 'The single JS thread isn''t blocked waiting on I/O, so it handles many connections.'),
  ('Node.js', 'Backend', 'high', 'How can Node use multiple CPU cores?', '["The cluster module or worker_threads","Async/await","More event loops","Bigger Buffers"]'::jsonb, 0, 'cluster forks processes; worker_threads run JS on separate threads.'),
  ('Node.js', 'Backend', 'high', 'What are worker_threads best for?', '["CPU-bound parallel work","HTTP routing","Reducing memory","Caching responses"]'::jsonb, 0, 'Worker threads offload CPU-heavy tasks that would otherwise block the loop.'),
  ('Node.js', 'Backend', 'high', 'What does stream backpressure prevent?', '["Overwhelming a slow consumer by pausing the source","Memory leaks in timers","Event loop starvation by I/O","Duplicate writes"]'::jsonb, 0, 'Backpressure throttles a fast producer when the consumer''s buffer fills.'),
  ('Node.js', 'Backend', 'high', 'Between promise callbacks and setTimeout, which runs first?', '["Promise microtasks drain before timers","Timers run before promises","They run together","Order is random"]'::jsonb, 0, 'Microtasks (resolved promises) complete before the loop moves to timer callbacks.'),
  ('Node.js', 'Backend', 'ultra', 'How do process.nextTick and setImmediate differ?', '["nextTick fires before the loop continues; setImmediate fires in the check phase","They are identical","setImmediate fires first always","nextTick runs after timers"]'::jsonb, 0, 'nextTick callbacks run before returning to the loop; setImmediate runs after I/O in the check phase.'),
  ('Node.js', 'Backend', 'ultra', 'What can worker_threads share that cluster processes cannot easily?', '["Memory via SharedArrayBuffer in-process","TCP ports","Environment variables","The file system"]'::jsonb, 0, 'Worker threads can share memory; cluster uses separate processes that don''t share heap.'),
  ('Node.js', 'Backend', 'ultra', 'What happens when a CPU-bound task runs on the main thread?', '["It blocks the event loop, stalling all other work","It runs in parallel automatically","libuv handles it","It is queued as a microtask"]'::jsonb, 0, 'Synchronous CPU work blocks everything; offload it to workers or native addons.'),
  ('Node.js', 'Backend', 'ultra', 'What does AbortController enable for Node async APIs?', '["Cancelling operations like fetch, timers, and streams","Retrying requests","Throttling I/O","Sharing memory"]'::jsonb, 0, 'Passing an AbortSignal lets you cancel supported async operations.'),
  ('Node.js', 'Backend', 'ultra', 'How do you measure event-loop lag?', '["perf_hooks monitorEventLoopDelay","console.time only","process.memoryUsage","os.cpus"]'::jsonb, 0, 'monitorEventLoopDelay tracks how delayed the loop is, signaling blocking work.'),
  ('NestJS', 'Backend', 'easy', 'What is NestJS?', '["A structured TypeScript framework for Node servers","A frontend library","A database ORM","A bundler"]'::jsonb, 0, 'Nest is an opinionated Node framework using TypeScript and modular architecture.'),
  ('NestJS', 'Backend', 'easy', 'Which pattern does Nest rely on heavily?', '["Dependency injection","Global singletons via imports","Service locators only","Manual wiring"]'::jsonb, 0, 'Nest uses an IoC container for dependency injection.'),
  ('NestJS', 'Backend', 'easy', 'Which decorator marks a controller?', '["@Controller","@Service","@Route","@Get only"]'::jsonb, 0, '@Controller declares a request-handling class.'),
  ('NestJS', 'Backend', 'easy', 'What groups controllers and providers?', '["@Module","@Component","@Package","@Group"]'::jsonb, 0, '@Module organizes related controllers, providers, and imports.'),
  ('NestJS', 'Backend', 'easy', 'Where does business logic usually live?', '["In services/providers","In controllers","In modules","In decorators"]'::jsonb, 0, 'Controllers delegate to injectable services that hold logic.'),
  ('NestJS', 'Backend', 'mid', 'What are Guards used for?', '["Authorization/authentication checks before a handler runs","Transforming inputs","Logging responses","Catching exceptions"]'::jsonb, 0, 'Guards decide whether a request may proceed to the handler.'),
  ('NestJS', 'Backend', 'mid', 'What are Pipes used for?', '["Validating and transforming inputs","Authorization","Routing","Caching"]'::jsonb, 0, 'Pipes validate/transform arguments before the handler receives them.'),
  ('NestJS', 'Backend', 'mid', 'What are Interceptors used for?', '["Wrapping handler execution (logging, transforming responses)","Defining routes","Validating DTOs","Connecting to the DB"]'::jsonb, 0, 'Interceptors run logic before/after the handler, e.g. mapping the response.'),
  ('NestJS', 'Backend', 'mid', 'What HTTP platform does Nest use by default?', '["Express (Fastify optional)","Koa","Hapi","A custom server"]'::jsonb, 0, 'Nest defaults to Express but can run on Fastify.'),
  ('NestJS', 'Backend', 'mid', 'What does a provider receive through DI?', '["Its declared dependencies","The HTTP request only","The whole module","Environment variables"]'::jsonb, 0, 'The container injects the provider''s constructor dependencies.'),
  ('NestJS', 'Backend', 'high', 'What is the default scope of a provider?', '["Singleton","Request-scoped","Transient","Module-scoped"]'::jsonb, 0, 'Providers are singletons by default, shared across the app.'),
  ('NestJS', 'Backend', 'high', 'What does a custom Exception Filter do?', '["Catches thrown exceptions and shapes the error response","Validates input","Authorizes requests","Logs metrics"]'::jsonb, 0, 'Exception filters translate errors into HTTP responses.'),
  ('NestJS', 'Backend', 'high', 'How does Nest typically validate request bodies?', '["class-validator with a ValidationPipe on DTOs","Manual if-checks only","Database constraints","Guards"]'::jsonb, 0, 'DTO classes annotated with class-validator are checked by the ValidationPipe.'),
  ('NestJS', 'Backend', 'high', 'What is a dynamic module?', '["A module configured at runtime via forRoot/forFeature","A module loaded lazily by the browser","A circular module","A test-only module"]'::jsonb, 0, 'Dynamic modules accept configuration and return module metadata (e.g. ConfigModule.forRoot()).'),
  ('NestJS', 'Backend', 'high', 'Roughly, what is the request lifecycle order?', '["middleware → guards → interceptors/pipes → handler → interceptors → filters","handler → guards → pipes","pipes → handler → guards","filters → handler → guards"]'::jsonb, 0, 'Nest runs middleware, then guards, then interceptors/pipes around the handler, with filters on errors.'),
  ('NestJS', 'Backend', 'ultra', 'What is a downside of request-scoped providers?', '["A new instance per request adds overhead and forces scope to propagate","They can''t be injected","They break TypeScript","They disable guards"]'::jsonb, 0, 'Request scope instantiates per request and bubbles up the injection chain, costing performance.'),
  ('NestJS', 'Backend', 'ultra', 'How does Nest resolve circular dependencies between providers?', '["forwardRef()","Lazy imports","Global modules","It cannot"]'::jsonb, 0, 'forwardRef defers resolution so two providers can depend on each other.'),
  ('NestJS', 'Backend', 'ultra', 'What does the IoC container manage?', '["Instantiation and lifetime of providers","HTTP routing tables","Database migrations","Bundle splitting"]'::jsonb, 0, 'The inversion-of-control container creates and wires provider instances.'),
  ('NestJS', 'Backend', 'ultra', 'What does the CQRS module separate?', '["Commands (writes) from queries (reads)","Controllers from modules","Guards from pipes","DTOs from entities"]'::jsonb, 0, 'CQRS splits write and read responsibilities into commands and queries.'),
  ('NestJS', 'Backend', 'ultra', 'How do custom param decorators read request data?', '["createParamDecorator with ExecutionContext","Global middleware","Reflect only","Direct req access in providers"]'::jsonb, 0, 'createParamDecorator exposes the ExecutionContext to extract values (e.g. @CurrentUser).'),
  ('GraphQL (Relay)', 'Backend', 'easy', 'What is GraphQL?', '["A typed query language for APIs","A SQL dialect","A REST framework","A caching proxy"]'::jsonb, 0, 'GraphQL lets clients request exactly the fields they need from a typed schema.'),
  ('GraphQL (Relay)', 'Backend', 'easy', 'What operation reads data?', '["A query","A mutation","A subscription","A migration"]'::jsonb, 0, 'Queries fetch data; the client specifies the fields.'),
  ('GraphQL (Relay)', 'Backend', 'easy', 'What operation modifies data?', '["A mutation","A query","A fragment","A directive"]'::jsonb, 0, 'Mutations perform writes and can return the updated data.'),
  ('GraphQL (Relay)', 'Backend', 'easy', 'What pushes real-time updates?', '["A subscription","A query","A mutation","A resolver"]'::jsonb, 0, 'Subscriptions stream server events to the client.'),
  ('GraphQL (Relay)', 'Backend', 'easy', 'What defines the API''s shape?', '["The schema (types and fields)","The resolver","The client","The network layer"]'::jsonb, 0, 'The schema declares types, fields, and operations.'),
  ('GraphQL (Relay)', 'Backend', 'mid', 'What problem does GraphQL solve versus REST?', '["Over- and under-fetching, via one tailored request","Authentication","Database indexing","TLS termination"]'::jsonb, 0, 'Clients fetch exactly the fields they need in a single request.'),
  ('GraphQL (Relay)', 'Backend', 'mid', 'What is a resolver?', '["A function that returns the data for a field","A schema validator","A cache layer","A router"]'::jsonb, 0, 'Each field has a resolver that produces its value.'),
  ('GraphQL (Relay)', 'Backend', 'mid', 'What is the N+1 problem?', '["Resolvers issuing one query per item instead of batching","Too many mutations","Schema cycles","Slow TLS"]'::jsonb, 0, 'Naively resolving a list field can trigger a query per element.'),
  ('GraphQL (Relay)', 'Backend', 'mid', 'What tool mitigates N+1?', '["DataLoader (per-request batching and caching)","A CDN","A linter","A subscription"]'::jsonb, 0, 'DataLoader batches keys within a tick and caches results per request.'),
  ('GraphQL (Relay)', 'Backend', 'mid', 'What is introspection?', '["Querying the schema itself","Logging requests","Caching queries","Compiling resolvers"]'::jsonb, 0, 'Introspection lets clients/tools discover the schema''s types and fields.'),
  ('GraphQL (Relay)', 'Backend', 'high', 'What does Relay require of the schema?', '["A Node interface with global IDs and connection-based pagination","Only mutations","REST-style endpoints","No types"]'::jsonb, 0, 'Relay assumes globally identifiable objects and standardized connections.'),
  ('GraphQL (Relay)', 'Backend', 'high', 'What is a Relay connection?', '["A standardized cursor-based pagination shape (edges/pageInfo)","A websocket","A DB connection pool","A schema directive"]'::jsonb, 0, 'Connections model paginated lists with edges, cursors, and pageInfo.'),
  ('GraphQL (Relay)', 'Backend', 'high', 'What does the Relay compiler do?', '["Precompiles queries and enforces fragment colocation","Runs the server","Caches responses on a CDN","Generates SQL"]'::jsonb, 0, 'Relay''s compiler validates and optimizes GraphQL at build time.'),
  ('GraphQL (Relay)', 'Backend', 'high', 'What is fragment colocation?', '["Components declare their own data needs as fragments","Putting all queries in one file","Sharing a single global query","Inlining SQL"]'::jsonb, 0, 'Each component specifies the fields it needs, composed into the parent query.'),
  ('GraphQL (Relay)', 'Backend', 'high', 'What does the Relay store provide?', '["A normalized client cache keyed by global IDs","Server-side sessions","A SQL database","A message queue"]'::jsonb, 0, 'Relay normalizes records by id so updates propagate consistently.'),
  ('GraphQL (Relay)', 'Backend', 'ultra', 'Why does Relay mandate global object IDs?', '["So any object can be normalized and refetched by id","To encrypt data","To enable subscriptions","To compress responses"]'::jsonb, 0, 'Global IDs let the normalized store cache and refetch individual objects.'),
  ('GraphQL (Relay)', 'Backend', 'ultra', 'How does Relay keep multiple components consistent?', '["A single normalized store keyed by id propagates updates everywhere","It refetches the whole page","Each component holds its own copy","Via localStorage"]'::jsonb, 0, 'One source of truth means a record update reflects in every component using it.'),
  ('GraphQL (Relay)', 'Backend', 'ultra', 'What do @defer and @stream enable?', '["Incremental delivery of parts of a response","Authentication","Schema stitching","Persisted caching"]'::jsonb, 0, 'They let the server send slower fields/list items progressively.'),
  ('GraphQL (Relay)', 'Backend', 'ultra', 'What is the benefit of persisted queries?', '["Send a query hash instead of full text (smaller, allowlistable)","Faster resolvers","Automatic caching of data","Schema validation"]'::jsonb, 0, 'Persisted queries reduce payload size and let the server allowlist known operations.'),
  ('GraphQL (Relay)', 'Backend', 'ultra', 'How does Relay manage pagination state?', '["Cursors and pageInfo via connections, tracked in the store","Offset numbers in the URL","Client-side arrays only","Server sessions"]'::jsonb, 0, 'Connections carry cursors/pageInfo the Relay store uses to append pages.'),
  ('REST / OpenAPI', 'Backend', 'easy', 'What does REST use to express actions?', '["HTTP methods (GET/POST/PUT/DELETE)","Custom verbs in the body","GraphQL operations","RPC names only"]'::jsonb, 0, 'REST maps actions onto HTTP methods over resources.'),
  ('REST / OpenAPI', 'Backend', 'easy', 'Which method is the safe, read-only one?', '["GET","POST","DELETE","PATCH"]'::jsonb, 0, 'GET retrieves data without side effects.'),
  ('REST / OpenAPI', 'Backend', 'easy', 'What identifies a resource?', '["A URI","A header","A cookie","A query parameter only"]'::jsonb, 0, 'Resources are addressed by their URI/URL.'),
  ('REST / OpenAPI', 'Backend', 'easy', 'What is OpenAPI?', '["A specification format describing REST APIs","A web server","An auth protocol","A database"]'::jsonb, 0, 'OpenAPI (formerly Swagger) documents endpoints, schemas, and responses.'),
  ('REST / OpenAPI', 'Backend', 'easy', 'Which status code means a resource was created?', '["201","200","204","301"]'::jsonb, 0, '201 Created indicates successful resource creation.'),
  ('REST / OpenAPI', 'Backend', 'mid', 'Which methods are idempotent?', '["GET, PUT, and DELETE","POST only","All methods","None"]'::jsonb, 0, 'Repeating GET/PUT/DELETE yields the same result; POST generally isn''t idempotent.'),
  ('REST / OpenAPI', 'Backend', 'mid', 'What does statelessness mean in REST?', '["Each request carries all context; the server keeps no session","The server never changes","Responses are never cached","Clients store nothing"]'::jsonb, 0, 'Statelessness improves scalability since any server can handle any request.'),
  ('REST / OpenAPI', 'Backend', 'mid', 'How do PUT and PATCH differ?', '["PUT replaces the resource; PATCH partially updates it","They are identical","PATCH replaces; PUT appends","PUT is for reads"]'::jsonb, 0, 'PUT sends a full representation; PATCH sends a partial change.'),
  ('REST / OpenAPI', 'Backend', 'mid', 'What does a 404 status indicate?', '["The resource was not found","Unauthorized","Server error","Created"]'::jsonb, 0, '404 Not Found means the resource doesn''t exist at that URI.'),
  ('REST / OpenAPI', 'Backend', 'mid', 'What does an OpenAPI document enable tooling to do?', '["Generate docs, clients, and request validation","Run the database","Encrypt traffic","Cache responses"]'::jsonb, 0, 'From the spec, tools generate SDKs, docs, mocks, and validators.'),
  ('REST / OpenAPI', 'Backend', 'high', 'Why does idempotency matter for retries?', '["A retried request won''t cause duplicate side effects","It makes requests faster","It compresses payloads","It authenticates the client"]'::jsonb, 0, 'Idempotent operations are safe to retry after timeouts/network errors.'),
  ('REST / OpenAPI', 'Backend', 'high', 'What does a 429 status mean?', '["Too Many Requests (rate limited)","Gateway timeout","Forbidden","Conflict"]'::jsonb, 0, '429 signals the client has exceeded a rate limit.'),
  ('REST / OpenAPI', 'Backend', 'high', 'What are ETags used for?', '["Caching and optimistic concurrency via a resource version","Authentication","Compression","Routing"]'::jsonb, 0, 'An ETag identifies a representation''s version for conditional requests/caching.'),
  ('REST / OpenAPI', 'Backend', 'high', 'How is a REST API commonly versioned?', '["URI path, header, or media type","Only by changing the port","By renaming the database","It can''t be versioned"]'::jsonb, 0, 'Versioning strategies include /v2 paths, custom headers, or content negotiation.'),
  ('REST / OpenAPI', 'Backend', 'high', 'What does HATEOAS add to a response?', '["Hypermedia links guiding available state transitions","Encryption","Pagination only","Schema validation"]'::jsonb, 0, 'HATEOAS embeds links so clients discover actions dynamically.'),
  ('REST / OpenAPI', 'Backend', 'ultra', 'How does a conditional request (If-Match/ETag) prevent lost updates?', '["It rejects the write if the resource changed since the client read it","It locks the database","It retries automatically","It caches the response"]'::jsonb, 0, 'Optimistic concurrency fails the update when the ETag no longer matches.'),
  ('REST / OpenAPI', 'Backend', 'ultra', 'What does an Idempotency-Key header solve for POST?', '["Deduplicating retried non-idempotent requests","Authentication","Compression","Pagination"]'::jsonb, 0, 'The server records the key so a retried POST isn''t processed twice (e.g. payments).'),
  ('REST / OpenAPI', 'Backend', 'ultra', 'Why does cursor pagination scale better than offset?', '["It stays stable under inserts and avoids large OFFSET scans","It returns more rows","It needs no index","It is simpler to implement"]'::jsonb, 0, 'Cursors page from a stable key, avoiding shifting results and expensive offset scans.'),
  ('REST / OpenAPI', 'Backend', 'ultra', 'What is the tradeoff of chatty REST versus GraphQL?', '["Multiple round trips/over-fetching versus one tailored query","REST can''t return JSON","GraphQL has no types","REST is always faster"]'::jsonb, 0, 'REST may need several requests or return extra fields; GraphQL fetches exactly what''s asked.'),
  ('REST / OpenAPI', 'Backend', 'ultra', 'What is the purpose of content negotiation?', '["Serving different representations based on the Accept header","Validating tokens","Throttling requests","Splitting chunks"]'::jsonb, 0, 'The server returns JSON/XML/etc. according to what the client accepts.'),
  ('Microservices', 'Backend', 'easy', 'What is a microservice?', '["A small, independently deployable service","A single large application","A frontend component","A database table"]'::jsonb, 0, 'Microservices split a system into small, separately deployable services.'),
  ('Microservices', 'Backend', 'easy', 'What is the contrasting architecture?', '["A monolith","A microkernel","A mainframe","A CDN"]'::jsonb, 0, 'A monolith bundles all functionality into one deployable unit.'),
  ('Microservices', 'Backend', 'easy', 'How do microservices typically communicate?', '["Over the network (HTTP/gRPC/messaging)","Shared in-process memory","Global variables","The DOM"]'::jsonb, 0, 'Services talk via network protocols or message brokers.'),
  ('Microservices', 'Backend', 'easy', 'What routes external traffic to services?', '["An API gateway","A linter","A bundler","A migration tool"]'::jsonb, 0, 'The API gateway is a single entry point routing to backend services.'),
  ('Microservices', 'Backend', 'easy', 'What does each service ideally own?', '["Its own data store","The shared global database","The frontend","The CI pipeline"]'::jsonb, 0, 'Database-per-service keeps boundaries and enables independent change.'),
  ('Microservices', 'Backend', 'mid', 'What is service discovery?', '["Locating service instances dynamically","Finding bugs","Scanning ports for security","Logging requests"]'::jsonb, 0, 'Discovery lets services find healthy instances without hard-coded addresses.'),
  ('Microservices', 'Backend', 'mid', 'What does eventual consistency mean?', '["Data converges across services over time","Data is always immediately consistent","Data is never consistent","Only reads are consistent"]'::jsonb, 0, 'Without a global transaction, replicas/services become consistent asynchronously.'),
  ('Microservices', 'Backend', 'mid', 'What does a circuit breaker prevent?', '["Cascading failures from a failing dependency","SQL injection","Memory leaks","Slow builds"]'::jsonb, 0, 'It stops calling a failing service, protecting the rest of the system.'),
  ('Microservices', 'Backend', 'mid', 'What pattern coordinates a distributed transaction?', '["Saga","Two-phase commit only","Singleton","Observer"]'::jsonb, 0, 'A saga sequences local transactions with compensations instead of a global lock.'),
  ('Microservices', 'Backend', 'mid', 'What is a benefit of independent deployability?', '["Deploy and scale services separately","One shared release for everything","No need for monitoring","Simpler networking"]'::jsonb, 0, 'Teams can release and scale their service without redeploying the whole system.'),
  ('Microservices', 'Backend', 'high', 'What problem does the saga pattern solve?', '["Distributed transactions via compensating actions instead of 2PC","Caching","Authentication","Load balancing"]'::jsonb, 0, 'Sagas keep data consistent across services using local commits and compensations.'),
  ('Microservices', 'Backend', 'high', 'What is the transactional outbox pattern for?', '["Reliably publishing events alongside a DB write","Caching reads","Routing requests","Rate limiting"]'::jsonb, 0, 'Events are written to an outbox table in the same transaction, then relayed, avoiding dual-write loss.'),
  ('Microservices', 'Backend', 'high', 'Why avoid sharing one database across services?', '["It couples services and breaks independent deployability","It is always slower","Databases can''t be shared technically","It prevents transactions"]'::jsonb, 0, 'A shared schema creates tight coupling, undermining autonomy.'),
  ('Microservices', 'Backend', 'high', 'When a circuit breaker is open, what does it do?', '["Fails fast without calling the dependency","Retries continuously","Queues all requests forever","Restarts the service"]'::jsonb, 0, 'An open breaker short-circuits calls, giving the dependency time to recover.'),
  ('Microservices', 'Backend', 'high', 'Why is an idempotent consumer important?', '["Messages may be delivered more than once and must be safe to reprocess","It speeds up the broker","It compresses messages","It guarantees ordering"]'::jsonb, 0, 'At-least-once delivery means consumers should handle duplicates without side effects.'),
  ('Microservices', 'Backend', 'ultra', 'Why does dual-write (DB then broker) cause inconsistency, and what fixes it?', '["A crash between the two writes loses one; the transactional outbox fixes it","Networks are slow; add retries","Brokers are unreliable; drop them","Use bigger transactions across systems"]'::jsonb, 0, 'You can''t atomically write to a DB and a broker; the outbox makes the event part of the DB transaction.'),
  ('Microservices', 'Backend', 'ultra', 'What does a saga''s compensating transaction do?', '["Undoes the effects of prior steps when a later step fails","Locks all participants","Retries the whole saga","Commits in two phases"]'::jsonb, 0, 'Each step has a compensation to semantically roll back already-committed work.'),
  ('Microservices', 'Backend', 'ultra', 'What is the tradeoff of long synchronous service chains?', '["Higher latency and coupling — one slow service degrades all","Better consistency always","No need for retries","Lower cost"]'::jsonb, 0, 'Synchronous chains compound latency and failure; async/event-driven flows decouple them.'),
  ('Microservices', 'Backend', 'ultra', 'How does event sourcing reconstruct current state?', '["By replaying the ordered event log","By reading a snapshot table only","By querying every service","It cannot"]'::jsonb, 0, 'State is derived by folding over the immutable sequence of events (often with snapshots).'),
  ('Microservices', 'Backend', 'ultra', 'What does a service mesh (sidecar) handle?', '["Cross-cutting concerns like mTLS, retries, and observability outside app code","Database schema","Frontend rendering","CI/CD"]'::jsonb, 0, 'A mesh moves networking concerns into sidecar proxies, keeping services focused on logic.'),
  ('Auth & Security', 'Backend', 'easy', 'What does authentication establish?', '["Who you are","What you can do","Where you are","How fast you are"]'::jsonb, 0, 'Authentication verifies identity; authorization grants permissions.'),
  ('Auth & Security', 'Backend', 'easy', 'What does authorization decide?', '["What an authenticated user may do","Who the user is","The user''s password","The server''s region"]'::jsonb, 0, 'Authorization controls access to resources/actions.'),
  ('Auth & Security', 'Backend', 'easy', 'What is a common stateless token format?', '["JWT","CSV","XML-RPC","YAML"]'::jsonb, 0, 'JSON Web Tokens carry signed claims for stateless auth.'),
  ('Auth & Security', 'Backend', 'easy', 'How should passwords never be stored?', '["In plain text","Hashed","Salted","In a KDF"]'::jsonb, 0, 'Never store plaintext passwords; always hash with a salt and a slow KDF.'),
  ('Auth & Security', 'Backend', 'easy', 'What protects data in transit?', '["TLS/HTTPS","Base64 encoding","Gzip","A firewall alone"]'::jsonb, 0, 'TLS encrypts traffic between client and server.'),
  ('Auth & Security', 'Backend', 'mid', 'How should passwords be stored?', '["Salted and hashed with a slow KDF (bcrypt/argon2)","Encrypted with a reversible cipher","Hashed once with MD5","Base64-encoded"]'::jsonb, 0, 'Use a deliberately slow, salted KDF so hashes resist cracking.'),
  ('Auth & Security', 'Backend', 'mid', 'What is CSRF?', '["Tricking a browser into making an unwanted authenticated request","Injecting SQL","Cross-site script execution","Leaking memory"]'::jsonb, 0, 'CSRF abuses the user''s existing session to perform actions they didn''t intend.'),
  ('Auth & Security', 'Backend', 'mid', 'What mitigates XSS?', '["Output encoding plus a Content Security Policy","Storing tokens in localStorage","Disabling HTTPS","Using GET for writes"]'::jsonb, 0, 'Escaping output and restricting script sources reduce cross-site scripting.'),
  ('Auth & Security', 'Backend', 'mid', 'What does OAuth2 provide?', '["Delegated authorization via access tokens","Password hashing","TLS termination","Database encryption"]'::jsonb, 0, 'OAuth2 lets an app act on a user''s behalf using scoped access tokens.'),
  ('Auth & Security', 'Backend', 'mid', 'How does OIDC relate to OAuth2?', '["OIDC adds an identity (authentication) layer on top of OAuth2","OIDC replaces OAuth2 entirely","They are unrelated","OIDC is only for mobile"]'::jsonb, 0, 'OpenID Connect standardizes authentication (ID tokens) over OAuth2''s authorization.'),
  ('Auth & Security', 'Backend', 'high', 'Why prefer httpOnly cookies over localStorage for tokens?', '["localStorage is readable by XSS; httpOnly cookies aren''t accessible to JS","Cookies are faster","localStorage can''t store strings","Cookies never expire"]'::jsonb, 0, 'httpOnly cookies aren''t exposed to JavaScript, reducing token theft via XSS.'),
  ('Auth & Security', 'Backend', 'high', 'What is a refresh token for?', '["Obtaining new short-lived access tokens without re-login","Encrypting requests","Storing user data","Rate limiting"]'::jsonb, 0, 'Refresh tokens mint fresh access tokens so access tokens can stay short-lived.'),
  ('Auth & Security', 'Backend', 'high', 'What does the principle of least privilege mean?', '["Grant the minimum access necessary","Give admins full access by default","Disable all access","Share one role for everyone"]'::jsonb, 0, 'Least privilege limits blast radius if credentials are compromised.'),
  ('Auth & Security', 'Backend', 'high', 'What does CORS control?', '["Which origins may call your API from the browser","Server-to-server calls","TLS ciphers","Password policies"]'::jsonb, 0, 'CORS is a browser policy governing cross-origin requests.'),
  ('Auth & Security', 'Backend', 'high', 'What is the purpose of rate limiting?', '["Mitigating brute-force and DoS abuse","Encrypting tokens","Validating input","Hashing passwords"]'::jsonb, 0, 'Limiting request rates curbs credential stuffing and resource exhaustion.'),
  ('Auth & Security', 'Backend', 'ultra', 'Why are bcrypt/argon2 preferred over SHA-256 for passwords?', '["Their tunable slowness resists brute force; fast hashes don''t","They produce shorter hashes","They are reversible","They need no salt"]'::jsonb, 0, 'A high work factor makes guessing expensive; general-purpose fast hashes are crackable at scale.'),
  ('Auth & Security', 'Backend', 'ultra', 'How does PKCE protect public OAuth clients?', '["It binds the auth code to a code verifier, preventing interception/replay","It encrypts the access token","It removes refresh tokens","It disables redirects"]'::jsonb, 0, 'PKCE ensures only the client that started the flow can redeem the authorization code.'),
  ('Auth & Security', 'Backend', 'ultra', 'What does refresh-token rotation help detect?', '["Stolen refresh tokens, by invalidating on reuse","Slow networks","Weak passwords","CORS errors"]'::jsonb, 0, 'Single-use rotation flags reuse of an old token as a likely theft.'),
  ('Auth & Security', 'Backend', 'ultra', 'What does a Content Security Policy fundamentally restrict?', '["Which sources scripts/styles may load from, mitigating XSS","Which users can log in","TLS versions","Database queries"]'::jsonb, 0, 'CSP limits allowed content origins, reducing the impact of injected scripts.'),
  ('Auth & Security', 'Backend', 'ultra', 'Why is the JWT alg:none pitfall dangerous?', '["Accepting unsigned tokens lets attackers forge claims","It doubles token size","It blocks refresh tokens","It breaks CORS"]'::jsonb, 0, 'If a server honors alg:none, anyone can craft a valid-looking token; always enforce the expected algorithm.'),
  ('Azure DevOps', 'Cloud & DevOps', 'easy', 'What is Azure DevOps?', '["A suite for pipelines, repos, boards, and artifacts","A container runtime","A database","A frontend framework"]'::jsonb, 0, 'Azure DevOps bundles CI/CD, source control, agile boards, and package feeds.'),
  ('Azure DevOps', 'Cloud & DevOps', 'easy', 'What are Azure Pipelines?', '["CI/CD pipelines for building and deploying","A monitoring dashboard","A code editor","A VM image"]'::jsonb, 0, 'Pipelines automate build, test, and deployment.'),
  ('Azure DevOps', 'Cloud & DevOps', 'easy', 'What does Azure Boards track?', '["Work items and agile planning","Network traffic","Container logs","DNS records"]'::jsonb, 0, 'Boards manages backlogs, sprints, and work items.'),
  ('Azure DevOps', 'Cloud & DevOps', 'easy', 'What stores source code in Azure DevOps?', '["Azure Repos (Git)","Azure Artifacts","Azure Boards","Azure Monitor"]'::jsonb, 0, 'Azure Repos hosts Git repositories.'),
  ('Azure DevOps', 'Cloud & DevOps', 'easy', 'What hosts build packages/feeds?', '["Azure Artifacts","Azure Repos","Azure Boards","Azure Pipelines"]'::jsonb, 0, 'Azure Artifacts hosts npm/NuGet/etc. package feeds.'),
  ('Azure DevOps', 'Cloud & DevOps', 'mid', 'What format defines a pipeline?', '["YAML (azure-pipelines.yml)","JSON only","XML","INI"]'::jsonb, 0, 'Pipelines are typically defined as YAML in the repo.'),
  ('Azure DevOps', 'Cloud & DevOps', 'mid', 'What is a pipeline agent?', '["A machine that runs pipeline jobs","A secret store","A test framework","A package feed"]'::jsonb, 0, 'Agents execute the jobs/steps of a pipeline.'),
  ('Azure DevOps', 'Cloud & DevOps', 'mid', 'What groups steps that run together on one agent?', '["A job","A stage","A trigger","A variable group"]'::jsonb, 0, 'A job is a set of steps executed on a single agent.'),
  ('Azure DevOps', 'Cloud & DevOps', 'mid', 'What groups jobs into a phase like build or deploy?', '["A stage","A step","A task","A pool"]'::jsonb, 0, 'Stages organize jobs (e.g. Build, Test, Deploy).'),
  ('Azure DevOps', 'Cloud & DevOps', 'mid', 'What is a service connection?', '["Stored credentials/identity to external systems","A network route","A pipeline trigger","A test report"]'::jsonb, 0, 'Service connections let pipelines authenticate to Azure, registries, etc.'),
  ('Azure DevOps', 'Cloud & DevOps', 'high', 'What do environments with approvals enable?', '["Gating deployments to a target with manual approval/checks","Faster builds","Bigger agents","Code formatting"]'::jsonb, 0, 'Environments track deployments and can require approvals before promotion.'),
  ('Azure DevOps', 'Cloud & DevOps', 'high', 'What does a deployment job add over a regular job?', '["Deployment strategies and environment tracking","Faster compilation","Secret encryption","Code linting"]'::jsonb, 0, 'Deployment jobs target environments and support strategies like rolling/canary.'),
  ('Azure DevOps', 'Cloud & DevOps', 'high', 'What is the tradeoff of self-hosted vs Microsoft-hosted agents?', '["Control/custom tooling vs managed, clean, ephemeral runners","Cost only","Speed only","There is no difference"]'::jsonb, 0, 'Self-hosted gives control but needs maintenance; hosted agents are managed and ephemeral.'),
  ('Azure DevOps', 'Cloud & DevOps', 'high', 'What does pipeline caching improve?', '["Run speed by reusing dependencies between runs","Secret security","Approval flows","Test coverage"]'::jsonb, 0, 'Caching restores dependencies (e.g. node_modules) to skip re-downloading.'),
  ('Azure DevOps', 'Cloud & DevOps', 'high', 'Where should pipeline secrets live?', '["Key Vault-backed variable groups, not plaintext variables","In the YAML file","In commit messages","In the repo README"]'::jsonb, 0, 'Link secrets from Key Vault and mark them secret; never commit plaintext.'),
  ('Azure DevOps', 'Cloud & DevOps', 'ultra', 'What does a multi-stage YAML pipeline let you express?', '["Build → test → deploy stages with gates in one versioned file","Only a single build step","Frontend routing","Database schema"]'::jsonb, 0, 'Multi-stage pipelines model the whole delivery flow with approvals between stages.'),
  ('Azure DevOps', 'Cloud & DevOps', 'ultra', 'Why are ephemeral hosted agents good for security?', '["Each run gets a clean, isolated environment","They are always faster","They store secrets longer","They skip approvals"]'::jsonb, 0, 'A fresh agent per run avoids leftover state or leaked credentials.'),
  ('Azure DevOps', 'Cloud & DevOps', 'ultra', 'How do approvals and checks enforce governance?', '["Required approvers, branch control, and conditions before deploy","By compiling faster","By caching artifacts","By tagging commits"]'::jsonb, 0, 'Checks (approvals, branch policies, business hours) gate environment deployments.'),
  ('Azure DevOps', 'Cloud & DevOps', 'ultra', 'Why promote the same built artifact across environments?', '["Reproducible deploys — you ship exactly what was tested","It builds faster","It avoids approvals","It reduces YAML"]'::jsonb, 0, 'Build once, deploy the identical artifact to dev/staging/prod for confidence.'),
  ('Azure DevOps', 'Cloud & DevOps', 'ultra', 'What does a YAML template enable across pipelines?', '["Reusable, parameterized pipeline definitions","Faster agents","Secret rotation","Test parallelism only"]'::jsonb, 0, 'Templates let teams share standardized job/stage definitions.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'easy', 'What is the Azure Portal?', '["A web UI for managing Azure resources","A CLI only","A database engine","A container registry"]'::jsonb, 0, 'The portal is the browser-based console for Azure.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'easy', 'What groups related Azure resources?', '["A resource group","A subscription only","A region","A tag"]'::jsonb, 0, 'Resource groups are containers for related resources.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'easy', 'What does GCP stand for?', '["Google Cloud Platform","General Compute Provider","Global Container Pool","Google Code Pipeline"]'::jsonb, 0, 'GCP is Google''s cloud offering.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'easy', 'What is a region?', '["A geographic location of data centers","A VM size","A billing plan","A network protocol"]'::jsonb, 0, 'Regions are geographic areas hosting cloud infrastructure.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'easy', 'How do IaaS and PaaS differ?', '["IaaS = infra you manage; PaaS = platform managed for you","They are identical","PaaS gives you raw VMs","IaaS has no servers"]'::jsonb, 0, 'IaaS exposes VMs/networking; PaaS abstracts the platform (e.g. App Service).'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'mid', 'What is the GCP equivalent of an Azure resource group''s organizing role?', '["A project","A bucket","A zone","A label"]'::jsonb, 0, 'GCP projects group resources, billing, and IAM.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'mid', 'What controls access in Azure?', '["RBAC role assignments","Firewall rules only","DNS","Tags"]'::jsonb, 0, 'Role-Based Access Control grants permissions via role assignments on scopes.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'mid', 'What is a VNet/VPC for?', '["Isolated private networking for resources","Storing files","Running pipelines","Hashing passwords"]'::jsonb, 0, 'Virtual networks provide private, isolated network space.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'mid', 'What does autoscaling do?', '["Adds/removes instances based on load","Encrypts disks","Rotates secrets","Compresses logs"]'::jsonb, 0, 'Autoscaling adjusts capacity to demand.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'mid', 'Why tag cloud resources?', '["Cost allocation and organization","To encrypt them","To speed them up","To grant access"]'::jsonb, 0, 'Tags label resources for billing, ownership, and filtering.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'high', 'What does a managed identity remove the need for?', '["Storing credentials/secrets in code","Networking","Load balancing","Monitoring"]'::jsonb, 0, 'Managed identities let resources authenticate without embedded secrets.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'high', 'How do availability zones relate to regions?', '["Zones are isolated data centers within a region","Zones span multiple regions","Zones are billing tiers","They are the same thing"]'::jsonb, 0, 'Spreading across zones protects against a single data-center failure within a region.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'high', 'What does Infrastructure as Code (Bicep/Terraform) provide?', '["Declarative, repeatable, version-controlled infrastructure","Faster VMs","Automatic scaling","Free storage"]'::jsonb, 0, 'IaC defines infra in code so it can be reviewed, versioned, and reproduced.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'high', 'What does a load balancer distribute?', '["Traffic across healthy instances","Secrets across services","Logs across regions","Disk across nodes"]'::jsonb, 0, 'Load balancers spread requests and route around unhealthy targets.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'high', 'What does a private endpoint achieve?', '["Reaching a PaaS service over the private network without public exposure","Faster DNS","Cheaper storage","More CPU"]'::jsonb, 0, 'Private endpoints keep traffic to managed services off the public internet.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'ultra', 'Why prefer a managed identity over a service-principal secret?', '["No secret to leak or rotate — the platform issues short-lived tokens","It is cheaper","It scales automatically","It needs no permissions"]'::jsonb, 0, 'Managed identities avoid stored credentials, eliminating a common leak/rotation burden.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'ultra', 'How do you design for a full region outage?', '["Multi-region with replication and failover/traffic routing","A bigger VM","More zones in one region","Daily backups only"]'::jsonb, 0, 'Cross-region redundancy with failover keeps the app available if a region fails.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'ultra', 'What is the main tradeoff of active-active multi-region?', '["Higher complexity/consistency challenges vs availability and latency gains","It is always cheaper","It removes the need for backups","It has no downsides"]'::jsonb, 0, 'Running everywhere boosts resilience/latency but complicates data consistency.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'ultra', 'What does cloud cost optimization emphasize?', '["Right-sizing, autoscaling, and reserved/spot capacity","Always using the biggest VMs","Disabling monitoring","Manual scaling only"]'::jsonb, 0, 'Matching capacity to need and using commitment/spot pricing controls spend.'),
  ('Azure Portal / GCP', 'Cloud & DevOps', 'ultra', 'What does least-privilege IAM reduce?', '["Blast radius if a credential is compromised","Latency","Storage cost","Build time"]'::jsonb, 0, 'Granting minimal roles limits what a leaked identity can do.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'easy', 'What does CI stand for?', '["Continuous Integration","Code Inspection","Container Initialization","Central Indexing"]'::jsonb, 0, 'CI = Continuous Integration: merge and verify code frequently.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'easy', 'What does CD commonly stand for?', '["Continuous Delivery/Deployment","Code Distribution","Cluster Deployment","Central Database"]'::jsonb, 0, 'CD covers Continuous Delivery and Continuous Deployment.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'easy', 'What commonly triggers a pipeline?', '["A push or pull request","A screen resize","A user login","A cron only"]'::jsonb, 0, 'Commits/PRs typically trigger CI runs.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'easy', 'What does the build step usually do?', '["Compile and package the app","Deploy to production","Open a PR","Send emails"]'::jsonb, 0, 'The build produces the runnable/deployable output.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'easy', 'What runs automated checks?', '["The test stage","The deploy stage","The merge","The tag"]'::jsonb, 0, 'Tests verify the build before it can be promoted.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'mid', 'What is the core goal of CI?', '["Integrate frequently with automated verification","Deploy only on Fridays","Avoid testing","Use long-lived branches"]'::jsonb, 0, 'Frequent integration with automated tests catches conflicts/regressions early.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'mid', 'How do continuous delivery and deployment differ?', '["Delivery needs a manual release step; deployment is automatic","They are identical","Deployment requires approval; delivery doesn''t","Delivery skips tests"]'::jsonb, 0, 'Delivery keeps a release-ready artifact; deployment ships to prod automatically.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'mid', 'What is a build artifact?', '["A built output passed between stages","A test log","A commit message","A branch name"]'::jsonb, 0, 'Artifacts (binaries, images) are produced once and promoted.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'mid', 'What does pipeline-as-code define?', '["Stages/jobs/steps stored in version control","Only secrets","Database schema","UI components"]'::jsonb, 0, 'Defining the pipeline in code makes it reviewable and reproducible.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'mid', 'What is a gate/approval?', '["A manual or automated check before promotion","A build cache","A merge conflict","A test fixture"]'::jsonb, 0, 'Gates control whether a change advances to the next environment.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'high', 'What does a blue-green deployment do?', '["Switch traffic between two environments to cut downtime","Run two test suites","Split the database","Cache responses"]'::jsonb, 0, 'You deploy to an idle environment, then flip traffic, enabling instant rollback.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'high', 'What does a canary release do?', '["Roll out to a small subset first, then expand","Deploy to everyone at once","Skip testing","Roll back automatically always"]'::jsonb, 0, 'Canaries expose a fraction of users first to catch issues early.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'high', 'Why pin dependency versions in CI?', '["Reproducible, deterministic builds","Faster downloads","Smaller repos","Better UI"]'::jsonb, 0, 'Pinned versions ensure the same inputs produce the same build.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'high', 'What is the tradeoff of build caching?', '["Speed vs correctness if the cache invalidates incorrectly","Cost vs security","Size vs color","None"]'::jsonb, 0, 'Caching speeds builds but a stale/incorrect key can produce wrong results.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'high', 'Why run tests before deploying?', '["Catch regressions before they reach users","To slow the pipeline","To create artifacts","To merge branches"]'::jsonb, 0, 'Automated gates prevent broken builds from being promoted.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'ultra', 'How does trunk-based development support CI?', '["Short-lived branches and frequent integration reduce merge pain","Long release branches","No branches at all","Manual integration weekly"]'::jsonb, 0, 'Merging small changes often keeps integration cheap and continuous.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'ultra', 'What does a canary''s automated rollback rely on?', '["Health/metrics thresholds crossing during the rollout","A manual ticket","Random sampling","Build duration"]'::jsonb, 0, 'Monitoring error rates/latency lets the pipeline abort and roll back automatically.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'ultra', 'Why separate build from deploy (build once, promote)?', '["You deploy the exact artifact that was tested across environments","It compiles faster","It avoids tests","It reduces YAML"]'::jsonb, 0, 'Rebuilding per environment risks drift; promoting one artifact guarantees parity.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'ultra', 'What is the danger of flaky tests in CI?', '["They erode trust and lead to ignored failures","They speed up builds","They improve coverage","They reduce cost"]'::jsonb, 0, 'Intermittent failures train teams to ignore red builds, masking real bugs.'),
  ('CI/CD Pipelines', 'Cloud & DevOps', 'ultra', 'How do progressive deployment strategies reduce blast radius?', '["Gradual rollout plus fast rollback (canary/blue-green)","Deploying everywhere instantly","Skipping staging","Bigger servers"]'::jsonb, 0, 'Limiting exposure and enabling quick reversal contains the impact of a bad release.'),
  ('Docker', 'Cloud & DevOps', 'easy', 'What is a container?', '["An isolated process packaged with its dependencies","A virtual machine with a full OS","A database","A load balancer"]'::jsonb, 0, 'Containers package an app and deps to run consistently anywhere.'),
  ('Docker', 'Cloud & DevOps', 'easy', 'What is a Docker image?', '["A read-only template for containers","A running process","A network","A log file"]'::jsonb, 0, 'Images are immutable templates; containers are running instances of them.'),
  ('Docker', 'Cloud & DevOps', 'easy', 'What file defines how to build an image?', '["A Dockerfile","docker-compose only","a .env file","an image.json"]'::jsonb, 0, 'A Dockerfile lists the steps to assemble an image.'),
  ('Docker', 'Cloud & DevOps', 'easy', 'Which command builds an image?', '["docker build","docker run","docker pull","docker ps"]'::jsonb, 0, 'docker build creates an image from a Dockerfile.'),
  ('Docker', 'Cloud & DevOps', 'easy', 'Which command starts a container?', '["docker run","docker build","docker commit","docker tag"]'::jsonb, 0, 'docker run creates and starts a container from an image.'),
  ('Docker', 'Cloud & DevOps', 'mid', 'What is an image layer?', '["A cached filesystem diff from an instruction","A network interface","A running process","A volume"]'::jsonb, 0, 'Each Dockerfile instruction adds a cacheable layer.'),
  ('Docker', 'Cloud & DevOps', 'mid', 'What does a volume provide?', '["Persistent storage outside the container''s writable layer","Faster CPU","A network bridge","A build cache"]'::jsonb, 0, 'Volumes persist data beyond a container''s lifecycle.'),
  ('Docker', 'Cloud & DevOps', 'mid', 'How do containers differ from VMs?', '["They share the host kernel (lighter) instead of a full OS each","They are heavier than VMs","They need a hypervisor per app","They can''t be isolated"]'::jsonb, 0, 'Containers share the kernel, so they start fast and use less overhead than VMs.'),
  ('Docker', 'Cloud & DevOps', 'mid', 'What does docker-compose do?', '["Defines and runs multi-container applications","Builds a single image faster","Encrypts images","Monitors containers"]'::jsonb, 0, 'Compose declares services, networks, and volumes for multi-container apps.'),
  ('Docker', 'Cloud & DevOps', 'mid', 'What does the EXPOSE instruction document?', '["The port the container listens on","The host firewall rule","The image size","The base image"]'::jsonb, 0, 'EXPOSE documents intended ports; publishing still needs -p at run.'),
  ('Docker', 'Cloud & DevOps', 'high', 'Why order Dockerfile steps least- to most-frequently-changing?', '["To maximize layer cache reuse","To reduce image layers to one","To improve runtime speed","To avoid volumes"]'::jsonb, 0, 'Stable steps stay cached; changing them early invalidates everything after.'),
  ('Docker', 'Cloud & DevOps', 'high', 'What does a multi-stage build achieve?', '["Smaller final images by discarding build-only deps","Faster networking","Automatic scaling","Encrypted layers"]'::jsonb, 0, 'You build in one stage and copy only artifacts into a slim runtime stage.'),
  ('Docker', 'Cloud & DevOps', 'high', 'What does a .dockerignore do?', '["Excludes files from the build context","Hides containers","Ignores logs","Skips tests"]'::jsonb, 0, 'It keeps unnecessary files out of the context sent to the daemon.'),
  ('Docker', 'Cloud & DevOps', 'high', 'Why run a container as a non-root user?', '["To reduce the impact of a container breakout","To run faster","To save disk","To enable volumes"]'::jsonb, 0, 'Non-root limits damage if an attacker escapes the container.'),
  ('Docker', 'Cloud & DevOps', 'high', 'How do CMD and ENTRYPOINT differ?', '["ENTRYPOINT sets the executable; CMD provides default args","They are identical","CMD sets the executable; ENTRYPOINT is args","Only one can be used"]'::jsonb, 0, 'ENTRYPOINT defines what runs; CMD supplies overridable default arguments.'),
  ('Docker', 'Cloud & DevOps', 'ultra', 'Which kernel features isolate and limit containers?', '["Namespaces (isolation) and cgroups (resource limits)","Hypervisors and BIOS","Only chroot","TLS and firewalls"]'::jsonb, 0, 'Namespaces isolate views (PID, net, mount); cgroups cap CPU/memory.'),
  ('Docker', 'Cloud & DevOps', 'ultra', 'Why aren''t containers a full security boundary by default?', '["They share the host kernel, so a kernel exploit can escape","They have no isolation","They run as VMs","They encrypt nothing"]'::jsonb, 0, 'Shared-kernel isolation is weaker than VM boundaries; add seccomp/user namespaces/sandboxing for stronger isolation.'),
  ('Docker', 'Cloud & DevOps', 'ultra', 'Why can `COPY . .` early in a Dockerfile hurt caching?', '["Any source change busts the cache for all later steps","It encrypts the layer","It doubles the image size","It disables volumes"]'::jsonb, 0, 'Copying everything early means dependency-install layers re-run on any file change; copy manifests first.'),
  ('Docker', 'Cloud & DevOps', 'ultra', 'What does a distroless/minimal base image reduce?', '["Attack surface and image size","Build determinism","Network latency","CPU usage"]'::jsonb, 0, 'Fewer packages mean fewer vulnerabilities and a smaller footprint.'),
  ('Docker', 'Cloud & DevOps', 'ultra', 'What does BuildKit add to image builds?', '["Parallel builds, better caching, and secret mounts","Runtime scaling","Container monitoring","Service discovery"]'::jsonb, 0, 'BuildKit improves build performance and supports build-time secrets without baking them in.'),
  ('Kubernetes', 'Cloud & DevOps', 'easy', 'What is Kubernetes?', '["A container orchestration platform","A container runtime only","A database","A CI server"]'::jsonb, 0, 'Kubernetes schedules and manages containerized workloads across nodes.'),
  ('Kubernetes', 'Cloud & DevOps', 'easy', 'What is the smallest deployable unit?', '["A Pod","A container","A node","A Service"]'::jsonb, 0, 'A Pod wraps one or more containers sharing network/storage.'),
  ('Kubernetes', 'Cloud & DevOps', 'easy', 'What maintains a desired number of pod replicas?', '["A Deployment","A Service","A ConfigMap","An Ingress"]'::jsonb, 0, 'Deployments manage ReplicaSets to keep the desired replica count.'),
  ('Kubernetes', 'Cloud & DevOps', 'easy', 'What gives pods a stable network endpoint?', '["A Service","A Pod","A node","A Secret"]'::jsonb, 0, 'Services provide a stable virtual IP/DNS in front of pods.'),
  ('Kubernetes', 'Cloud & DevOps', 'easy', 'What stores non-secret configuration?', '["A ConfigMap","A Deployment","A node","A Service"]'::jsonb, 0, 'ConfigMaps hold config; Secrets hold sensitive values.'),
  ('Kubernetes', 'Cloud & DevOps', 'mid', 'What does a Deployment manage for releases?', '["Rolling updates of pod replicas","DNS records","Persistent disks only","TLS certificates"]'::jsonb, 0, 'Deployments roll out new pod versions gradually.'),
  ('Kubernetes', 'Cloud & DevOps', 'mid', 'What does a ClusterIP Service provide?', '["A stable internal virtual IP","A public IP","A persistent volume","A cron job"]'::jsonb, 0, 'ClusterIP exposes the service only inside the cluster.'),
  ('Kubernetes', 'Cloud & DevOps', 'mid', 'What routes external HTTP traffic to services?', '["An Ingress","A ConfigMap","A Secret","A node"]'::jsonb, 0, 'Ingress (with a controller) routes HTTP(S) to services by host/path.'),
  ('Kubernetes', 'Cloud & DevOps', 'mid', 'What places pods onto nodes?', '["The scheduler","The kubelet only","The Ingress","etcd"]'::jsonb, 0, 'The scheduler assigns pods to suitable nodes based on resources/constraints.'),
  ('Kubernetes', 'Cloud & DevOps', 'mid', 'What is a namespace for?', '["Logical isolation and grouping of resources","Storing secrets","Networking only","Scaling nodes"]'::jsonb, 0, 'Namespaces partition a cluster for teams/environments.'),
  ('Kubernetes', 'Cloud & DevOps', 'high', 'What does the reconciliation/control loop do?', '["Continuously drives actual state toward desired state","Compiles containers","Encrypts traffic","Caches images"]'::jsonb, 0, 'Controllers observe and act to converge the cluster to the declared spec.'),
  ('Kubernetes', 'Cloud & DevOps', 'high', 'What does a readiness probe control?', '["Whether a pod receives traffic","Whether a pod restarts","Node scaling","Log rotation"]'::jsonb, 0, 'A failing readiness probe removes the pod from Service endpoints.'),
  ('Kubernetes', 'Cloud & DevOps', 'high', 'What does a failing liveness probe trigger?', '["A restart of the container","Removal from the Service","A node drain","A new namespace"]'::jsonb, 0, 'Liveness failures cause the kubelet to restart the container.'),
  ('Kubernetes', 'Cloud & DevOps', 'high', 'What do resource requests and limits set?', '["Guaranteed (requests) and maximum (limits) CPU/memory","Network routes","Storage classes","Pod names"]'::jsonb, 0, 'Requests inform scheduling; limits cap usage at runtime.'),
  ('Kubernetes', 'Cloud & DevOps', 'high', 'What does a HorizontalPodAutoscaler do?', '["Scales pod replicas based on metrics","Resizes nodes","Rotates secrets","Builds images"]'::jsonb, 0, 'The HPA adjusts replica count from CPU/memory/custom metrics.'),
  ('Kubernetes', 'Cloud & DevOps', 'ultra', 'How does reconciliation make Kubernetes declarative?', '["Controllers continuously converge actual state to the declared desired state","It runs imperative scripts once","It snapshots the cluster","It compiles manifests"]'::jsonb, 0, 'You declare the end state; controllers keep making it true.'),
  ('Kubernetes', 'Cloud & DevOps', 'ultra', 'What does a StatefulSet add over a Deployment?', '["Stable identities and ordered, persistent per-pod storage","Faster rollouts","Ingress routing","Autoscaling"]'::jsonb, 0, 'StatefulSets suit databases needing stable network IDs and volumes.'),
  ('Kubernetes', 'Cloud & DevOps', 'ultra', 'How do requests vs limits behave at scheduling vs runtime?', '["Requests affect scheduling; limits cap/throttle at runtime (OOMKill on memory)","Both only affect scheduling","Both only affect runtime","They are interchangeable"]'::jsonb, 0, 'The scheduler reserves by requests; exceeding memory limits gets the container OOMKilled, CPU is throttled.'),
  ('Kubernetes', 'Cloud & DevOps', 'ultra', 'What problem does a PodDisruptionBudget solve?', '["Maintaining minimum availability during voluntary disruptions","Scaling nodes","Encrypting secrets","Routing traffic"]'::jsonb, 0, 'A PDB limits how many pods can be down during drains/upgrades.'),
  ('Kubernetes', 'Cloud & DevOps', 'ultra', 'How does a rolling update achieve zero downtime?', '["Gradually replace pods while readiness gates traffic to ready ones","Delete all pods then recreate","Scale to zero first","Restart the node"]'::jsonb, 0, 'New pods must pass readiness before old ones are removed, keeping capacity available.'),
  ('Git', 'Cloud & DevOps', 'easy', 'What kind of system is Git?', '["A distributed version control system","A build tool","A container runtime","A database"]'::jsonb, 0, 'Git is a distributed VCS where each clone has full history.'),
  ('Git', 'Cloud & DevOps', 'easy', 'What records a snapshot of changes?', '["A commit","A branch","A tag","A remote"]'::jsonb, 0, 'A commit captures the staged snapshot with a message and parent.'),
  ('Git', 'Cloud & DevOps', 'easy', 'What is a branch?', '["A movable pointer to a commit","A copy of the whole repo","A remote server","A merge conflict"]'::jsonb, 0, 'Branches are lightweight references that advance with new commits.'),
  ('Git', 'Cloud & DevOps', 'easy', 'Which command stages changes?', '["git add","git push","git log","git clone"]'::jsonb, 0, 'git add stages changes for the next commit.'),
  ('Git', 'Cloud & DevOps', 'easy', 'Which command uploads commits to a remote?', '["git push","git pull","git add","git status"]'::jsonb, 0, 'git push publishes local commits to the remote.'),
  ('Git', 'Cloud & DevOps', 'mid', 'What does git merge do?', '["Combines branches, possibly creating a merge commit","Deletes a branch","Rewrites history linearly","Uploads to a remote"]'::jsonb, 0, 'Merge integrates one branch into another, preserving both histories.'),
  ('Git', 'Cloud & DevOps', 'mid', 'What does git rebase do?', '["Reapplies commits onto a new base for a linear history","Creates a merge commit","Stashes changes","Tags a release"]'::jsonb, 0, 'Rebase moves commits to a new base, producing a straight-line history.'),
  ('Git', 'Cloud & DevOps', 'mid', 'What is a fast-forward merge?', '["Moving the branch pointer forward when there''s no divergence","A forced overwrite","A squash of all commits","A conflict resolution"]'::jsonb, 0, 'If the target hasn''t diverged, Git just advances the pointer — no merge commit.'),
  ('Git', 'Cloud & DevOps', 'mid', 'What does HEAD point to?', '["The current commit/branch you''re on","The remote default branch","The first commit","The staging area"]'::jsonb, 0, 'HEAD references your current position in the history.'),
  ('Git', 'Cloud & DevOps', 'mid', 'What does git stash do?', '["Temporarily shelves uncommitted changes","Deletes changes permanently","Creates a branch","Pushes to a remote"]'::jsonb, 0, 'Stash saves work-in-progress so you can switch context, then reapply it.'),
  ('Git', 'Cloud & DevOps', 'high', 'What is the merge vs rebase tradeoff?', '["Merge preserves the true history; rebase rewrites it for a linear log","Rebase is always safer","Merge deletes commits","They are identical"]'::jsonb, 0, 'Merge keeps the actual graph; rebase produces cleaner linear history but rewrites commits.'),
  ('Git', 'Cloud & DevOps', 'high', 'Why avoid rebasing a shared/public branch?', '["It rewrites history others have based work on","It is slower","It deletes the remote","It can''t be undone"]'::jsonb, 0, 'Rewritten commits diverge from collaborators'' copies, causing painful conflicts.'),
  ('Git', 'Cloud & DevOps', 'high', 'What does git cherry-pick do?', '["Applies a specific commit onto the current branch","Merges two branches","Reverts the last commit","Squashes history"]'::jsonb, 0, 'Cherry-pick replays a chosen commit elsewhere.'),
  ('Git', 'Cloud & DevOps', 'high', 'How does git revert differ from git reset?', '["Revert creates a new commit undoing changes (safe for shared history)","They are identical","Revert deletes commits","Reset is always safer"]'::jsonb, 0, 'Revert is additive and shareable; reset moves the branch pointer and can rewrite history.'),
  ('Git', 'Cloud & DevOps', 'high', 'What is the reflog used for?', '["Recovering lost commits via the history of HEAD movements","Listing remotes","Showing file diffs","Tagging releases"]'::jsonb, 0, 'The reflog records where HEAD/branches pointed, letting you recover ''lost'' commits.'),
  ('Git', 'Cloud & DevOps', 'ultra', 'What does an interactive rebase let you do?', '["Squash, reorder, edit, or drop commits before sharing","Push to multiple remotes","Resolve merge conflicts automatically","Encrypt history"]'::jsonb, 0, 'git rebase -i lets you rewrite a series of commits into a cleaner sequence.'),
  ('Git', 'Cloud & DevOps', 'ultra', 'How does Git store data internally?', '["As content-addressable objects (blobs/trees/commits) keyed by hash","As line-by-line diffs only","In a SQL database","As compressed patches per branch"]'::jsonb, 0, 'Git is a content-addressable store; identical content shares the same hash/object.'),
  ('Git', 'Cloud & DevOps', 'ultra', 'What is the danger of force-pushing after rebasing a shared branch?', '["It overwrites others'' refs, losing or diverging their work","It deletes the repo","It corrupts objects","It is impossible"]'::jsonb, 0, 'Force-push replaces remote history; collaborators'' commits can be lost without coordination.'),
  ('Git', 'Cloud & DevOps', 'ultra', 'What inputs does a three-way merge use?', '["The common ancestor plus both branch tips","Only the two tips","Only the ancestor","The reflog"]'::jsonb, 0, 'Comparing both sides against their merge base lets Git auto-resolve non-conflicting changes.'),
  ('Git', 'Cloud & DevOps', 'ultra', 'How can the reflog rescue you after a hard reset?', '["It logs prior ref positions so you can reset back to the lost commit","It re-downloads from the remote","It rebuilds from diffs","It can''t help"]'::jsonb, 0, 'Since the commit object still exists and the reflog remembers it, you can recover it.'),
  ('PostgreSQL', 'Databases & CRM', 'easy', 'What is PostgreSQL?', '["An open-source relational database","A key-value cache","A document store","A message queue"]'::jsonb, 0, 'PostgreSQL is a powerful open-source relational (SQL) database.'),
  ('PostgreSQL', 'Databases & CRM', 'easy', 'What language queries it?', '["SQL","PromQL","KQL","GraphQL"]'::jsonb, 0, 'You query Postgres with SQL.'),
  ('PostgreSQL', 'Databases & CRM', 'easy', 'What speeds up row lookups?', '["An index","A trigger","A view","A sequence"]'::jsonb, 0, 'Indexes let the database find rows without scanning the whole table.'),
  ('PostgreSQL', 'Databases & CRM', 'easy', 'What enforces uniqueness and identifies a row?', '["A primary key","A foreign key","An index hint","A comment"]'::jsonb, 0, 'A primary key uniquely identifies each row.'),
  ('PostgreSQL', 'Databases & CRM', 'easy', 'What structures rows and columns?', '["A table","A bucket","A collection","A stream"]'::jsonb, 0, 'Relational data lives in tables.'),
  ('PostgreSQL', 'Databases & CRM', 'mid', 'What does ACID stand for?', '["Atomicity, Consistency, Isolation, Durability","Async, Cache, Index, Data","Atomic, Concurrent, Indexed, Durable","Access, Control, ID, Domain"]'::jsonb, 0, 'ACID describes reliable transaction guarantees.'),
  ('PostgreSQL', 'Databases & CRM', 'mid', 'What does a JOIN do?', '["Combines rows from tables based on a condition","Deletes rows","Creates an index","Locks a table"]'::jsonb, 0, 'JOINs relate rows across tables on matching columns.'),
  ('PostgreSQL', 'Databases & CRM', 'mid', 'What does a transaction provide?', '["All-or-nothing execution of statements","Faster reads","Automatic indexing","Schema migration"]'::jsonb, 0, 'A transaction commits fully or rolls back, preserving consistency.'),
  ('PostgreSQL', 'Databases & CRM', 'mid', 'What is JSONB?', '["A binary JSON type that can be indexed","A text-only JSON column","A foreign key type","A backup format"]'::jsonb, 0, 'JSONB stores JSON in a binary, queryable, indexable form.'),
  ('PostgreSQL', 'Databases & CRM', 'mid', 'What does EXPLAIN show?', '["The query execution plan","The table schema","The user permissions","The backup status"]'::jsonb, 0, 'EXPLAIN reveals how the planner will execute a query.'),
  ('PostgreSQL', 'Databases & CRM', 'high', 'What does MVCC provide?', '["Readers don''t block writers via row versioning","Stronger locking on reads","Automatic sharding","In-memory storage"]'::jsonb, 0, 'Multi-Version Concurrency Control gives each transaction a consistent snapshot.'),
  ('PostgreSQL', 'Databases & CRM', 'high', 'Which index type suits JSONB containment queries?', '["GIN","B-tree","Hash","BRIN"]'::jsonb, 0, 'GIN indexes accelerate containment/key lookups in JSONB and arrays.'),
  ('PostgreSQL', 'Databases & CRM', 'high', 'What is a covering index?', '["One that satisfies a query without reading the table","An index on every column","A unique index","A partial index"]'::jsonb, 0, 'If all needed columns are in the index, Postgres can do an index-only scan.'),
  ('PostgreSQL', 'Databases & CRM', 'high', 'What does VACUUM do?', '["Reclaims space from dead tuples left by MVCC","Rebuilds all indexes","Backs up the database","Encrypts data"]'::jsonb, 0, 'Updates/deletes leave dead row versions; VACUUM reclaims that space.'),
  ('PostgreSQL', 'Databases & CRM', 'high', 'What does a partial index optimize?', '["Indexing only rows matching a predicate","All rows twice","Foreign keys","Sequences"]'::jsonb, 0, 'A partial index covers a subset (e.g. WHERE active), making it smaller/faster.'),
  ('PostgreSQL', 'Databases & CRM', 'ultra', 'How does MVCC let reads avoid locks?', '["Each transaction sees a consistent snapshot of row versions","It locks the whole table for reads","It disables writes","It copies the database"]'::jsonb, 0, 'Snapshots mean readers see a stable view without blocking writers.'),
  ('PostgreSQL', 'Databases & CRM', 'ultra', 'What causes table bloat and how is it addressed?', '["Dead tuples from updates/deletes; addressed by (auto)VACUUM","Too many indexes; addressed by dropping them","Large JSONB; addressed by GIN","Long names; addressed by renaming"]'::jsonb, 0, 'MVCC leaves dead tuples; autovacuum reclaims them to control bloat.'),
  ('PostgreSQL', 'Databases & CRM', 'ultra', 'What does the query planner rely on to choose plans?', '["Table statistics (ANALYZE) and cost estimates","Random selection","Alphabetical order","The newest index always"]'::jsonb, 0, 'Up-to-date statistics let the cost-based optimizer pick efficient plans.'),
  ('PostgreSQL', 'Databases & CRM', 'ultra', 'What is the database-layer N+1 problem?', '["Issuing many small queries instead of one set-based join","Too many indexes","Bloated tables","Missing primary keys"]'::jsonb, 0, 'Looping per-row queries is far slower than a single joined query.'),
  ('PostgreSQL', 'Databases & CRM', 'ultra', 'What is a key benefit of a recursive CTE?', '["Querying hierarchical/graph data (e.g. trees) iteratively","Faster than all indexes","Automatic sharding","Encrypting results"]'::jsonb, 0, 'WITH RECURSIVE traverses hierarchical relationships like org charts or categories.'),
  ('MySQL', 'Databases & CRM', 'easy', 'What is MySQL?', '["A popular open-source relational database","A document database","A cache","A search engine"]'::jsonb, 0, 'MySQL is a widely used relational (SQL) database.'),
