  ('MySQL', 'Databases & CRM', 'high', 'What does a composite index''s column order determine?', '["Which queries it serves via the leftmost prefix","Its storage engine","Its name","Its isolation level"]'::jsonb, 0, 'A composite index helps queries using its leading columns (leftmost prefix).'),
  ('MySQL', 'Databases & CRM', 'high', 'What does the InnoDB buffer pool cache?', '["Data and index pages in memory","Query text only","User sessions","Binary logs"]'::jsonb, 0, 'The buffer pool keeps hot pages in RAM to avoid disk I/O.'),
  ('MySQL', 'Databases & CRM', 'high', 'What does an index-only (covering) scan avoid?', '["Reading the full row from the table","Using the index","Locking","Sorting always"]'::jsonb, 0, 'If the index has all needed columns, MySQL skips the table lookup.'),
  ('MySQL', 'Databases & CRM', 'high', 'What is the cost of too many indexes?', '["Write amplification and extra storage","Slower reads always","Loss of transactions","Broken foreign keys"]'::jsonb, 0, 'Every write updates all relevant indexes, adding overhead.'),
  ('MySQL', 'Databases & CRM', 'ultra', 'How does the leftmost-prefix rule limit composite index use?', '["A query must use the leading columns to benefit from the index","Indexes work on any column subset","Only the last column matters","Order is irrelevant"]'::jsonb, 0, 'An index on (a,b,c) helps queries on a, a+b, a+b+c — not b alone.'),
  ('MySQL', 'Databases & CRM', 'ultra', 'What does InnoDB use for crash recovery?', '["The redo log (write-ahead logging)","The query cache","The buffer pool only","Snapshots"]'::jsonb, 0, 'The redo log replays committed changes after a crash for durability.'),
  ('MySQL', 'Databases & CRM', 'ultra', 'Why can SELECT * hurt performance?', '["It fetches unneeded columns and can defeat covering indexes","It locks the table","It disables the buffer pool","It is a syntax error"]'::jsonb, 0, 'Selecting only needed columns enables index-only scans and less I/O.'),
  ('MySQL', 'Databases & CRM', 'ultra', 'What is a deadlock, and how does InnoDB resolve it?', '["A cyclic lock wait; InnoDB rolls back a victim transaction","A network timeout; it retries","A full disk; it pauses","A bad index; it rebuilds"]'::jsonb, 0, 'InnoDB detects the cycle and aborts one transaction to break it.'),
