  ('Oracle', 'Databases & CRM', 'mid', 'What does a bind variable improve?', '["Plan reuse and protection from SQL injection","Disk space","Backup speed","Index size"]'::jsonb, 0, 'Bind variables let the optimizer reuse plans and avoid injection.'),
