  ('Oracle', 'Databases & CRM', 'high', 'What does a materialized view store?', '["Precomputed query results that are refreshed","Only the query text","A user session","An index definition"]'::jsonb, 0, 'Materialized views persist results for fast reads, refreshed periodically.'),
  ('Oracle', 'Databases & CRM', 'high', 'What does partitioning improve?', '["Manageability and performance on very large tables","Backup encryption","User security","Network latency"]'::jsonb, 0, 'Partitioning splits big tables so queries/maintenance touch less data.'),
  ('Oracle', 'Databases & CRM', 'high', 'What is the optimizer''s role?', '["Choosing an efficient execution plan using statistics","Encrypting data","Scheduling backups","Managing users"]'::jsonb, 0, 'The cost-based optimizer picks plans based on table statistics.'),
  ('Oracle', 'Databases & CRM', 'high', 'What does Oracle use for read consistency?', '["Undo/rollback segments to build consistent snapshots","Table locks on reads","The redo log only","Materialized views"]'::jsonb, 0, 'Undo data lets readers see a consistent point-in-time view without blocking.'),
  ('Oracle', 'Databases & CRM', 'ultra', 'Why do bind variables reduce hard parses?', '["The same cached plan is reused across different literal values","They skip the optimizer","They disable statistics","They compress SQL"]'::jsonb, 0, 'Without binds, each literal value yields a new parse; binds enable plan reuse.'),
