  ('MongoDB', 'Databases & CRM', 'mid', 'What does an index do in MongoDB?', '["Speeds queries by avoiding collection scans","Encrypts documents","Shards data","Backs up data"]'::jsonb, 0, 'Indexes let queries target documents efficiently.'),
  ('MongoDB', 'Databases & CRM', 'mid', 'What is the aggregation pipeline?', '["A staged sequence of document transformations","A backup process","A replication channel","An index builder"]'::jsonb, 0, 'Pipelines pass documents through stages like $match, $group, $project.'),
  ('MongoDB', 'Databases & CRM', 'mid', 'What is embedding vs referencing?', '["Nesting related data vs linking by id","Two index types","Two query languages","Two backup modes"]'::jsonb, 0, 'Embed for data accessed together; reference to link separate documents.'),
  ('MongoDB', 'Databases & CRM', 'mid', 'What is a replica set?', '["A primary with secondaries for high availability","A sharded cluster","An index group","A backup schedule"]'::jsonb, 0, 'Replica sets replicate data and elect a new primary on failure.'),
  ('MongoDB', 'Databases & CRM', 'mid', 'What does the $lookup stage do?', '["Performs a left outer join across collections","Creates an index","Shards a collection","Deletes documents"]'::jsonb, 0, '$lookup joins documents from another collection.'),
  ('MongoDB', 'Databases & CRM', 'high', 'When should you prefer embedding over referencing?', '["When data is accessed together and bounded in size","Always","Only for large arrays","Never"]'::jsonb, 0, 'Embedding avoids joins when related data is read together and stays small.'),
  ('MongoDB', 'Databases & CRM', 'high', 'What does sharding provide?', '["Horizontal scaling across nodes by a shard key","Stronger consistency","Automatic indexing","Smaller documents"]'::jsonb, 0, 'Sharding distributes data across shards to scale writes/storage.'),
