  ('MongoDB', 'Databases & CRM', 'high', 'What do write concern and read concern control?', '["Durability/consistency guarantees for writes and reads","Index creation","Sharding strategy","Backup frequency"]'::jsonb, 0, 'They tune how many nodes must acknowledge and what data reads can see.'),
  ('MongoDB', 'Databases & CRM', 'high', 'What does an index covering a query''s filter and sort avoid?', '["In-memory sorts and collection scans","Replication","Sharding","Backups"]'::jsonb, 0, 'A well-ordered index can serve both filtering and sorting efficiently.'),
  ('MongoDB', 'Databases & CRM', 'ultra', 'Why is shard key choice critical and hard to change?', '["It dictates distribution/hotspots and is effectively permanent","It only affects backups","It can be changed anytime freely","It controls indexing only"]'::jsonb, 0, 'A poor shard key causes hotspots/scatter-gather, and resharding is costly.'),
  ('MongoDB', 'Databases & CRM', 'ultra', 'What is the risk of unbounded array embedding?', '["Documents can grow toward the 16MB limit and degrade performance","It improves writes","It shards automatically","It speeds queries"]'::jsonb, 0, 'Ever-growing arrays bloat documents and hurt read/write performance.'),
  ('MongoDB', 'Databases & CRM', 'ultra', 'What causes a scatter-gather query in a sharded cluster?', '["A query that omits the shard key, hitting all shards","Using an index","A small result set","A covered query"]'::jsonb, 0, 'Without the shard key, the router must query every shard.'),
  ('MongoDB', 'Databases & CRM', 'ultra', 'How do write concern and read concern trade off?', '["Higher durability/consistency costs more latency","They have no effect","More consistency is always free","They only affect storage"]'::jsonb, 0, 'Waiting for more acknowledgements/consistent reads increases latency.'),
  ('MongoDB', 'Databases & CRM', 'ultra', 'What is the cost of $lookup at scale?', '["Cross-collection joins can be expensive, unlike embedded data","It is always free","It shards automatically","It reduces index use"]'::jsonb, 0, 'Joins counter Mongo''s document model strengths; embedding is often faster for hot paths.'),
  ('Couchbase', 'Databases & CRM', 'easy', 'What is Couchbase?', '["A distributed NoSQL document database","A relational database","A message broker","A CDN"]'::jsonb, 0, 'Couchbase is a distributed JSON document database with a built-in cache.'),
