  ('Redis', 'Databases & CRM', 'mid', 'What is a sorted set ideal for?', '["Leaderboards and ranked data","Binary blobs","Joins","Schemas"]'::jsonb, 0, 'Sorted sets keep members ordered by score, perfect for rankings.'),
  ('Redis', 'Databases & CRM', 'mid', 'What is Redis pub/sub for?', '["Messaging between publishers and subscribers","Persisting data","Indexing","Sharding"]'::jsonb, 0, 'Pub/sub broadcasts messages to subscribed clients.'),
  ('Redis', 'Databases & CRM', 'mid', 'Is Redis command execution effectively single-threaded?', '["Yes — commands run one at a time","No, fully multi-threaded","Only for reads","Only with clustering"]'::jsonb, 0, 'The main command loop is single-threaded, giving atomic command execution.'),
  ('Redis', 'Databases & CRM', 'mid', 'What does EXPIRE do?', '["Sets a time-to-live on a key","Deletes all keys","Persists to disk","Creates a replica"]'::jsonb, 0, 'EXPIRE schedules a key to be removed after N seconds.'),
  ('Redis', 'Databases & CRM', 'high', 'What is the cache-aside pattern?', '["App checks cache, loads from DB on miss, then populates the cache","DB writes straight to cache only","Cache writes to DB synchronously","No cache is used"]'::jsonb, 0, 'Cache-aside (lazy loading) fills the cache on demand after a miss.'),
  ('Redis', 'Databases & CRM', 'high', 'What does Redis Cluster provide?', '["Sharding across nodes via hash slots","Stronger single-node durability","SQL queries","Automatic indexing"]'::jsonb, 0, 'Cluster mode partitions the keyspace across nodes by hash slot.'),
  ('Redis', 'Databases & CRM', 'high', 'What is the AOF vs RDB tradeoff?', '["AOF gives finer durability but larger/slower; RDB is compact/faster but coarser","RDB is always more durable","They are identical","AOF can''t be replayed"]'::jsonb, 0, 'AOF logs every write (better recovery); RDB snapshots are smaller but lose recent writes.'),
  ('Redis', 'Databases & CRM', 'high', 'What does a common eviction policy like allkeys-lru do?', '["Evicts least-recently-used keys when maxmemory is reached","Deletes random keys hourly","Never evicts","Evicts the largest keys"]'::jsonb, 0, 'LRU eviction frees memory by dropping the least recently used keys.'),
  ('Redis', 'Databases & CRM', 'high', 'What problem does a distributed lock address?', '["Mutual exclusion across processes/instances","Faster reads","Data compression","Indexing"]'::jsonb, 0, 'Distributed locks coordinate exclusive access to a shared resource.'),
  ('Redis', 'Databases & CRM', 'ultra', 'What is a cache stampede, and how do you mitigate it?', '["Many simultaneous misses hammer the DB; mitigate with locking/early recompute/jittered TTLs","Too many writes; add replicas","A network loop; restart","An eviction bug; disable TTL"]'::jsonb, 0, 'When a hot key expires, concurrent misses overload the backend; use a lock or staggered expiry.'),
  ('Redis', 'Databases & CRM', 'ultra', 'Why is single-threaded execution fast yet requires caution?', '["No lock overhead, but one slow command blocks all (avoid O(N) like KEYS)","It is slow and safe","It allows parallel writes","It needs no memory limit"]'::jsonb, 0, 'Atomicity is free, but a heavy command stalls everything — use SCAN, not KEYS.'),
  ('Redis', 'Databases & CRM', 'ultra', 'How does Redis Cluster route a key to a node?', '["Hash slots (CRC16 mod 16384) mapped to nodes","Round-robin","By key length","Randomly"]'::jsonb, 0, 'Each key maps to one of 16384 hash slots, which are distributed across nodes.'),
  ('Redis', 'Databases & CRM', 'ultra', 'What is the consistency caveat of async replication on failover?', '["Recently acknowledged writes can be lost (not strongly consistent)","Writes are always preserved","Reads stop entirely","It guarantees linearizability"]'::jsonb, 0, 'Async replication means a primary failure can drop writes not yet replicated.'),
  ('Redis', 'Databases & CRM', 'ultra', 'What does setting maxmemory plus an eviction policy prevent?', '["Unbounded memory growth and out-of-memory failures","Slow reads","Replication lag","Key collisions"]'::jsonb, 0, 'A memory cap with eviction keeps Redis from exhausting RAM.'),
