  ('HubSpot', 'Databases & CRM', 'easy', 'What is a deal?', '["A sales opportunity record","A marketing email","A contact list","A dashboard"]'::jsonb, 0, 'Deals track revenue opportunities through stages.'),
  ('HubSpot', 'Databases & CRM', 'easy', 'What is a pipeline?', '["The set of stages a deal moves through","A data backup","An API key","A report type"]'::jsonb, 0, 'Pipelines define the sales stages from lead to close.'),
