  ('React', 'Frontend & Mobile', 'easy', 'What should each item in a rendered list have?', '["A unique key prop","An onClick handler","An id attribute only","A ref"]'::jsonb, 0, 'Stable, unique keys help React match list items across renders.'),
  ('React', 'Frontend & Mobile', 'easy', 'Which hook runs side effects after render?', '["useEffect","useState","useMemo","useId"]'::jsonb, 0, 'useEffect runs effects (subscriptions, fetches) after the component renders.'),
  ('React', 'Frontend & Mobile', 'mid', 'What does useEffect''s dependency array control?', '["When the effect re-runs","The order of hooks","Whether the component renders","The effect''s return type"]'::jsonb, 0, 'The effect re-runs when any dependency value changes between renders.'),
  ('React', 'Frontend & Mobile', 'mid', 'What does useMemo do?', '["Memoizes a computed value between renders","Memoizes a function reference","Triggers a re-render","Stores DOM nodes"]'::jsonb, 0, 'useMemo caches an expensive computation, recomputing only when deps change.'),
  ('React', 'Frontend & Mobile', 'mid', 'What does useCallback return?', '["A memoized function reference","A memoized value","A ref object","A context value"]'::jsonb, 0, 'useCallback returns a stable function identity across renders unless deps change.'),
  ('React', 'Frontend & Mobile', 'mid', 'What causes a component to re-render?', '["A change to its state or props","A console.log call","A CSS change","Scrolling the page"]'::jsonb, 0, 'React re-renders when state or props change (or a parent re-renders).'),
  ('React', 'Frontend & Mobile', 'mid', 'What does useReducer help manage?', '["Complex state transitions via a reducer","Network requests","CSS variables","Routing"]'::jsonb, 0, 'useReducer centralizes related state updates into a (state, action) reducer.'),
  ('React', 'Frontend & Mobile', 'high', 'What is reconciliation?', '["React''s diffing of the virtual tree to update the DOM minimally","Merging two git branches","Synchronizing server state","Resolving CSS specificity"]'::jsonb, 0, 'Reconciliation compares the new and previous element trees to apply minimal DOM changes.'),
  ('React', 'Frontend & Mobile', 'high', 'What does useRef provide?', '["A mutable value that persists without triggering re-renders","Reactive state","A memoized callback","A context provider"]'::jsonb, 0, 'A ref''s .current can change without causing a render; often used for DOM nodes or instance values.'),
  ('React', 'Frontend & Mobile', 'high', 'What is a core rule of hooks?', '["Call them at the top level, in the same order every render","Call them only inside loops","Call them after early returns","Call them inside event handlers only"]'::jsonb, 0, 'Hooks must run unconditionally at the top level so React can match them by call order.'),
  ('React', 'Frontend & Mobile', 'high', 'What does React.memo do?', '["Skips re-rendering when props are shallowly equal","Caches network responses","Memoizes a value","Defers rendering to idle time"]'::jsonb, 0, 'React.memo wraps a component to bail out of re-renders when props haven''t shallowly changed.'),
  ('React', 'Frontend & Mobile', 'high', 'Why must you treat state as immutable?', '["React compares references to decide re-renders, so mutation can be missed","Mutation throws an error","Immutability is required by JSX","It improves CSS performance"]'::jsonb, 0, 'React often relies on reference identity; mutating in place can skip needed updates.'),
  ('React', 'Frontend & Mobile', 'ultra', 'What does concurrent rendering (React 18) enable?', '["Interruptible rendering so urgent updates can preempt","Multi-threaded JavaScript","Server-only rendering","Automatic memoization of all components"]'::jsonb, 0, 'Concurrent features let React pause, resume, and prioritize rendering work.'),
  ('React', 'Frontend & Mobile', 'ultra', 'What does useTransition do?', '["Marks state updates as non-urgent to keep the UI responsive","Animates DOM transitions","Suspends data fetching","Batches all updates synchronously"]'::jsonb, 0, 'Updates wrapped in startTransition are lower priority, so urgent input stays snappy.'),
  ('React', 'Frontend & Mobile', 'ultra', 'How does useLayoutEffect differ from useEffect?', '["It fires synchronously after DOM mutations, before the browser paints","It runs only on the server","It never runs on mount","It debounces effects"]'::jsonb, 0, 'useLayoutEffect runs before paint, useful for measuring layout, but can block paint.'),
  ('React', 'Frontend & Mobile', 'ultra', 'What do React Server Components primarily reduce?', '["Client JavaScript shipped for server-rendered parts","Server CPU usage","CSS bundle size only","The number of network requests to zero"]'::jsonb, 0, 'Server Components render on the server and ship no JS for themselves, shrinking the client bundle.'),
  ('React', 'Frontend & Mobile', 'ultra', 'Why can a key like the array index cause bugs?', '["Reordering/inserting makes React mismatch state to the wrong item","Indexes are not unique","Indexes are strings","It disables reconciliation"]'::jsonb, 0, 'Index keys break identity when the list reorders, leaking state to the wrong element.'),
