  ('React Native', 'Frontend & Mobile', 'easy', 'Which component efficiently renders long, scrollable lists?', '["FlatList","ScrollView","View","List"]'::jsonb, 0, 'FlatList virtualizes rows, rendering only what''s visible.'),
