  ('Next.js', 'Frontend & Mobile', 'easy', 'What does next/link provide?', '["Client-side navigation between routes","Server logging","Image optimization","CSS modules"]'::jsonb, 0, '<Link> performs client-side transitions and prefetching.'),
  ('Next.js', 'Frontend & Mobile', 'easy', 'What does next/image optimize?', '["Image sizing, lazy loading, and formats","Fonts","Routing","API responses"]'::jsonb, 0, 'The Image component automatically optimizes and lazy-loads images.'),
  ('Next.js', 'Frontend & Mobile', 'easy', 'Which directory powers the App Router (Next 13+)?', '["app/","pages/","routes/","src-only"]'::jsonb, 0, 'The app/ directory enables the App Router with layouts and Server Components.'),
  ('Next.js', 'Frontend & Mobile', 'easy', 'What does `next build` produce?', '["An optimized production build","A dev server","A test report","A lint summary"]'::jsonb, 0, '`next build` compiles and optimizes the app for production.'),
  ('Next.js', 'Frontend & Mobile', 'mid', 'What is SSR?', '["Rendering the page HTML on the server per request","Rendering only on the client","Static export at build time","Streaming video"]'::jsonb, 0, 'Server-side rendering generates HTML on each request.'),
  ('Next.js', 'Frontend & Mobile', 'mid', 'What is SSG?', '["Pre-rendering pages at build time","Rendering per request","Client-only rendering","Server streaming"]'::jsonb, 0, 'Static Site Generation pre-renders HTML during the build.'),
  ('Next.js', 'Frontend & Mobile', 'mid', 'What does ISR (Incremental Static Regeneration) do?', '["Rebuilds static pages in the background after a revalidate interval","Renders everything per request","Disables caching","Runs only in development"]'::jsonb, 0, 'ISR lets static pages update after deployment without a full rebuild.'),
  ('Next.js', 'Frontend & Mobile', 'mid', 'In the App Router, what is a component by default?', '["A Server Component","A Client Component","A static HTML file","An API route"]'::jsonb, 0, 'App Router components are Server Components unless marked otherwise.'),
  ('Next.js', 'Frontend & Mobile', 'mid', 'How do you opt a component into the client?', '["Add the \"use client\" directive at the top","Export default async","Wrap it in Suspense","Name it with .client.tsx"]'::jsonb, 0, '"use client" marks a module (and its imports) as a Client Component boundary.'),
  ('Next.js', 'Frontend & Mobile', 'high', 'What can a Server Component NOT use?', '["Browser-only APIs and hooks like useState/useEffect","async/await","fetch","Importing other components"]'::jsonb, 0, 'Server Components run on the server, so they lack state hooks and browser APIs.'),
  ('Next.js', 'Frontend & Mobile', 'high', 'What does generateStaticParams do?', '["Pre-generates dynamic route segments at build time","Fetches data on the client","Defines middleware","Configures redirects"]'::jsonb, 0, 'It returns the params to statically pre-render for a dynamic route.'),
  ('Next.js', 'Frontend & Mobile', 'high', 'By default, how is `fetch` treated in the App Router?', '["Cached unless you opt out with revalidate or no-store","Never cached","Cached only in development","Cached for exactly 60 seconds"]'::jsonb, 0, 'App Router fetches are cached by default; you control freshness with revalidate/no-store.'),
  ('Next.js', 'Frontend & Mobile', 'high', 'What are Route Handlers?', '["API endpoints defined in route.ts using web Request/Response","Client navigation events","Build-time hooks","CSS scoping rules"]'::jsonb, 0, 'route.ts files export GET/POST/etc. handlers, replacing pages/api in the App Router.'),
  ('Next.js', 'Frontend & Mobile', 'high', 'What does streaming with Suspense enable?', '["Sending HTML progressively as parts of the page become ready","Video streaming","Disabling JS","Server logging"]'::jsonb, 0, 'Suspense boundaries let the server stream ready chunks while slower parts load.'),
  ('Next.js', 'Frontend & Mobile', 'ultra', 'What are Server Actions?', '["Server-run functions callable from components for mutations without a separate API route","Edge middleware functions","Build scripts","Client event handlers"]'::jsonb, 0, 'Server Actions let forms/components invoke server functions directly for mutations.'),
  ('Next.js', 'Frontend & Mobile', 'ultra', 'How does Partial Prerendering work?', '["Serve a static shell instantly and stream dynamic holes","Render everything dynamically","Cache the whole page forever","Disable SSR"]'::jsonb, 0, 'PPR combines a static shell with streamed dynamic regions in one response.'),
  ('Next.js', 'Frontend & Mobile', 'ultra', 'How does Next dedupe identical fetches within one render?', '["Request memoization across the render pass","It doesn''t — each call hits the network","By hashing the response","Via service workers"]'::jsonb, 0, 'Identical fetch calls in the same render are memoized to avoid duplicate requests.'),
  ('Next.js', 'Frontend & Mobile', 'ultra', 'What does the Edge runtime restrict?', '["A limited subset of Node APIs, running on V8 isolates","All async code","TypeScript","JSX"]'::jsonb, 0, 'Edge functions run on lightweight isolates without full Node APIs (no native modules/fs).'),
  ('Next.js', 'Frontend & Mobile', 'ultra', 'What is the main tradeoff of marking a subtree "use client"?', '["It ships JS and gives up server-only rendering benefits for that subtree","It disables routing","It prevents data fetching","It forces static export"]'::jsonb, 0, 'Client Components increase the JS bundle and run in the browser, losing zero-JS server rendering.'),
  ('TanStack', 'Frontend & Mobile', 'easy', 'What kind of state is TanStack Query designed for?', '["Server state (async data fetching and caching)","Local form state","CSS theme state","Routing state"]'::jsonb, 0, 'TanStack Query manages asynchronous server data: fetching, caching, and syncing.'),
  ('TanStack', 'Frontend & Mobile', 'easy', 'Which hook reads data?', '["useQuery","useMutation","useStore","useFetch"]'::jsonb, 0, 'useQuery fetches and caches read data keyed by a query key.'),
  ('TanStack', 'Frontend & Mobile', 'easy', 'What uniquely identifies a cached query?', '["The query key","The component name","The URL only","A random id"]'::jsonb, 0, 'Query keys (usually arrays) identify and index cached entries.'),
  ('TanStack', 'Frontend & Mobile', 'easy', 'Which hook performs writes?', '["useMutation","useQuery","useEffect","useState"]'::jsonb, 0, 'useMutation handles create/update/delete operations.'),
  ('TanStack', 'Frontend & Mobile', 'easy', 'What does isLoading typically mean?', '["A query is fetching with no cached data yet","The mutation failed","The cache is empty forever","The network is offline"]'::jsonb, 0, 'isLoading (isPending) indicates the first fetch with no cached data.'),
  ('TanStack', 'Frontend & Mobile', 'mid', 'What does staleTime control?', '["How long fetched data is considered fresh before refetching","How long data stays in the cache","Request timeout","Retry count"]'::jsonb, 0, 'Within staleTime, cached data is used without a background refetch.'),
  ('TanStack', 'Frontend & Mobile', 'mid', 'What does invalidateQueries do?', '["Marks matching queries stale and triggers refetch","Deletes the cache permanently","Pauses all queries","Clears local storage"]'::jsonb, 0, 'Invalidation flags queries as stale so they refetch on next use.'),
  ('TanStack', 'Frontend & Mobile', 'mid', 'How do staleTime and gcTime differ?', '["staleTime is freshness; gcTime is how long unused cache is retained","They are the same","gcTime is freshness; staleTime is retention","Both control retries"]'::jsonb, 0, 'gcTime (cacheTime) controls when inactive data is garbage-collected.'),
  ('TanStack', 'Frontend & Mobile', 'mid', 'Which event triggers automatic refetch by default?', '["Window refocus (and reconnect/mount)","Every render","Scrolling","Typing"]'::jsonb, 0, 'By default queries refetch on window focus, reconnect, and remount when stale.'),
  ('TanStack', 'Frontend & Mobile', 'mid', 'What happens when a query key changes?', '["It is treated as a different query and refetches","Nothing","It throws an error","The cache is cleared globally"]'::jsonb, 0, 'A new key maps to a different cache entry, fetching fresh data.'),
  ('TanStack', 'Frontend & Mobile', 'high', 'What is an optimistic update?', '["Updating the cache immediately and rolling back on error","Retrying failed requests","Prefetching the next page","Disabling the cache"]'::jsonb, 0, 'You apply the expected result instantly, then revert if the mutation fails.'),
  ('TanStack', 'Frontend & Mobile', 'high', 'How do you build paginated infinite lists?', '["useInfiniteQuery with getNextPageParam","useQuery in a loop","useMutation","Manual fetch in useEffect"]'::jsonb, 0, 'useInfiniteQuery accumulates pages and derives the next page param.'),
  ('TanStack', 'Frontend & Mobile', 'high', 'What does the `select` option do?', '["Transforms/derives data without changing the cached value","Selects which query to run","Filters network requests","Picks a retry strategy"]'::jsonb, 0, 'select shapes the data returned to the component while the cache keeps the raw result.'),
  ('TanStack', 'Frontend & Mobile', 'high', 'What does keepPreviousData/placeholderData improve?', '["Smooth pagination by showing prior data while fetching new","Retry behavior","Cache size","Error formatting"]'::jsonb, 0, 'It avoids flashing a loading state when only the key (e.g. page) changes.'),
  ('TanStack', 'Frontend & Mobile', 'high', 'Why use array (hierarchical) query keys?', '["They enable partial/prefix invalidation of related queries","They are required syntax","They are faster to hash","They avoid network calls"]'::jsonb, 0, 'Structured keys let you invalidate groups, e.g. all [''todos''] entries.'),
  ('TanStack', 'Frontend & Mobile', 'ultra', 'How does request deduplication work?', '["Concurrent identical keys share one in-flight request","Each component fetches separately","Requests are queued globally","It caches by URL only"]'::jsonb, 0, 'Multiple components using the same key during a fetch share the single promise.'),
  ('TanStack', 'Frontend & Mobile', 'ultra', 'What does structural sharing optimize?', '["Preserving unchanged references to avoid needless re-renders","Disk usage","Network bandwidth","Bundle size"]'::jsonb, 0, 'Query keeps stable references for unchanged parts of data, reducing renders.'),
  ('TanStack', 'Frontend & Mobile', 'ultra', 'How does prefetching improve perceived performance?', '["It warms the cache before navigation so data appears instantly","It compresses responses","It retries faster","It disables refetching"]'::jsonb, 0, 'prefetchQuery loads data ahead of time so the next screen has it cached.'),
  ('TanStack', 'Frontend & Mobile', 'ultra', 'What happens to a mutation while offline (with pausing)?', '["It is paused and resumes when the connection returns","It fails immediately","It is silently dropped","It blocks the UI thread"]'::jsonb, 0, 'Network-mode pausing queues mutations/queries until connectivity is restored.'),
  ('TanStack', 'Frontend & Mobile', 'ultra', 'How can the cache survive reloads?', '["Use a persister (localStorage/AsyncStorage) via persistQueryClient","It persists automatically","Store keys in cookies","Use a service worker only"]'::jsonb, 0, 'persistQueryClient serializes the cache to storage and rehydrates on startup.'),
  ('Redux', 'Frontend & Mobile', 'easy', 'What holds the entire application state?', '["The store","The reducer","The action","The selector"]'::jsonb, 0, 'Redux keeps one state tree in a single store.'),
  ('Redux', 'Frontend & Mobile', 'easy', 'How do you request a state change?', '["Dispatch an action","Mutate the store directly","Call setState","Edit the reducer at runtime"]'::jsonb, 0, 'You dispatch an action describing what happened.'),
  ('Redux', 'Frontend & Mobile', 'easy', 'What computes the next state?', '["A reducer","A selector","A dispatcher","A thunk"]'::jsonb, 0, 'A reducer is a pure (state, action) => newState function.'),
  ('Redux', 'Frontend & Mobile', 'easy', 'What must a reducer be?', '["A pure function with no side effects","An async function","A class method","A generator"]'::jsonb, 0, 'Reducers must be pure and deterministic for predictable state.'),
  ('Redux', 'Frontend & Mobile', 'easy', 'What does an action describe?', '["An event, via a type (and optional payload)","A component","A CSS rule","A route"]'::jsonb, 0, 'Actions are plain objects with a type field describing what happened.'),
  ('Redux', 'Frontend & Mobile', 'mid', 'What does Redux Toolkit''s createSlice generate?', '["A reducer plus matching action creators","Only selectors","A React component","A store instance"]'::jsonb, 0, 'createSlice produces the slice reducer and auto-generated action creators.'),
  ('Redux', 'Frontend & Mobile', 'mid', 'Why must reducers avoid mutating state?', '["Redux detects changes by new references","Mutation is a syntax error","It breaks TypeScript","It slows the network"]'::jsonb, 0, 'Reference equality drives update detection; in-place mutation can be missed.'),
  ('Redux', 'Frontend & Mobile', 'mid', 'What is a selector?', '["A function that reads/derives a piece of state","A reducer factory","A middleware","An action creator"]'::jsonb, 0, 'Selectors encapsulate how to read or compute values from the state tree.'),
  ('Redux', 'Frontend & Mobile', 'mid', 'Which middleware handles async logic by default in RTK?', '["thunk","saga","observable","logger"]'::jsonb, 0, 'Redux Toolkit includes redux-thunk by default for async action creators.'),
  ('Redux', 'Frontend & Mobile', 'mid', 'What does "single source of truth" mean?', '["State lives in one centralized tree","Each component owns its state","The server is the only state","There is no shared state"]'::jsonb, 0, 'All shared state is in the one store, simplifying reasoning and debugging.'),
  ('Redux', 'Frontend & Mobile', 'high', 'How does Immer (used by RTK) let you write mutating code safely?', '["It records draft mutations and produces a new immutable state","It deep-clones on every change","It freezes the store","It disables reducers"]'::jsonb, 0, 'Immer tracks changes to a draft and outputs an immutable next state.'),
  ('Redux', 'Frontend & Mobile', 'high', 'What does createAsyncThunk manage?', '["pending/fulfilled/rejected lifecycle actions for async logic","Synchronous reducers only","Component rendering","Routing transitions"]'::jsonb, 0, 'It dispatches lifecycle actions you can handle in extraReducers.'),
  ('Redux', 'Frontend & Mobile', 'high', 'What does reselect''s memoization prevent?', '["Recomputing derived data when inputs are unchanged","Network calls","Re-rendering of the store","Action dispatch"]'::jsonb, 0, 'Memoized selectors recompute only when their input selectors change.'),
  ('Redux', 'Frontend & Mobile', 'high', 'What is RTK Query?', '["A data fetching/caching layer built into Redux Toolkit","A SQL query builder","A selector library","A testing tool"]'::jsonb, 0, 'RTK Query handles server-state fetching, caching, and invalidation within Redux.'),
  ('Redux', 'Frontend & Mobile', 'high', 'Why normalize state?', '["To avoid duplication and update entities by id efficiently","To make state immutable","To reduce the bundle","To enable SSR"]'::jsonb, 0, 'Normalized (by-id) state removes duplication and simplifies updates.'),
  ('Redux', 'Frontend & Mobile', 'ultra', 'Why can a non-memoized selector returning a new object hurt performance?', '["A new reference each call can trigger unnecessary re-renders","It throws an error","It mutates the store","It blocks dispatch"]'::jsonb, 0, 'useSelector compares by reference, so fresh objects look like changes every render.'),
  ('Redux', 'Frontend & Mobile', 'ultra', 'What does the entity-adapter pattern provide at scale?', '["Normalized {ids, entities} storage with CRUD helpers","Automatic component generation","Server rendering","A router"]'::jsonb, 0, 'createEntityAdapter standardizes normalized collections and their reducers/selectors.'),
  ('Redux', 'Frontend & Mobile', 'ultra', 'How does the store notify the UI after dispatch?', '["It runs the root reducer, then calls subscribed listeners","It re-mounts the app","It posts a network request","It mutates the DOM directly"]'::jsonb, 0, 'After computing new state, the store calls subscribers (e.g. react-redux).'),
  ('Redux', 'Frontend & Mobile', 'ultra', 'Where does middleware sit?', '["Between dispatching an action and the reducer receiving it","Inside React components","After the reducer returns","In the selector layer"]'::jsonb, 0, 'Middleware wraps dispatch, enabling async, logging, etc., before reducers run.'),
  ('Redux', 'Frontend & Mobile', 'ultra', 'Why is time-travel debugging possible in Redux?', '["State is a pure function of (previous state, action), fully reproducible","Actions are stored on the server","Reducers are async","The store snapshots the DOM"]'::jsonb, 0, 'Deterministic reducers let tools replay actions to reconstruct any past state.'),
  ('Tailwind', 'Frontend & Mobile', 'easy', 'What kind of CSS framework is Tailwind?', '["Utility-first","Component-based with prebuilt widgets","A CSS preprocessor","A CSS-in-JS runtime"]'::jsonb, 0, 'Tailwind provides low-level utility classes you compose in markup.'),
  ('Tailwind', 'Frontend & Mobile', 'easy', 'Which class sets display: flex?', '["flex","d-flex","display-flex","flexbox"]'::jsonb, 0, 'The `flex` utility sets display: flex.'),
  ('Tailwind', 'Frontend & Mobile', 'easy', 'How do you set text color to red-500?', '["text-red-500","color-red-500","text-[red]","red-500"]'::jsonb, 0, 'Color utilities follow text-{color}-{shade}.'),
  ('Tailwind', 'Frontend & Mobile', 'easy', 'How is padding of size 4 applied?', '["p-4","padding-4","pad-4","p:4"]'::jsonb, 0, 'p-4 applies padding on all sides (1rem by default).'),
  ('Tailwind', 'Frontend & Mobile', 'easy', 'Where are utility classes applied?', '["Directly in the markup''s class attribute","In a separate .scss file","In JS objects","In a config only"]'::jsonb, 0, 'You compose utilities in the element''s class list.'),
  ('Tailwind', 'Frontend & Mobile', 'mid', 'How does Tailwind''s responsive model work?', '["Mobile-first: unprefixed applies everywhere, md: applies at >= breakpoint","Desktop-first with max-width prefixes only","Breakpoints require media query files","It has no breakpoints"]'::jsonb, 0, 'Prefixes like md: apply from that breakpoint upward (min-width).'),
  ('Tailwind', 'Frontend & Mobile', 'mid', 'How do you style the hover state?', '["Prefix the utility with hover:","Use :hover in a CSS file","Add an onHover prop","Use the hover() function"]'::jsonb, 0, 'State variants like hover: prefix the utility (hover:bg-blue-600).'),
  ('Tailwind', 'Frontend & Mobile', 'mid', 'What does the JIT engine do?', '["Generates only the CSS for classes actually used","Minifies JavaScript","Compiles to WebAssembly","Bundles images"]'::jsonb, 0, 'Just-in-Time generation produces styles on demand, keeping CSS small.'),
  ('Tailwind', 'Frontend & Mobile', 'mid', 'Where do you customize the design tokens?', '["tailwind.config theme","Inline styles","A .env file","package.json"]'::jsonb, 0, 'The theme key in the config defines colors, spacing, fonts, etc.'),
  ('Tailwind', 'Frontend & Mobile', 'mid', 'What does @apply do?', '["Inlines utility classes into a custom CSS rule","Imports a plugin","Purges unused CSS","Defines a breakpoint"]'::jsonb, 0, '@apply lets you compose utilities inside your own CSS class.'),
  ('Tailwind', 'Frontend & Mobile', 'high', 'How does content scanning keep the bundle small?', '["Only classes found in scanned files are generated","It compresses the output","It tree-shakes JavaScript","It lazy-loads CSS"]'::jsonb, 0, 'Tailwind scans your content paths and emits CSS only for detected classes.'),
  ('Tailwind', 'Frontend & Mobile', 'high', 'What are arbitrary values?', '["One-off values in brackets like w-[37px]","Random colors","Auto-generated spacing","Deprecated utilities"]'::jsonb, 0, 'Bracket syntax lets you use a specific value without extending the theme.'),
  ('Tailwind', 'Frontend & Mobile', 'high', 'How is dark mode applied?', '["The dark: variant, toggled by class or media strategy","A separate dark.css","Automatically for all sites","Only via JavaScript"]'::jsonb, 0, 'darkMode config (''class'' or ''media'') controls when dark: utilities apply.'),
  ('Tailwind', 'Frontend & Mobile', 'high', 'What does space-x-* do?', '["Adds horizontal margin between child elements","Sets letter spacing","Adds padding","Adds a grid gap only"]'::jsonb, 0, 'space-x-* applies margins between flex/inline children.'),
  ('Tailwind', 'Frontend & Mobile', 'high', 'How does extend differ from replacing a theme key?', '["extend merges with defaults; a top-level key overrides them","extend overrides; top-level merges","Both merge","Both override"]'::jsonb, 0, 'Put additions under theme.extend to keep defaults; define at theme.<key> to replace.'),
  ('Tailwind', 'Frontend & Mobile', 'ultra', 'When two utilities set the same property, which wins?', '["The one later in the generated stylesheet (source order), not class order in markup","The first listed class in the element","The shorter class name","It is undefined"]'::jsonb, 0, 'CSS specificity is equal, so generated source order decides — reordering classes in HTML doesn''t change it.'),
  ('Tailwind', 'Frontend & Mobile', 'ultra', 'What does the @layer directive control?', '["Which layer (base/components/utilities) a rule belongs to for ordering","The z-index of elements","Dark mode layering","Animation order"]'::jsonb, 0, '@layer organizes custom CSS into Tailwind''s layers so ordering/overrides behave predictably.'),
  ('Tailwind', 'Frontend & Mobile', 'ultra', 'Why is CSS size claimed to plateau with utility-first?', '["Utilities are reused, so adding features rarely adds new CSS","CSS is gzipped harder","It inlines styles","It removes all comments"]'::jsonb, 0, 'Because the same utilities recur, the generated stylesheet stops growing as the app grows.'),
  ('Tailwind', 'Frontend & Mobile', 'ultra', 'What do Tailwind plugins enable?', '["Adding custom utilities, components, and variants programmatically","Faster builds only","Server rendering","Type checking"]'::jsonb, 0, 'The plugin API registers new classes and variants via JS.'),
  ('Tailwind', 'Frontend & Mobile', 'ultra', 'How do container queries work in Tailwind (v3.2+)?', '["@container with @sm:/@md: variants based on the parent''s size","They use viewport width only","They require a plugin in every project","They are not supported"]'::jsonb, 0, 'Marking an element a container lets children respond to the container''s width, not the viewport.'),
  ('Material UI', 'Frontend & Mobile', 'easy', 'What is MUI?', '["A React component library implementing Material Design","A CSS reset","A state manager","A bundler"]'::jsonb, 0, 'MUI provides ready-made React components following Material Design.'),
