  ('Material UI', 'Frontend & Mobile', 'mid', 'What does the sx prop do?', '["Applies inline style overrides with access to the theme","Sets the component variant","Adds a CSS class name","Configures routing"]'::jsonb, 0, 'sx is a shortcut for theme-aware styles, breakpoints, and pseudo-selectors.'),
  ('Material UI', 'Frontend & Mobile', 'mid', 'What is MUI''s default spacing unit?', '["8px (theme.spacing)","16px","1rem","4px"]'::jsonb, 0, 'theme.spacing(1) is 8px by default; spacing props multiply it.'),
  ('Material UI', 'Frontend & Mobile', 'mid', 'What does CssBaseline provide?', '["A consistent baseline/reset of browser styles","A dark theme","A grid system","Icon fonts"]'::jsonb, 0, 'CssBaseline normalizes default styles across browsers.'),
