  ('Material UI', 'Frontend & Mobile', 'high', 'Which styling engine does MUI v5 use?', '["Emotion","styled-components only","JSS","Sass"]'::jsonb, 0, 'MUI v5 uses Emotion by default for styled() and sx (styled-components is an option).'),
  ('Material UI', 'Frontend & Mobile', 'high', 'How do you globally override a component''s styles/defaults?', '["theme.components overrides and defaultProps","Editing node_modules","Inline style on each instance","A global .css import only"]'::jsonb, 0, 'theme.components lets you set styleOverrides and defaultProps per component.'),
  ('Material UI', 'Frontend & Mobile', 'high', 'What does the styled() utility create?', '["A theme-aware styled component","A reducer","A context provider","A route"]'::jsonb, 0, 'styled() wraps a component with styles that can read the theme.'),
  ('Material UI', 'Frontend & Mobile', 'high', 'Why might sx be preferred over the inline style attribute?', '["sx supports theme tokens, breakpoints, and pseudo-selectors","sx is faster than everything","style can''t set colors","sx avoids re-renders"]'::jsonb, 0, 'Plain style is static; sx integrates with the theme and responsive/pseudo features.'),
  ('Material UI', 'Frontend & Mobile', 'high', 'What is the benefit of palette tokens?', '["Consistent theming and easy light/dark switching","Smaller bundles","Faster routing","Automatic accessibility"]'::jsonb, 0, 'Centralized palette values keep colors consistent and themeable.'),
  ('Material UI', 'Frontend & Mobile', 'ultra', 'How does MUI avoid a flash of unstyled content during SSR?', '["Extract critical CSS / use an Emotion cache during server render","It disables CSS-in-JS","It inlines all CSS at build","It can''t be used with SSR"]'::jsonb, 0, 'Server rendering collects Emotion styles and injects them so the first paint is styled.'),
  ('Material UI', 'Frontend & Mobile', 'ultra', 'What is a tradeoff of runtime CSS-in-JS like Emotion?', '["Per-render style serialization cost versus zero-runtime solutions","It can''t theme","It breaks SSR entirely","It requires Sass"]'::jsonb, 0, 'Runtime style generation adds JS work compared to zero-runtime/atomic CSS approaches.'),
  ('Material UI', 'Frontend & Mobile', 'ultra', 'How does the theme reach styled components?', '["Via React context consumed by Emotion''s ThemeProvider","Through global variables","By prop drilling only","Through CSS variables only"]'::jsonb, 0, 'ThemeProvider puts the theme in context; styled/sx read it from there.'),
  ('Material UI', 'Frontend & Mobile', 'ultra', 'What does MUI Base (unstyled) offer?', '["Accessible behavior/logic without styles for full design control","Prebuilt dark themes","A CSS framework","Server components"]'::jsonb, 0, 'Base UI provides headless components so you bring your own styling.'),
  ('Material UI', 'Frontend & Mobile', 'ultra', 'Why can sx be slower than styled() in hot paths?', '["sx is parsed on each render; styled() is defined once","sx can''t be memoized ever","styled() runs on the server only","sx disables caching"]'::jsonb, 0, 'Frequently re-rendered components may benefit from styled() to avoid repeated sx parsing.'),
  ('Vite', 'Frontend & Mobile', 'easy', 'What is Vite?', '["A fast dev server and build tool","A CSS framework","A test runner","A state library"]'::jsonb, 0, 'Vite provides an instant dev server and an optimized production build.'),
  ('Vite', 'Frontend & Mobile', 'easy', 'What does Vite serve in development for fast startup?', '["Native ES modules (no upfront bundling)","A fully bundled file","Server-rendered HTML","WebAssembly"]'::jsonb, 0, 'Vite serves source over native ESM and transforms on demand.'),
  ('Vite', 'Frontend & Mobile', 'easy', 'Which bundler does Vite use for production builds?', '["Rollup","webpack","Parcel","esbuild only"]'::jsonb, 0, 'Production builds are bundled with Rollup.'),
