  ('Vite', 'Frontend & Mobile', 'easy', 'Which file configures Vite?', '["vite.config.js/ts","vite.json","package.json only",".viterc"]'::jsonb, 0, 'Configuration lives in vite.config.js or vite.config.ts.'),
  ('Vite', 'Frontend & Mobile', 'mid', 'Why is Vite dev startup so fast?', '["It serves unbundled ESM and transforms files only when requested","It precompiles everything","It skips TypeScript","It uses no JavaScript"]'::jsonb, 0, 'No upfront bundle is built; the browser requests modules and Vite transforms on demand.'),
  ('Vite', 'Frontend & Mobile', 'mid', 'What pre-bundles dependencies?', '["esbuild","Rollup","Babel","SWC only"]'::jsonb, 0, 'esbuild pre-bundles deps quickly (CJS→ESM, fewer requests).'),
  ('Vite', 'Frontend & Mobile', 'mid', 'How are env vars exposed to client code?', '["Via import.meta.env with a VITE_ prefix","Through process.env automatically","Through window.ENV","They aren''t exposed"]'::jsonb, 0, 'Only variables prefixed VITE_ are exposed on import.meta.env.'),
  ('Vite', 'Frontend & Mobile', 'mid', 'What is the role of the public/ folder?', '["Files served as-is at the root, not processed by the build","Compiled output","Source modules","Test fixtures"]'::jsonb, 0, 'Assets in public/ are copied verbatim and referenced from the root path.'),
  ('Vite', 'Frontend & Mobile', 'mid', 'What does import.meta.glob do?', '["Imports many files matching a glob pattern","Fetches remote data","Defines env vars","Lazy-loads CSS only"]'::jsonb, 0, 'import.meta.glob bulk-imports files, optionally lazily, resolved at build time.'),
  ('Vite', 'Frontend & Mobile', 'high', 'Why does Vite use esbuild for deps but Rollup for the final build?', '["esbuild is fast for transforms/pre-bundling; Rollup gives better prod optimization and plugins","Rollup is faster than esbuild","esbuild can''t read ESM","Rollup runs only in dev"]'::jsonb, 0, 'Each tool plays to its strength: speed in dev, optimization/ecosystem for production.'),
  ('Vite', 'Frontend & Mobile', 'high', 'What does dependency pre-bundling solve?', '["Converting CJS to ESM and collapsing many module requests","Minifying the app","Tree-shaking the app code","Generating types"]'::jsonb, 0, 'Pre-bundling normalizes deps to ESM and reduces request waterfalls in dev.'),
  ('Vite', 'Frontend & Mobile', 'high', 'How does Vite handle CSS in async chunks?', '["It code-splits CSS per async chunk","It inlines all CSS in JS","It ignores CSS","It uses one global file always"]'::jsonb, 0, 'Vite extracts CSS for each dynamically imported chunk.'),
  ('Vite', 'Frontend & Mobile', 'high', 'What does a dynamic import() enable?', '["Lazy-loaded code-split chunks","Synchronous loading","Server rendering","CSS scoping"]'::jsonb, 0, 'Dynamic imports create separate chunks loaded on demand.'),
  ('Vite', 'Frontend & Mobile', 'high', 'What is the Vite plugin API based on?', '["Rollup''s plugin interface plus Vite-specific dev hooks","webpack loaders","Babel plugins only","PostCSS only"]'::jsonb, 0, 'Vite plugins are Rollup-compatible with extra hooks for the dev server.'),
  ('Vite', 'Frontend & Mobile', 'ultra', 'Why bundle for production but not for dev?', '["Unbundled ESM is fast in dev; prod needs bundling to avoid request waterfalls and enable optimizations","Bundling is impossible in dev","Dev has no modules","Prod browsers lack ESM"]'::jsonb, 0, 'Shipping hundreds of unbundled modules to users would be slow; bundling optimizes delivery.'),
