  ('Vite', 'Frontend & Mobile', 'ultra', 'What is a downside of too many tiny chunks in production?', '["Request overhead and worse compression ratios","Larger total source","No tree shaking","Broken HMR"]'::jsonb, 0, 'Excessive splitting adds HTTP overhead and reduces gzip/brotli efficiency.'),
  ('Vite', 'Frontend & Mobile', 'ultra', 'How is import.meta.glob resolved?', '["Statically analyzed and transformed into explicit imports at build","Evaluated at runtime via fetch","Ignored in production","Resolved by the server"]'::jsonb, 0, 'Vite rewrites the glob into concrete import statements during the build.'),
