  ('Rspack', 'Frontend & Mobile', 'easy', 'What does HMR do in Rspack?', '["Hot-updates changed modules without a full reload","Compiles to native code","Runs tests","Lints files"]'::jsonb, 0, 'Like webpack, Rspack supports hot module replacement in dev.'),
  ('Rspack', 'Frontend & Mobile', 'mid', 'Which higher-level framework wraps Rspack?', '["Rsbuild","Rsbundle","Rollup","Rsnext"]'::jsonb, 0, 'Rsbuild provides an opinionated build setup on top of Rspack.'),
