  ('Rspack', 'Frontend & Mobile', 'mid', 'Why would a team migrate from webpack to Rspack?', '["Faster build and CI times on large apps","Smaller node_modules","Better CSS support","To drop TypeScript"]'::jsonb, 0, 'The main motivation is build performance at scale.'),
  ('Rspack', 'Frontend & Mobile', 'mid', 'What feature supports micro-frontends?', '["Module Federation","CSS Modules","Tree shaking","Source maps"]'::jsonb, 0, 'Rspack supports Module Federation for sharing code across apps.'),
  ('Rspack', 'Frontend & Mobile', 'high', 'Why can a Rust bundler parallelize better than a JS one?', '["Native threads without a single-threaded event-loop limit","Rust has no garbage collector at all","JS can''t read files","Rust compiles to CSS"]'::jsonb, 0, 'Rust can use real multithreading for parsing/transforming, unlike single-threaded Node.'),
  ('Rspack', 'Frontend & Mobile', 'high', 'What compatibility caveat exists with Rspack?', '["Not 100% of webpack plugins are supported","It can''t bundle CSS","It has no loaders","It only builds for Node"]'::jsonb, 0, 'Some webpack plugins rely on internal APIs not fully reimplemented.'),
  ('Rspack', 'Frontend & Mobile', 'high', 'What does persistent caching buy you?', '["Near-instant rebuilds by reusing prior work","Smaller output files","Automatic tests","Type checking"]'::jsonb, 0, 'Caching avoids recompiling unchanged modules between builds.'),
  ('Rspack', 'Frontend & Mobile', 'high', 'What does Module Federation enable?', '["Runtime sharing of modules across independently built apps","Compile-time inlining","CSS scoping","Type generation"]'::jsonb, 0, 'Federation lets separately deployed bundles share code at runtime (micro-frontends).'),
  ('Rspack', 'Frontend & Mobile', 'high', 'What limits perfect webpack parity?', '["Plugins depending on webpack''s JS-internal APIs","Different config file names","Lack of loaders","No HMR"]'::jsonb, 0, 'Deep plugin integrations with webpack internals are hardest to match.'),
  ('Rspack', 'Frontend & Mobile', 'ultra', 'Why does a Rust bundler cut cold-build time dramatically on huge graphs?', '["Parallel, compiled parsing/transform versus interpreted single-threaded JS","It skips bundling","It caches the network","It avoids reading source"]'::jsonb, 0, 'Compiled, multithreaded processing scales far better across thousands of modules.'),
  ('Rspack', 'Frontend & Mobile', 'ultra', 'What is the main risk of adopting a newer bundler like Rspack?', '["Plugin/loader gaps and ecosystem maturity","It can''t run in CI","No source maps","No TypeScript support"]'::jsonb, 0, 'Edge-case plugins or features may not yet be supported.'),
  ('Rspack', 'Frontend & Mobile', 'ultra', 'How does Module Federation handle shared dependency versions?', '["It negotiates a compatible shared singleton at runtime","It bundles duplicates always","It refuses mismatched versions","It ignores versions"]'::jsonb, 0, 'Federation can share singletons and resolve compatible versions among hosts/remotes.'),
  ('Rspack', 'Frontend & Mobile', 'ultra', 'What does SWC/Rust-based transform replace from the JS toolchain?', '["Babel-style transpilation, but faster","The browser","The package manager","The test runner"]'::jsonb, 0, 'Rust-based transformers do TS/JSX transpilation much faster than Babel.'),
  ('Rspack', 'Frontend & Mobile', 'ultra', 'Why does build speed matter most on large monorepos?', '["Rebuild/CI time dominates developer feedback loops at scale","Small apps never build","It changes runtime performance","It reduces bundle size automatically"]'::jsonb, 0, 'On big codebases, slow builds throttle iteration speed and CI throughput.'),
  ('Webpack', 'Frontend & Mobile', 'easy', 'What is webpack?', '["A module bundler","A test framework","A CSS preprocessor","A package manager"]'::jsonb, 0, 'webpack bundles modules and assets into output files.'),
  ('Webpack', 'Frontend & Mobile', 'easy', 'What is an entry point?', '["The starting module of the dependency graph","The output file","A plugin","A dev server route"]'::jsonb, 0, 'webpack builds the graph starting from the entry.'),
  ('Webpack', 'Frontend & Mobile', 'easy', 'What transforms non-JS files into modules?', '["Loaders","Plugins","Entries","Chunks"]'::jsonb, 0, 'Loaders convert files (CSS, images, TS) so webpack can include them.'),
  ('Webpack', 'Frontend & Mobile', 'easy', 'What extends webpack''s capabilities across the build?', '["Plugins","Loaders only","Entries","Aliases"]'::jsonb, 0, 'Plugins hook into the compilation lifecycle for broader tasks.'),
  ('Webpack', 'Frontend & Mobile', 'easy', 'What is the build''s output called?', '["A bundle/chunk","A loader","An entry","A manifest only"]'::jsonb, 0, 'webpack emits bundles (split into chunks).'),
  ('Webpack', 'Frontend & Mobile', 'mid', 'What does a loader do?', '["Transforms a file type into a module webpack can process","Splits chunks","Minifies output","Starts the dev server"]'::jsonb, 0, 'e.g. babel-loader transpiles, css-loader handles CSS imports.'),
  ('Webpack', 'Frontend & Mobile', 'mid', 'What does code splitting achieve?', '["Splitting output into lazily loadable chunks","Merging all code into one file","Removing comments","Type checking"]'::jsonb, 0, 'Splitting lets parts of the app load on demand.'),
  ('Webpack', 'Frontend & Mobile', 'mid', 'What does tree shaking remove?', '["Unused exports (dead code)","Whitespace","Source maps","Node modules"]'::jsonb, 0, 'Tree shaking eliminates exports that are never imported.'),
  ('Webpack', 'Frontend & Mobile', 'mid', 'What does webpack-dev-server provide?', '["Live reloading and HMR during development","Production hosting","A database","A linter"]'::jsonb, 0, 'It serves the app in dev with hot reloading.'),
  ('Webpack', 'Frontend & Mobile', 'mid', 'What is a chunk?', '["A unit of bundled output","A loader rule","A plugin","A config file"]'::jsonb, 0, 'Chunks are the split pieces of the bundled graph.'),
  ('Webpack', 'Frontend & Mobile', 'high', 'What enables effective tree shaking?', '["Static ES module structure plus production mode","CommonJS requires","Dynamic eval","Disabling minification"]'::jsonb, 0, 'ESM''s static imports let webpack/terser prove exports are unused.'),
  ('Webpack', 'Frontend & Mobile', 'high', 'What does SplitChunksPlugin do?', '["Extracts common/vendor code into shared chunks","Lints code","Generates types","Runs tests"]'::jsonb, 0, 'It deduplicates shared modules into separate cacheable chunks.'),
  ('Webpack', 'Frontend & Mobile', 'high', 'What do source maps enable?', '["Mapping bundled code back to original source for debugging","Faster builds","Smaller bundles","CSS scoping"]'::jsonb, 0, 'Source maps let dev tools show original files despite bundling/minification.'),
  ('Webpack', 'Frontend & Mobile', 'high', 'What does mode: ''production'' turn on?', '["Minification and built-in optimizations","The dev server","Watch mode","Verbose logging"]'::jsonb, 0, 'Production mode enables terser minification, scope hoisting, and more.'),
  ('Webpack', 'Frontend & Mobile', 'high', 'What is contenthash used for in output filenames?', '["Long-term caching by busting only changed chunks","Encryption","Compression","Source mapping"]'::jsonb, 0, 'Filenames change only when content changes, so unchanged chunks stay cached.'),
  ('Webpack', 'Frontend & Mobile', 'ultra', 'Why is webpack slower than Rust bundlers on large graphs?', '["Single-threaded JS parsing and transformation","It bundles twice","It lacks caching entirely","It reads files over the network"]'::jsonb, 0, 'Node''s single thread limits parsing/transform throughput versus native multithreaded tools.'),
  ('Webpack', 'Frontend & Mobile', 'ultra', 'How does filesystem (persistent) caching help?', '["It reuses module compilation between builds for faster rebuilds","It compresses output","It removes dead code","It splits chunks"]'::jsonb, 0, 'cache.type ''filesystem'' persists compiled modules across runs.'),
  ('Webpack', 'Frontend & Mobile', 'ultra', 'What is a tradeoff of very aggressive code splitting?', '["More requests versus better caching and lazy loading","It disables HMR","It prevents tree shaking","It breaks source maps"]'::jsonb, 0, 'Too many chunks add request overhead; too few hurt caching/lazy loading.'),
  ('Webpack', 'Frontend & Mobile', 'ultra', 'How does Module Federation share dependencies?', '["It negotiates a compatible shared singleton at runtime","It always duplicates them","It forbids sharing","It inlines them at build"]'::jsonb, 0, 'Federated apps can share singletons (e.g. one React) resolved at runtime.'),
  ('Webpack', 'Frontend & Mobile', 'ultra', 'What does scope hoisting (module concatenation) improve?', '["Smaller, faster output by concatenating modules into fewer closures","CSS specificity","Type safety","Test coverage"]'::jsonb, 0, 'Hoisting reduces per-module wrapper overhead, improving size and runtime.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'easy', 'What is pnpm?', '["A fast, disk-efficient package manager","A bundler","A test runner","A linter"]'::jsonb, 0, 'pnpm installs dependencies quickly while saving disk space.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'easy', 'How does pnpm save disk space?', '["A content-addressable store with hard links","Compressing node_modules","Deleting dev deps","Skipping lockfiles"]'::jsonb, 0, 'Files are stored once globally and hard-linked into projects.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'easy', 'Which file locks dependency versions?', '["pnpm-lock.yaml","package-lock.json","yarn.lock","pnpm.config"]'::jsonb, 0, 'pnpm uses pnpm-lock.yaml for deterministic installs.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'easy', 'What is Corepack?', '["A Node tool that manages package manager versions","A bundler","A registry","A CI service"]'::jsonb, 0, 'Corepack ships with Node and pins/provisions pnpm/yarn versions.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'easy', 'What defines a pnpm workspace?', '["pnpm-workspace.yaml","workspace.json","lerna.json","package.json only"]'::jsonb, 0, 'pnpm-workspace.yaml lists the packages in a monorepo.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'mid', 'Why is pnpm''s node_modules layout stricter than npm''s?', '["It is symlinked/non-flat, so code can''t use undeclared deps","It flattens everything","It removes nesting","It hides peer deps"]'::jsonb, 0, 'Only declared dependencies are reachable, preventing phantom dependencies.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'mid', 'What does `pnpm --filter` do?', '["Runs commands scoped to selected packages","Filters dependencies by license","Removes packages","Lints a folder"]'::jsonb, 0, '--filter targets specific workspace packages (and optionally their deps).'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'mid', 'What does Corepack pin via the packageManager field?', '["The exact package manager and version","The Node version","The registry URL","The lockfile format"]'::jsonb, 0, 'packageManager (e.g. pnpm@9.x) tells Corepack which PM/version to use.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'mid', 'Why does pnpm install faster than copying?', '["It links files from the store instead of copying them","It skips dependencies","It uses fewer files","It caches the network only"]'::jsonb, 0, 'Hard-linking from the global store avoids duplicate copies and is near-instant.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'mid', 'What does the workspace: protocol do in a monorepo?', '["Links a dependency to the local workspace package","Downloads from npm","Pins a git commit","Disables versioning"]'::jsonb, 0, 'workspace:* resolves to the local package rather than the registry.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'high', 'What are phantom dependencies, and how does pnpm prevent them?', '["Using a package you didn''t declare; pnpm''s symlinked layout blocks access to undeclared deps","Deps with no version; pnpm pins them","Circular deps; pnpm removes them","Peer deps; pnpm hides them"]'::jsonb, 0, 'Flat node_modules let you import undeclared packages; pnpm''s structure exposes only declared ones.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'high', 'How does the content-addressable store dedupe across projects?', '["Identical files are stored once and hard-linked everywhere","It compresses each project","It deletes duplicates nightly","It uses symlinks to the registry"]'::jsonb, 0, 'Files keyed by content hash are shared across all projects on the machine.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'high', 'How does pnpm handle peer dependencies?', '["It resolves peers per dependency context (strict by default)","It ignores them","It installs the latest always","It deduplicates them into one"]'::jsonb, 0, 'pnpm models peers strictly, warning or erroring on unmet/conflicting peers.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'high', 'What does `pnpm dlx` do?', '["Runs a package binary without installing it permanently","Deletes a package","Lists licenses","Links a workspace"]'::jsonb, 0, 'dlx fetches and runs a CLI package on the fly (like npx).'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'high', 'Why does pnpm avoid hoisting by default?', '["To prevent phantom dependencies from flattened modules","To save memory","To speed up the CLI","To support CommonJS only"]'::jsonb, 0, 'Hoisting flattens deps and reintroduces phantom-dependency risks pnpm aims to avoid.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'ultra', 'How do hard links affect install speed and disk usage?', '["They are near-instant and share storage across projects","They double disk usage","They slow installs","They require copying first"]'::jsonb, 0, 'Hard-linking points multiple paths at the same on-disk blocks — fast and space-saving.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'ultra', 'What team problem does Corepack solve?', '["Everyone uses the exact same package manager version","It speeds up the bundler","It replaces the lockfile","It hosts the registry"]'::jsonb, 0, 'Pinning the PM version removes ''works on my machine'' install drift.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'ultra', 'What does `pnpm store prune` do?', '["Removes unreferenced files from the global store","Deletes node_modules","Clears the lockfile","Uninstalls pnpm"]'::jsonb, 0, 'Pruning reclaims space by dropping store content no project links to.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'ultra', 'Why does pnpm''s strictness improve correctness in monorepos?', '["It surfaces missing/undeclared dependencies early","It auto-adds deps","It merges all packages","It disables peer deps"]'::jsonb, 0, 'By only exposing declared deps, latent missing-dependency bugs fail fast.'),
  ('pnpm / Corepack', 'Frontend & Mobile', 'ultra', 'How does Corepack provision a package manager on first use?', '["It downloads and caches the pinned version on demand","It bundles every PM with Node","It compiles from source","It requires a global install"]'::jsonb, 0, 'Corepack fetches the specified PM version when a command runs, then caches it.'),
  ('TypeScript', 'Languages', 'easy', 'Which keyword declares a value that can''t be reassigned?', '["const","let","var","static"]'::jsonb, 0, 'const creates a binding that can''t be reassigned. (The object it points to can still be mutated.)'),
  ('TypeScript', 'Languages', 'easy', 'How do you annotate a variable as a number?', '["let count: number","let count = number","let count<number>","number count"]'::jsonb, 0, 'Type annotations follow the identifier after a colon: `let count: number`.'),
  ('TypeScript', 'Languages', 'easy', 'What symbol marks an interface property as optional?', '["?","!","*","~"]'::jsonb, 0, 'A trailing `?` (e.g. `name?: string`) makes the property optional.'),
  ('TypeScript', 'Languages', 'easy', 'Which type represents true/false values?', '["boolean","bit","bool","binary"]'::jsonb, 0, 'TypeScript''s primitive for true/false is `boolean` (lowercase).'),
  ('TypeScript', 'Languages', 'easy', 'What does the `any` type do?', '["Opts a value out of type checking entirely","Restricts a value to primitives","Forces a runtime type check","Makes a value read-only"]'::jsonb, 0, '`any` disables type checking for that value — convenient but it forfeits safety.'),
  ('TypeScript', 'Languages', 'mid', 'What does `keyof T` evaluate to?', '["A union of T''s property names","An array of T''s values","The number of properties in T","A copy of T with optional keys"]'::jsonb, 0, '`keyof T` produces the union of T''s keys as string/number literal types.'),
  ('TypeScript', 'Languages', 'mid', 'What is the key difference between `unknown` and `any`?', '["unknown requires a type check before use; any bypasses checking entirely","any is only for primitives; unknown also works with objects","unknown throws at runtime when misused; any fails silently","any is deprecated; unknown replaces it"]'::jsonb, 0, '`unknown` is the type-safe counterpart of `any`: you must narrow it before using it.'),
  ('TypeScript', 'Languages', 'mid', 'What does the `readonly` modifier do on a property?', '["Prevents reassignment of the property after initialization","Makes the property optional","Hides the property from JSON output","Freezes the entire object at runtime"]'::jsonb, 0, '`readonly` is a compile-time check that blocks reassignment; it has no runtime effect.'),
  ('TypeScript', 'Languages', 'mid', 'Which capability is unique to `interface` (not `type`)?', '["Declaration merging across multiple declarations","Aliasing a union type","Aliasing a primitive like string","Using mapped types"]'::jsonb, 0, 'Interfaces with the same name merge their members; type aliases cannot be reopened.'),
  ('TypeScript', 'Languages', 'mid', 'What does `as const` do to an object literal?', '["Infers the narrowest literal types and makes it deeply readonly","Converts it to a runtime constant","Removes optional properties","Casts it to any"]'::jsonb, 0, '`as const` narrows values to literals and marks every property readonly.'),
  ('TypeScript', 'Languages', 'high', 'What is `infer` used for in a conditional type?', '["Capturing a type from within the type being matched","Forcing a value to a specific type","Declaring a generic default","Widening a literal to its base type"]'::jsonb, 0, '`infer R` introduces a type variable inside a conditional type, e.g. `T extends Array<infer R> ? R : never`.'),
  ('TypeScript', 'Languages', 'high', 'What does the `satisfies` operator do?', '["Checks a value matches a type without widening its inferred type","Asserts a value is a type at runtime","Casts a value, bypassing checks","Makes a type''s properties optional"]'::jsonb, 0, '`satisfies` validates against a type while preserving the more specific inferred type of the value.'),
  ('TypeScript', 'Languages', 'high', 'What does a mapped type `{ [K in keyof T]: ... }` do?', '["Builds a new type by transforming each property of T","Iterates T''s values at runtime","Returns the keys of T as an array","Removes all properties from T"]'::jsonb, 0, 'Mapped types project over each key of T to construct a new type (the basis of Partial, Readonly, etc.).'),
  ('TypeScript', 'Languages', 'high', 'In `T extends U ? X : Y`, what is being tested?', '["Whether T is assignable to U","Whether T and U are identical","Whether T inherits a class U","Whether U is a subtype of T"]'::jsonb, 0, 'Conditional types branch on assignability — is T assignable to U.'),
  ('TypeScript', 'Languages', 'high', 'Why narrow `unknown` input rather than typing it `any`?', '["unknown keeps type safety by forcing a check before use","unknown is faster at runtime","any cannot be assigned to objects","unknown auto-casts to the right type"]'::jsonb, 0, '`unknown` preserves safety: the compiler blocks use until you narrow, while `any` silently allows anything.'),
  ('TypeScript', 'Languages', 'ultra', 'How do distributive conditional types behave over a union?', '["The condition is applied to each member of the union separately","The union is treated as a single opaque type","Only the first member is tested","Distribution requires an explicit decorator"]'::jsonb, 0, 'A naked type parameter in a conditional distributes over unions; wrapping in a tuple `[T] extends [U]` disables it.'),
  ('TypeScript', 'Languages', 'ultra', 'What does a `const` type parameter `<const T>` (TS 5.0) do?', '["Infers the narrowest literal type for the argument","Makes the function pure","Freezes the argument at runtime","Requires the argument to be a constant"]'::jsonb, 0, 'A `const` type parameter infers literal types as if the caller wrote `as const`.'),
  ('TypeScript', 'Languages', 'ultra', 'Which constructs support declaration merging?', '["Interfaces, namespaces, and enums","Type aliases only","Classes and type aliases","Every type construct"]'::jsonb, 0, 'Interfaces, namespaces, and enums can merge; type aliases cannot be redeclared.'),
  ('TypeScript', 'Languages', 'ultra', 'What is a variadic tuple type?', '["A tuple that includes a spread of another array/tuple type","A tuple whose length is fixed at four","A union of tuple types","A tuple that can hold only one type"]'::jsonb, 0, 'Variadic tuples use `...T` to compose tuples of arbitrary length, e.g. `[string, ...number[]]`.'),
  ('TypeScript', 'Languages', 'ultra', 'What commonly triggers "Type instantiation is excessively deep and possibly infinite"?', '["A recursive conditional/mapped type exceeding the depth limit","Too many properties on an interface","Using any in a generic","Importing a circular module"]'::jsonb, 0, 'Deeply recursive type-level computation hits TypeScript''s instantiation depth guard.'),
  ('JavaScript', 'Languages', 'easy', 'Which keyword declares a block-scoped variable?', '["let","var","def","scope"]'::jsonb, 0, '`let` (and `const`) are block-scoped; `var` is function-scoped.'),
  ('JavaScript', 'Languages', 'easy', 'What does `typeof "hello"` return?', '["\"string\"","\"text\"","\"String\"","\"char\""]'::jsonb, 0, '`typeof` returns the lowercase string `"string"` for string values.'),
  ('JavaScript', 'Languages', 'easy', 'Which operator checks both value and type without coercion?', '["===","==","=","=>"]'::jsonb, 0, '`===` is strict equality; `==` performs type coercion before comparing.'),
  ('JavaScript', 'Languages', 'easy', 'What does `Array.prototype.push` do?', '["Adds one or more elements to the end of the array","Removes the last element","Adds an element to the front","Returns a sorted copy"]'::jsonb, 0, '`push` appends to the end and returns the new length; `unshift` adds to the front.'),
  ('JavaScript', 'Languages', 'easy', 'How do you write a single-line comment?', '["// comment","# comment","<!-- comment -->","-- comment"]'::jsonb, 0, '`//` starts a single-line comment; `/* */` wraps a block comment.'),
  ('JavaScript', 'Languages', 'mid', 'In the event loop, which runs first after the current task?', '["Microtasks (Promise callbacks)","Macrotasks (setTimeout)","Whichever was scheduled first","Render/paint callbacks"]'::jsonb, 0, 'The microtask queue (Promises, queueMicrotask) fully drains before the next macrotask runs.'),
  ('JavaScript', 'Languages', 'mid', 'What does a closure capture?', '["Variables from its enclosing lexical scope","A deep copy of all globals","Only the arguments passed to it","The value of this at call time"]'::jsonb, 0, 'A closure retains references to variables in the scope where it was defined.'),
  ('JavaScript', 'Languages', 'mid', 'What does `Array.prototype.map` return?', '["A new array of the same length with transformed elements","The original array, mutated","A single accumulated value","The first matching element"]'::jsonb, 0, '`map` returns a new array; it does not mutate the source. `reduce` accumulates a single value.'),
  ('JavaScript', 'Languages', 'mid', 'What determines `this` inside an arrow function?', '["The this of the enclosing lexical scope","The object the function is called on","Always the global object","The first argument passed"]'::jsonb, 0, 'Arrow functions don''t bind their own `this`; they inherit it from where they were defined.'),
  ('JavaScript', 'Languages', 'mid', 'For `{ ...a, ...b }`, which value wins on a duplicate key?', '["The one from b (the later spread)","The one from a (the earlier spread)","It throws a duplicate-key error","Both are kept as an array"]'::jsonb, 0, 'Later spreads overwrite earlier ones, so b''s value wins for shared keys.'),
  ('JavaScript', 'Languages', 'high', 'How does `Promise.all` behave when one input rejects?', '["It rejects immediately with that error","It waits for all, then rejects","It resolves with the successful results","It retries the rejected promise"]'::jsonb, 0, '`Promise.all` short-circuits: the first rejection rejects the whole thing. Use `allSettled` to wait for every outcome.'),
  ('JavaScript', 'Languages', 'high', 'What does `Object.freeze` guarantee?', '["Top-level properties can''t be added, removed, or changed","The whole object tree becomes immutable","The object can''t be read","The object is deep-cloned"]'::jsonb, 0, '`Object.freeze` is shallow — nested objects remain mutable unless frozen too.'),
  ('JavaScript', 'Languages', 'high', 'What is a generator function (`function*`) for?', '["Producing an iterator that can pause and resume with yield","Running code on a background thread","Generating random values","Auto-creating class instances"]'::jsonb, 0, 'Generators yield values lazily and suspend execution between `yield`s.'),
  ('JavaScript', 'Languages', 'high', 'Difference between `Promise.all` and `Promise.allSettled`?', '["allSettled never rejects and reports each promise''s status","all is the async version of allSettled","allSettled resolves only when all succeed","all preserves order while allSettled doesn''t"]'::jsonb, 0, '`allSettled` always resolves with an array of {status, value/reason}, regardless of rejections.'),
  ('JavaScript', 'Languages', 'high', 'What does `Array.prototype.reduce` do?', '["Folds the array into a single accumulated value","Filters out falsy elements","Returns a reversed copy","Splits the array in half"]'::jsonb, 0, '`reduce` applies a reducer across elements, carrying an accumulator to a final value.'),
  ('JavaScript', 'Languages', 'ultra', 'What is the temporal dead zone (TDZ)?', '["The span where a let/const binding exists but can''t be accessed yet","A region of unreachable code","The delay before a setTimeout fires","A garbage-collection pause"]'::jsonb, 0, 'From scope entry until the let/const declaration runs, accessing the binding throws a ReferenceError.'),
  ('JavaScript', 'Languages', 'ultra', 'What does implementing `Symbol.iterator` enable?', '["The object becomes usable with for...of and spread","The object is automatically frozen","The object gains private fields","The object is serialized to JSON"]'::jsonb, 0, 'An object with a `[Symbol.iterator]()` method is iterable, so for...of and `...` work on it.'),
  ('JavaScript', 'Languages', 'ultra', 'How do WeakMap keys differ from Map keys regarding memory?', '["WeakMap holds keys weakly, so they can be garbage-collected","WeakMap keys are copied by value","WeakMap keys must be strings","WeakMap keeps keys alive forever"]'::jsonb, 0, 'A WeakMap doesn''t prevent its object keys from being collected, avoiding leaks; it isn''t iterable for that reason.'),
  ('JavaScript', 'Languages', 'ultra', 'What''s the difference between `for...in` and `for...of`?', '["for...in iterates enumerable keys; for...of iterates iterable values","They are identical","for...of works only on arrays of numbers","for...in is the async version"]'::jsonb, 0, '`for...in` walks enumerable property keys (including inherited ones); `for...of` walks values of an iterable.'),
  ('JavaScript', 'Languages', 'ultra', 'When you call a bound function (from `bind`) with `new`, what happens to `this`?', '["The bound this is ignored; this is the newly created instance","It throws a TypeError","this is the bound value","this becomes undefined"]'::jsonb, 0, '`new` overrides a bound `this` (the new instance wins), though bound leading arguments are still applied.'),
  ('Python', 'Languages', 'easy', 'Which keyword defines a function?', '["def","func","function","fn"]'::jsonb, 0, '`def name(args):` defines a function in Python.'),
  ('Python', 'Languages', 'easy', 'How do you start a single-line comment?', '["#","//","--","/*"]'::jsonb, 0, 'Python comments begin with `#`.'),
  ('Python', 'Languages', 'easy', 'Which built-in returns the number of items in a list?', '["len(x)","x.length","count(x)","size(x)"]'::jsonb, 0, '`len()` returns the length of a sequence or collection.'),
  ('Python', 'Languages', 'easy', 'What does the literal `{}` create?', '["An empty dict","An empty set","An empty list","An empty tuple"]'::jsonb, 0, '`{}` is an empty dict; an empty set needs `set()`.'),
  ('Python', 'Languages', 'easy', 'Which keyword iterates over a sequence?', '["for","loop","foreach","iterate"]'::jsonb, 0, '`for item in sequence:` iterates over an iterable.'),
  ('Python', 'Languages', 'mid', 'What does a list comprehension `[x for x in xs]` produce?', '["A new list","A generator","A tuple","The original list mutated"]'::jsonb, 0, 'A list comprehension builds a new list; use parentheses for a generator expression.'),
  ('Python', 'Languages', 'mid', 'How does a tuple differ from a list?', '["A tuple is immutable","A tuple can only hold numbers","A tuple is always sorted","A tuple cannot be nested"]'::jsonb, 0, 'Tuples are immutable; lists are mutable.'),
  ('Python', 'Languages', 'mid', 'What does `*args` collect in a function signature?', '["Extra positional arguments into a tuple","Keyword arguments into a dict","A single list argument","Nothing — it is a syntax error"]'::jsonb, 0, '`*args` gathers extra positional arguments; `**kwargs` gathers keyword arguments.'),
  ('Python', 'Languages', 'mid', 'What does the `with` statement provide?', '["Context management with automatic cleanup","A faster loop","A type annotation","Exception suppression"]'::jsonb, 0, '`with` uses a context manager to set up and tear down resources (e.g. closing files) reliably.'),
  ('Python', 'Languages', 'mid', 'How does `is` differ from `==`?', '["`is` compares identity; `==` compares value","They are identical","`is` compares value; `==` compares identity","`is` only works on numbers"]'::jsonb, 0, '`is` checks whether two names point to the same object; `==` checks equality of value.'),
  ('Python', 'Languages', 'high', 'What does the GIL (Global Interpreter Lock) enforce in CPython?', '["Only one thread executes Python bytecode at a time","All threads run truly in parallel","Memory is garbage-collected eagerly","Functions are compiled to machine code"]'::jsonb, 0, 'The GIL serializes bytecode execution, so CPU-bound threads don''t run in parallel; use multiprocessing for that.'),
  ('Python', 'Languages', 'high', 'What is a generator function?', '["A function using yield that produces values lazily","A function that auto-generates random data","A class factory","A function that runs on another thread"]'::jsonb, 0, 'Generators use `yield` to produce values one at a time, suspending state between calls.'),
  ('Python', 'Languages', 'high', 'What does a decorator do?', '["Wraps a function and returns a new callable","Adds type hints automatically","Documents a function","Caches all return values by default"]'::jsonb, 0, 'A decorator takes a function and returns a (usually wrapped) function, applied with `@name`.'),
  ('Python', 'Languages', 'high', 'How does `@classmethod` differ from `@staticmethod`?', '["classmethod receives the class as cls; staticmethod receives no implicit arg","staticmethod receives self; classmethod does not","They are interchangeable","classmethod cannot be called on the class"]'::jsonb, 0, '`classmethod` gets `cls`; `staticmethod` gets neither `self` nor `cls`.'),
  ('Python', 'Languages', 'high', 'What does defining `__slots__` on a class do?', '["Restricts instance attributes and avoids a per-instance __dict__","Makes the class abstract","Enables multiple inheritance","Auto-generates __init__"]'::jsonb, 0, '`__slots__` fixes the allowed attributes and saves memory by skipping the instance dict.'),
  ('Python', 'Languages', 'ultra', 'When is a mutable default argument like `def f(x=[])` evaluated?', '["Once at definition time, shared across all calls","Fresh on every call","Never — it is a syntax error","Only on the first call that omits it"]'::jsonb, 0, 'Default values are evaluated once at def time; a shared mutable default is a classic bug — use None and create inside.'),
  ('Python', 'Languages', 'ultra', 'Which algorithm computes Python''s method resolution order?', '["C3 linearization","Depth-first left-to-right only","Breadth-first search","Alphabetical by class name"]'::jsonb, 0, 'Python uses C3 linearization to produce a consistent MRO for multiple inheritance.'),
  ('Python', 'Languages', 'ultra', 'How does asyncio achieve concurrency?', '["A single-threaded event loop running coroutines cooperatively","OS threads with preemptive scheduling","Multiple processes","Hardware interrupts"]'::jsonb, 0, 'asyncio runs coroutines on one thread; they cooperatively yield control at `await` points.'),
  ('Python', 'Languages', 'ultra', 'What does a metaclass control?', '["How classes themselves are created","How instances are garbage-collected","The import order of modules","The size of integers"]'::jsonb, 0, 'A metaclass is the class of a class; it customizes class creation (the default is `type`).'),
  ('Python', 'Languages', 'ultra', 'What does `functools.lru_cache` do?', '["Memoizes results with a bounded least-recently-used cache","Logs every function call","Runs the function lazily","Limits recursion depth"]'::jsonb, 0, '`lru_cache` caches return values keyed by arguments, evicting least-recently-used entries past maxsize.'),
  ('Java', 'Languages', 'easy', 'Which keyword marks a variable that cannot be reassigned?', '["final","const","static","readonly"]'::jsonb, 0, '`final` prevents reassignment of a variable in Java.'),
  ('Java', 'Languages', 'easy', 'What is the standard entry-point method signature?', '["public static void main(String[] args)","static int main()","public void start()","void main(args)"]'::jsonb, 0, 'The JVM invokes `public static void main(String[] args)`.'),
  ('Java', 'Languages', 'easy', 'Which collection stores key-value pairs?', '["Map","List","Set","Queue"]'::jsonb, 0, '`Map` (e.g. HashMap) stores key-to-value associations.'),
  ('Java', 'Languages', 'easy', 'What does JVM stand for?', '["Java Virtual Machine","Java Variable Manager","Just-in-time Virtual Memory","Java Verified Module"]'::jsonb, 0, 'The Java Virtual Machine executes compiled bytecode.'),
  ('Java', 'Languages', 'easy', 'Which primitive is a 32-bit signed integer?', '["int","long","short","byte"]'::jsonb, 0, '`int` is 32 bits; `long` is 64, `short` is 16, `byte` is 8.'),
  ('Java', 'Languages', 'mid', 'For two object references, what does `==` compare?', '["Whether they point to the same object","Their field values","Their hash codes","Their string forms"]'::jsonb, 0, '`==` compares references for objects; use `.equals()` for value equality.'),
  ('Java', 'Languages', 'mid', 'What is autoboxing?', '["Automatic conversion between primitives and their wrapper types","Wrapping exceptions in a try block","Boxing a class into a module","Compressing class files"]'::jsonb, 0, 'Autoboxing converts e.g. `int` ↔ `Integer` automatically.'),
  ('Java', 'Languages', 'mid', 'How do checked and unchecked exceptions differ?', '["Checked must be declared or caught; unchecked (RuntimeException) need not","Unchecked must always be caught","Checked exceptions are faster","There is no difference"]'::jsonb, 0, 'Checked exceptions are enforced at compile time; unchecked extend RuntimeException and aren''t enforced.'),
  ('Java', 'Languages', 'mid', 'What does `final` on a class declaration mean?', '["The class cannot be subclassed","The class cannot be instantiated","All methods are static","The class is immutable automatically"]'::jsonb, 0, 'A `final` class cannot be extended (e.g. `String`).'),
  ('Java', 'Languages', 'mid', 'What is the main purpose of generics?', '["Compile-time type safety for collections","Faster runtime performance","Automatic memory management","Dynamic typing"]'::jsonb, 0, 'Generics let the compiler enforce element types; the type info is erased at runtime.'),
  ('Java', 'Languages', 'high', 'What is type erasure?', '["Generic type information is removed at compile time","Garbage collection of unused types","Stripping comments from bytecode","Removing unused imports"]'::jsonb, 0, 'Generics are erased to their bounds at compile time, so types like `List<String>` aren''t available at runtime.'),
  ('Java', 'Languages', 'high', 'How does ConcurrentHashMap differ from HashMap?', '["It is thread-safe with fine-grained locking","It preserves insertion order","It allows null keys","It is always faster single-threaded"]'::jsonb, 0, 'ConcurrentHashMap supports concurrent access without locking the whole map; HashMap is not thread-safe.'),
  ('Java', 'Languages', 'high', 'What does the `volatile` keyword guarantee?', '["Visibility of writes across threads, but not atomicity","Atomic compound operations","Thread-exclusive access","Persistence to disk"]'::jsonb, 0, '`volatile` ensures reads/writes go to main memory (visibility) but doesn''t make `i++` atomic.'),
  ('Java', 'Languages', 'high', 'Which is mutable and synchronized?', '["StringBuffer","String","StringBuilder","CharSequence"]'::jsonb, 0, 'String is immutable; StringBuilder is mutable but not synchronized; StringBuffer is mutable and synchronized.'),
  ('Java', 'Languages', 'high', 'What partitioning does the HotSpot garbage collector use?', '["Generational heap (young and old generations)","A single flat heap","Reference counting","Stack-only allocation"]'::jsonb, 0, 'Generational GC separates short-lived (young) from long-lived (old) objects to collect efficiently.'),
  ('Java', 'Languages', 'ultra', 'What does the happens-before relationship define?', '["Memory visibility and ordering guarantees in the Java Memory Model","Method call order within a class","Thread priority scheduling","Class loading order"]'::jsonb, 0, 'Happens-before establishes when one thread''s writes are guaranteed visible to another.'),
  ('Java', 'Languages', 'ultra', 'How do Comparable and Comparator differ?', '["Comparable defines natural ordering via compareTo; Comparator is external/custom","They are identical interfaces","Comparator must be implemented by the element class","Comparable sorts in reverse only"]'::jsonb, 0, 'A class implements Comparable for its natural order; a Comparator provides an alternate ordering externally.'),
  ('Java', 'Languages', 'ultra', 'What do `record` types (Java 16+) provide?', '["Concise immutable data carriers with generated equals/hashCode/toString","Mutable structs","Thread-safe singletons","Reflection-free serialization"]'::jsonb, 0, 'Records auto-generate the canonical constructor, accessors, equals, hashCode, and toString for immutable data.'),
  ('Java', 'Languages', 'ultra', 'How does `synchronized` achieve mutual exclusion?', '["By acquiring the object''s intrinsic monitor lock","By disabling the scheduler","By copying the object per thread","By spinning on a volatile flag"]'::jsonb, 0, 'Entering a synchronized block/method acquires the monitor of the lock object, blocking other threads.'),
  ('Java', 'Languages', 'ultra', 'What is escape analysis?', '["A JIT optimization that may stack-allocate objects that don''t escape a method","A way to handle escaped characters","A security sandbox","A thread-escape detector for deadlocks"]'::jsonb, 0, 'If the JIT proves an object doesn''t escape, it can allocate it on the stack or eliminate it, reducing GC pressure.'),
  ('PHP', 'Languages', 'easy', 'How do all PHP variables begin?', '["With a $ sign","With @","With #","With a type keyword"]'::jsonb, 0, 'PHP variables are written as `$name`.'),
  ('PHP', 'Languages', 'easy', 'Which operator concatenates two strings?', '[".","+","&","++"]'::jsonb, 0, 'PHP uses `.` for string concatenation; `+` is numeric addition.'),
  ('PHP', 'Languages', 'easy', 'Which tag opens a PHP code block?', '["<?php","<php>","{php}","<%"]'::jsonb, 0, 'PHP code starts with `<?php`.'),
  ('PHP', 'Languages', 'easy', 'Which construct outputs text?', '["echo","print_r only","console.log","write"]'::jsonb, 0, '`echo` (and `print`) output text to the response.'),
  ('PHP', 'Languages', 'easy', 'Which superglobal holds URL query parameters?', '["$_GET","$_POST","$_QUERY","$_PARAMS"]'::jsonb, 0, '`$_GET` contains query-string parameters; `$_POST` holds form body data.'),
  ('PHP', 'Languages', 'mid', 'How does `===` differ from `==`?', '["`===` also compares type, with no juggling","`===` ignores type","`===` only works on numbers","They are identical"]'::jsonb, 0, '`===` is identical comparison (value and type); `==` performs type juggling.'),
  ('PHP', 'Languages', 'mid', 'What is an associative array?', '["An array mapping arbitrary keys to values","A read-only array","An array of objects only","A multi-dimensional array"]'::jsonb, 0, 'PHP arrays are ordered maps; associative arrays use string/int keys mapping to values.'),
  ('PHP', 'Languages', 'mid', 'What does the `=>` operator do in an array literal?', '["Maps a key to a value","Defines an arrow function only","Compares two values","Returns from a function"]'::jsonb, 0, '`''key'' => ''value''` associates a key with a value in array syntax.'),
  ('PHP', 'Languages', 'mid', 'What does the `->` operator access?', '["An object''s property or method","A static member","An array element","A namespace"]'::jsonb, 0, '`$obj->prop` / `$obj->method()` accesses instance members; `::` accesses static members.'),
  ('PHP', 'Languages', 'mid', 'What does the null coalescing operator `??` return?', '["The left operand if it is set and not null, else the right","Always the right operand","True if both are null","The first falsy value"]'::jsonb, 0, '`$a ?? $b` yields `$a` when it exists and isn''t null, otherwise `$b` — without a notice for undefined keys.'),
  ('PHP', 'Languages', 'high', 'What does `declare(strict_types=1)` do?', '["Enforces strict scalar type checks in that file","Enables strict comparison globally","Disables type juggling everywhere","Turns on error reporting"]'::jsonb, 0, 'With strict types, scalar type declarations reject coercion and require exact types in that file.'),
  ('PHP', 'Languages', 'high', 'What is a trait?', '["A reusable set of methods composed horizontally into classes","An interface with constants","A private class","A namespace alias"]'::jsonb, 0, 'Traits enable code reuse across unrelated classes without inheritance.'),
  ('PHP', 'Languages', 'high', 'How do `require` and `include` differ on failure?', '["`require` raises a fatal error; `include` only warns","`include` is fatal; `require` warns","Both silently continue","Both stop the script"]'::jsonb, 0, 'A failed `require` halts execution; a failed `include` emits a warning and continues.'),
  ('PHP', 'Languages', 'high', 'What does the PSR-4 standard define?', '["Autoloading by mapping namespaces to file paths","A coding style guide","An HTTP message interface","A logging interface"]'::jsonb, 0, 'PSR-4 specifies how fully-qualified class names map to file paths for autoloading (used by Composer).'),
  ('PHP', 'Languages', 'high', 'What does `array_map` return?', '["A new array with the callback applied to each element","The original array, mutated","A single reduced value","A boolean"]'::jsonb, 0, '`array_map` returns a new array of transformed elements without modifying the source.'),
  ('PHP', 'Languages', 'ultra', 'How are objects passed to functions in PHP?', '["By handle — the same object is referenced, not deep-copied","Always deep-copied by value","Always by reference variable","As serialized strings"]'::jsonb, 0, 'PHP passes an object handle by value, so the callee operates on the same underlying object (not a clone).'),
  ('PHP', 'Languages', 'ultra', 'What does a Generator (using `yield`) enable?', '["Lazy iteration without building the whole array in memory","Parallel execution","Compile-time evaluation","Automatic caching"]'::jsonb, 0, 'Generators produce values on demand, ideal for large or infinite sequences.'),
  ('PHP', 'Languages', 'ultra', 'What does the `__invoke` magic method allow?', '["Calling an object instance as if it were a function","Cloning an object","Serializing an object","Comparing two objects"]'::jsonb, 0, 'Defining `__invoke()` makes instances callable: `$obj(...)`.'),
  ('PHP', 'Languages', 'ultra', 'What do Fibers (PHP 8.1) provide?', '["Interruptible full-stack functions for cooperative multitasking","OS-level threads","A new array type","Compile-time templates"]'::jsonb, 0, 'Fibers let code suspend and resume an entire call stack, underpinning async runtimes.'),
  ('PHP', 'Languages', 'ultra', 'What does OPcache do?', '["Caches precompiled script bytecode to skip recompilation","Caches HTTP responses","Stores session data","Minifies output"]'::jsonb, 0, 'OPcache stores compiled opcodes in shared memory, avoiding recompiling PHP on every request.'),
  ('C++', 'Languages', 'easy', 'Which operator accesses a member through a pointer?', '["->",".","::","*"]'::jsonb, 0, '`ptr->member` dereferences and accesses; `.` is for objects/references.'),
  ('C++', 'Languages', 'easy', 'What does `std::cout` do?', '["Writes to standard output","Reads from standard input","Allocates memory","Throws an exception"]'::jsonb, 0, '`std::cout` is the standard output stream, used with `<<`.'),
  ('C++', 'Languages', 'easy', 'Which header provides `std::vector`?', '["<vector>","<array>","<list>","<string>"]'::jsonb, 0, '`std::vector` lives in the `<vector>` header.'),
  ('C++', 'Languages', 'easy', 'Which keyword declares a compile-time-unchangeable value?', '["const","final","let","readonly"]'::jsonb, 0, '`const` declares a value that can''t be modified after initialization.'),
  ('C++', 'Languages', 'easy', 'What does `#include` do?', '["Textually inserts the contents of a header","Links a library at runtime","Imports a module namespace","Declares a macro"]'::jsonb, 0, 'The preprocessor replaces `#include` with the named file''s contents before compilation.'),
  ('C++', 'Languages', 'mid', 'What is RAII?', '["Tying resource lifetime to object lifetime","A reference-counting allocator","A runtime assertion macro","A threading model"]'::jsonb, 0, 'Resource Acquisition Is Initialization: acquire in the constructor, release in the destructor, so cleanup is automatic.'),
  ('C++', 'Languages', 'mid', 'How does a reference differ from a pointer?', '["A reference can''t be null or reseated after binding","A reference can point anywhere","A reference takes more memory","A pointer can''t be reassigned"]'::jsonb, 0, 'References must bind to an object at initialization and can''t be rebound; pointers can be null and reassigned.'),
  ('C++', 'Languages', 'mid', 'What ownership does `std::unique_ptr` express?', '["Exclusive ownership of a heap resource","Shared ownership","No ownership (just a view)","Weak ownership"]'::jsonb, 0, '`unique_ptr` is move-only and owns its resource exclusively, freeing it on destruction.'),
  ('C++', 'Languages', 'mid', 'What does a trailing `const` on a member function mean?', '["The method won''t modify the object''s observable state","The return value is const","The method is static","The method can''t be overridden"]'::jsonb, 0, '`void f() const;` promises not to modify the object, so it''s callable on const instances.'),
  ('C++', 'Languages', 'mid', 'How do stack and heap allocation differ?', '["Stack is automatic/scoped; heap is manual/dynamic","Heap is always faster","Stack objects never have destructors","Heap memory frees itself automatically"]'::jsonb, 0, 'Stack objects are freed when scope ends; heap memory (new/delete or smart pointers) is managed explicitly.'),
  ('C++', 'Languages', 'high', 'What do move semantics enable?', '["Transferring resources from an rvalue to avoid copies","Sharing memory between threads","Garbage collection","Implicit type conversion"]'::jsonb, 0, 'Move constructors/assignment steal an expiring object''s resources (via `std::move`) instead of copying.'),
  ('C++', 'Languages', 'high', 'What is the rule of five about?', '["If you define one of the five special members, you likely need all five","Five levels of inheritance max","Five-argument constructors","Five-byte alignment"]'::jsonb, 0, 'The destructor, copy/move constructors, and copy/move assignment usually need to be defined together for correct resource handling.'),
  ('C++', 'Languages', 'high', 'Why declare a base class destructor `virtual`?', '["So deleting through a base pointer destroys the derived object correctly","To allow copying","To make the class abstract","To enable templates"]'::jsonb, 0, 'Without a virtual destructor, `delete basePtr` on a derived object is undefined behavior.'),
  ('C++', 'Languages', 'high', 'How do `std::vector` and `std::list` differ structurally?', '["vector is contiguous (random access); list is node-based (fast splice)","Both are contiguous","list supports random access in O(1)","vector cannot grow"]'::jsonb, 0, 'vector stores elements contiguously for O(1) indexing; list is a doubly-linked list with O(1) splice but no random access.'),
  ('C++', 'Languages', 'high', 'How does `std::shared_ptr` track lifetime?', '["Reference counting via a control block","A garbage collector","Stack scoping","A global registry of pointers"]'::jsonb, 0, 'shared_ptr keeps a reference count; the resource is freed when the count reaches zero.'),
  ('C++', 'Languages', 'ultra', 'What breaks a reference cycle between two `shared_ptr`s?', '["Using std::weak_ptr for one side","Calling delete manually","Resetting both at once","Nothing — cycles free automatically"]'::jsonb, 0, 'shared_ptr cycles leak because counts never hit zero; weak_ptr observes without owning, breaking the cycle.'),
  ('C++', 'Languages', 'ultra', 'What does `constexpr` enable?', '["Evaluation at compile time","Lazy runtime evaluation","Thread-local storage","Implicit narrowing"]'::jsonb, 0, '`constexpr` allows values/functions to be evaluated during compilation when given constant inputs.'),
  ('C++', 'Languages', 'ultra', 'What is undefined behavior?', '["A program construct for which the standard imposes no requirements","A compiler warning","A caught exception","A deprecated feature"]'::jsonb, 0, 'UB (e.g. signed overflow, out-of-bounds access) means the standard guarantees nothing — the compiler may do anything.'),
  ('C++', 'Languages', 'ultra', 'What does SFINAE stand for?', '["Substitution Failure Is Not An Error","Static Function Inlining And Naming Extension","Safe Function Invocation And Error","StandardForm Integer Numeric Expression"]'::jsonb, 0, 'When template argument substitution fails, that candidate is removed from overload resolution rather than causing a hard error.'),
  ('C++', 'Languages', 'ultra', 'How do `std::map` and `std::unordered_map` differ?', '["map is an ordered balanced tree (O(log n)); unordered_map is a hash table (avg O(1))","Both are hash tables","unordered_map keeps keys sorted","map has O(1) lookup"]'::jsonb, 0, 'map keeps keys sorted via a balanced BST; unordered_map hashes keys for average constant-time access, unordered.'),
  ('App Store / Play Store', 'Mobile Delivery', 'easy', 'What is Apple''s app marketplace?', '["The App Store","Google Play","TestFlight","Xcode"]'::jsonb, 0, 'iOS apps are distributed through the App Store.'),
  ('App Store / Play Store', 'Mobile Delivery', 'easy', 'What is Google''s app marketplace?', '["Google Play (Play Store)","The App Store","Firebase","Play Console only"]'::jsonb, 0, 'Android apps are distributed via Google Play.'),
  ('App Store / Play Store', 'Mobile Delivery', 'easy', 'What account is required to publish on iOS?', '["An Apple Developer account","A Google account","A GitHub account","A Firebase project"]'::jsonb, 0, 'Publishing to the App Store requires an Apple Developer Program membership.'),
  ('App Store / Play Store', 'Mobile Delivery', 'easy', 'What is Apple''s beta distribution tool?', '["TestFlight","Play Console","Firebase App Distribution","Xcode Cloud"]'::jsonb, 0, 'TestFlight distributes pre-release builds to testers.'),
  ('App Store / Play Store', 'Mobile Delivery', 'easy', 'What is the Play Console?', '["Google''s app management/publishing dashboard","An Android emulator","A build tool","A crash reporter only"]'::jsonb, 0, 'The Play Console is where you manage Android releases, listings, and metrics.'),
  ('App Store / Play Store', 'Mobile Delivery', 'mid', 'What format does Google Play prefer for uploads?', '["AAB (Android App Bundle)","APK only","IPA","ZIP"]'::jsonb, 0, 'Play uses the AAB to generate optimized APKs per device.'),
  ('App Store / Play Store', 'Mobile Delivery', 'mid', 'What are the App Store Review Guidelines for?', '["Rules an app must follow to be approved","Marketing copy templates","Pricing tiers","Crash reports"]'::jsonb, 0, 'Apps must comply with Apple''s guidelines to pass review.'),
  ('App Store / Play Store', 'Mobile Delivery', 'mid', 'What is a staged/phased rollout?', '["Releasing to a growing percentage of users gradually","Releasing to everyone at once","A beta-only release","A rollback"]'::jsonb, 0, 'Phased rollouts limit exposure so issues can be caught early.'),
  ('App Store / Play Store', 'Mobile Delivery', 'mid', 'What is a bundle identifier / application id?', '["A unique app id like com.company.app","The app''s version number","The signing key","The store URL"]'::jsonb, 0, 'The unique identifier distinguishes your app on the platform.'),
  ('App Store / Play Store', 'Mobile Delivery', 'mid', 'What reviews iOS apps before release?', '["Apple''s App Review","Google Play Protect","TestFlight","The CI pipeline"]'::jsonb, 0, 'App Review evaluates submissions against the guidelines.'),
  ('App Store / Play Store', 'Mobile Delivery', 'high', 'Why does iOS require code signing?', '["To ensure app integrity and authenticity via certificates/provisioning","To compress the binary","To enable dark mode","To speed up downloads"]'::jsonb, 0, 'Signing proves the app''s origin and that it hasn''t been tampered with.'),
  ('App Store / Play Store', 'Mobile Delivery', 'high', 'What is the advantage of an AAB over a universal APK?', '["Play generates smaller, per-device optimized APKs","It runs on iOS too","It needs no signing","It skips review"]'::jsonb, 0, 'Dynamic Delivery ships only the code/resources each device needs.'),
  ('App Store / Play Store', 'Mobile Delivery', 'high', 'What is a common iOS rejection reason?', '["Guideline violations (privacy, broken features, metadata)","Using Swift","Having too few screenshots","Using TestFlight"]'::jsonb, 0, 'Privacy issues, crashes, and misleading metadata frequently cause rejections.'),
  ('App Store / Play Store', 'Mobile Delivery', 'high', 'What does a phased rollout let you do if metrics regress?', '["Halt or roll back before reaching all users","Force-update every device","Skip review","Refund automatically"]'::jsonb, 0, 'You can pause/halt the rollout when crash or rating signals worsen.'),
  ('App Store / Play Store', 'Mobile Delivery', 'high', 'What are privacy nutrition labels / Data safety sections?', '["Disclosures of what data the app collects and how it''s used","Performance benchmarks","Pricing details","Screenshots"]'::jsonb, 0, 'Both stores require declaring data collection and usage to users.'),
  ('App Store / Play Store', 'Mobile Delivery', 'ultra', 'Why can app review delay releases, and how do you plan for it?', '["Human review adds variable latency; build buffer time and use beta tracks","Review is instant; no planning needed","Reviews never reject","Only Android has review"]'::jsonb, 0, 'Review times vary, so schedule buffers and validate via TestFlight/internal tracks first.'),
  ('App Store / Play Store', 'Mobile Delivery', 'ultra', 'How does Play''s Dynamic Delivery reduce download size?', '["It serves only the code/resources needed for each device configuration","It compresses the whole APK once","It removes all assets","It streams the app live"]'::jsonb, 0, 'From the AAB, Play builds device-specific APKs (by density, ABI, language).'),
  ('App Store / Play Store', 'Mobile Delivery', 'ultra', 'How do staged rollout plus release vitals control risk?', '["Expose gradually while watching crash/ANR vitals, halting on regression","Release to all and hope","Skip monitoring","Only test internally"]'::jsonb, 0, 'Monitoring vitals during a gradual rollout lets you stop a bad release early.'),
  ('App Store / Play Store', 'Mobile Delivery', 'ultra', 'Why are OTA updates (e.g. Expo Updates/CodePush) limited by store policy?', '["Only JS/asset changes are allowed; native changes need a store submission","OTA is fully unrestricted","OTA replaces the binary entirely","Stores ban all OTA"]'::jsonb, 0, 'Stores permit pushing JS/asset bug fixes but not changing native code/behavior out of band.'),
  ('App Store / Play Store', 'Mobile Delivery', 'ultra', 'Why separate build number from marketing version?', '["To avoid upload conflicts and user-facing confusion across releases","To reduce app size","To skip signing","To bypass review"]'::jsonb, 0, 'Stores require an ever-incrementing build number, while the marketing version (e.g. 2.1.0) is what users see.'),
  ('Application Insights', 'Monitoring', 'easy', 'What is Application Insights?', '["An APM service within Azure Monitor","A container runtime","A CI server","A database"]'::jsonb, 0, 'Application Insights collects application telemetry for performance and failure analysis.'),
  ('Application Insights', 'Monitoring', 'easy', 'What does it primarily collect?', '["Telemetry like requests, dependencies, and exceptions","Source code","Container images","DNS records"]'::jsonb, 0, 'It gathers requests, dependency calls, exceptions, and custom events.'),
  ('Application Insights', 'Monitoring', 'easy', 'Which query language does it use?', '["KQL","SQL only","GraphQL","PromQL"]'::jsonb, 0, 'You analyze its data with Kusto Query Language (KQL).'),
  ('Application Insights', 'Monitoring', 'easy', 'What is an availability test?', '["A synthetic uptime/ping check","A unit test","A load test only","A security scan"]'::jsonb, 0, 'Availability tests probe endpoints from multiple locations to track uptime.'),
  ('Application Insights', 'Monitoring', 'easy', 'What does it help you diagnose?', '["Performance issues and failures","CSS bugs","Compilation errors","Merge conflicts"]'::jsonb, 0, 'It surfaces slow operations, errors, and dependency problems in production.'),
  ('Application Insights', 'Monitoring', 'mid', 'What is distributed tracing?', '["Correlating a request across services via a shared operation id","Logging to one file","Tracing CSS rules","Profiling a single function"]'::jsonb, 0, 'It ties together telemetry from multiple components handling one request.'),
  ('Application Insights', 'Monitoring', 'mid', 'What does dependency tracking record?', '["Outbound calls (DB, HTTP) and their durations","CPU temperature","Source commits","User passwords"]'::jsonb, 0, 'It captures calls to databases, services, and external APIs with timing.'),
  ('Application Insights', 'Monitoring', 'mid', 'What is Live Metrics?', '["A near-real-time stream of telemetry","A static report","A billing dashboard","A log archive"]'::jsonb, 0, 'Live Metrics shows incoming telemetry with sub-second latency.'),
  ('Application Insights', 'Monitoring', 'mid', 'What is the purpose of sampling?', '["Reduce telemetry volume/cost while staying representative","Encrypt telemetry","Speed up queries only","Add more events"]'::jsonb, 0, 'Sampling keeps a representative subset to control ingestion and cost.'),
  ('Application Insights', 'Monitoring', 'mid', 'How are metrics different from traces/logs?', '["Metrics are aggregated numbers; traces/logs are per-event records","Metrics store full requests","Logs are numeric only","They are identical"]'::jsonb, 0, 'Metrics summarize; traces/logs capture individual events for deep diagnosis.'),
  ('Application Insights', 'Monitoring', 'high', 'How does cross-service correlation work?', '["A shared operation/trace id is propagated in headers","By matching timestamps only","By IP address","By user agent"]'::jsonb, 0, 'Context propagation carries the trace id so telemetry can be joined end to end.'),
  ('Application Insights', 'Monitoring', 'high', 'What does adaptive sampling do?', '["Dynamically adjusts the sample rate toward a target volume","Samples nothing","Doubles all events","Encrypts data"]'::jsonb, 0, 'It tunes the rate automatically to hit a configured items-per-second target.'),
  ('Application Insights', 'Monitoring', 'high', 'What does the Application Map show?', '["Service topology with health and latency between components","Source file structure","A billing breakdown","Network firewall rules"]'::jsonb, 0, 'The map visualizes service dependencies and their performance/error rates.'),
  ('Application Insights', 'Monitoring', 'high', 'Why configure a daily ingestion cap?', '["To control ingestion cost","To speed up the app","To improve accuracy","To enable tracing"]'::jsonb, 0, 'A cap limits how much telemetry is ingested (and billed) per day.'),
