  ('Application Insights', 'Monitoring', 'ultra', 'Why can sampling distort rare events?', '["Infrequent events may be dropped, skewing diagnostics","It duplicates them","It always keeps them","It encrypts them"]'::jsonb, 0, 'Uniform sampling can miss low-frequency events; rule-based sampling keeps errors.'),
  ('Application Insights', 'Monitoring', 'ultra', 'How can you cut noise without losing error fidelity?', '["Sample successful requests but always keep failures","Sample everything equally","Turn off telemetry","Index all logs"]'::jsonb, 0, 'Rule-based/ingestion sampling can retain 100% of errors while thinning successes.'),
  ('Application Insights', 'Monitoring', 'ultra', 'What''s the tradeoff of high-cardinality custom dimensions?', '["Indexing many unique values raises cost and slows queries","It improves accuracy for free","It reduces storage","It has no effect"]'::jsonb, 0, 'Too many distinct dimension values explode storage/query cost.'),
  ('Application Insights', 'Monitoring', 'ultra', 'What does ingestion latency affect?', '["How quickly dashboards and alerts reflect reality","The app''s response time","Build duration","Disk usage on the host"]'::jsonb, 0, 'Delay between an event and its availability impacts alert/dashboard freshness.'),
