  ('KQL', 'Monitoring', 'high', 'What does materialize() optimize?', '["Caches a subquery result reused multiple times","Sorts large tables","Encrypts output","Limits rows"]'::jsonb, 0, 'materialize avoids recomputing a subquery referenced more than once.'),
