  ('KQL', 'Monitoring', 'ultra', 'How does filtering before a join improve performance?', '["Fewer rows are shuffled and scanned during the join","It changes the join type","It removes the need for keys","It encrypts the data"]'::jsonb, 0, 'Reducing both sides before joining lowers the work and data movement.'),
