  ('LaunchDarkly', 'Monitoring', 'high', 'What does streaming flag updates provide?', '["Near-instant flag changes without polling","Cheaper storage","Faster builds","More variations"]'::jsonb, 0, 'SDKs receive pushed updates so changes take effect immediately.'),
