  ('Playwright (E2E)', 'Testing', 'easy', 'What is Playwright?', '["An end-to-end browser automation/testing framework","A unit test runner only","A bundler","A linter"]'::jsonb, 0, 'Playwright drives real browsers to test apps end to end.'),
