  ('Playwright (E2E)', 'Testing', 'easy', 'What is an end-to-end (E2E) test?', '["A test exercising the app through the UI like a user","A test of one function","A type check","A lint rule"]'::jsonb, 0, 'E2E tests validate full user flows across the real stack.'),
  ('Playwright (E2E)', 'Testing', 'easy', 'What does page.goto() do?', '["Navigates to a URL","Clicks a button","Asserts text","Takes a screenshot"]'::jsonb, 0, 'goto loads the given URL in the page.'),
  ('Playwright (E2E)', 'Testing', 'easy', 'What does a locator represent?', '["A way to find an element on the page","A network request","A test report","A browser tab"]'::jsonb, 0, 'Locators describe how to find and act on elements.'),
  ('Playwright (E2E)', 'Testing', 'mid', 'What do Playwright''s auto-waits do?', '["Wait for elements to be actionable before interacting","Add fixed sleeps","Disable retries","Mock the network"]'::jsonb, 0, 'Actions wait until elements are visible/enabled, reducing flakiness.'),
  ('Playwright (E2E)', 'Testing', 'mid', 'What is a recommended locator strategy?', '["User-facing queries like role/text/test-id","Deeply nested CSS selectors","XPath by index","Random ids"]'::jsonb, 0, 'Resilient, user-facing locators survive markup changes.'),
  ('Playwright (E2E)', 'Testing', 'mid', 'What does the trace viewer provide?', '["A recorded timeline to debug test failures","A coverage report","A lint summary","A bundle analysis"]'::jsonb, 0, 'Traces capture snapshots, actions, and network for post-mortem debugging.'),
  ('Playwright (E2E)', 'Testing', 'mid', 'How does Playwright isolate tests?', '["A fresh browser context per test","Sharing one global session","Reusing cookies across tests","A single tab for all"]'::jsonb, 0, 'Each test gets an isolated context (cookies/storage), like a clean incognito session.'),
  ('Playwright (E2E)', 'Testing', 'mid', 'What is a fixture in Playwright?', '["Reusable setup provided to tests","A CSS class","A network mock only","A screenshot"]'::jsonb, 0, 'Fixtures supply prepared objects (page, auth, data) to tests.'),
  ('Playwright (E2E)', 'Testing', 'high', 'Why do auto-waits reduce flakiness?', '["They retry until the element is ready instead of using fixed sleeps","They skip slow steps","They mock timing","They run tests twice"]'::jsonb, 0, 'Waiting on actionability avoids race conditions from hardcoded delays.'),
  ('Playwright (E2E)', 'Testing', 'high', 'What is the benefit of browser contexts?', '["Fast, isolated sessions without launching a new browser","Slower but safer tests","Shared state across tests","Real device emulation only"]'::jsonb, 0, 'Contexts are cheap, isolated profiles within one browser process.'),
  ('Playwright (E2E)', 'Testing', 'high', 'What does a web-first assertion (expect) do?', '["Auto-retries until the condition holds or it times out","Asserts once immediately","Mocks the DOM","Logs to console"]'::jsonb, 0, 'Playwright''s expect polls the condition, smoothing over async UI updates.'),
  ('Playwright (E2E)', 'Testing', 'high', 'Why prefer getByRole over CSS selectors?', '["It''s resilient to markup changes and accessibility-aligned","It''s shorter to type","It''s faster to execute","It avoids waiting"]'::jsonb, 0, 'Role-based queries reflect how users/AT perceive the UI and resist refactors.'),
  ('Playwright (E2E)', 'Testing', 'high', 'How does Playwright run tests in parallel?', '["Multiple workers run spec files concurrently","It runs everything serially","It clones the browser per assertion","It can''t parallelize"]'::jsonb, 0, 'Workers execute different spec files at once for speed.'),
  ('Playwright (E2E)', 'Testing', 'ultra', 'What is the root cause of E2E flakiness, and Playwright''s mitigation?', '["Timing/race conditions; mitigated by auto-waiting and retrying assertions","Slow CPUs; mitigated by sleeps","Bad CSS; mitigated by XPath","Network only; mitigated by caching"]'::jsonb, 0, 'Most flakiness is timing-related; auto-waits and web-first assertions address it.'),
  ('Playwright (E2E)', 'Testing', 'ultra', 'How does sharding speed up large E2E suites?', '["It splits specs across machines/workers to run in parallel","It deletes slow tests","It mocks everything","It runs once a day"]'::jsonb, 0, 'Sharding distributes the suite so total wall-clock time drops.'),
  ('Playwright (E2E)', 'Testing', 'ultra', 'What does network interception/mocking enable?', '["Deterministic tests by stubbing API responses","Faster CSS","Real payments","Bigger screenshots"]'::jsonb, 0, 'Mocking responses removes backend variability for stable tests.'),
  ('Playwright (E2E)', 'Testing', 'ultra', 'Why is a test-id sometimes needed despite role/text queries?', '["Dynamic or ambiguous content needs a stable hook","Role queries never work","It''s faster","CSS is forbidden"]'::jsonb, 0, 'When accessible queries are ambiguous, a dedicated test-id gives stability.'),
  ('Playwright (E2E)', 'Testing', 'ultra', 'What is the tradeoff of E2E versus unit tests?', '["Higher realism/confidence but slower, costlier, and more brittle","Always faster","Lower confidence","No setup needed"]'::jsonb, 0, 'E2E covers real flows but is heavier; balance with cheaper unit tests (the test pyramid).'),
  ('Jest', 'Testing', 'easy', 'What is Jest?', '["A JavaScript testing framework","A bundler","A linter","A browser"]'::jsonb, 0, 'Jest runs JS/TS tests with assertions, mocks, and coverage.'),
  ('Jest', 'Testing', 'easy', 'Which function defines a single test?', '["test() / it()","describe()","expect()","run()"]'::jsonb, 0, 'test (alias it) declares an individual test case.'),
  ('Jest', 'Testing', 'easy', 'What groups related tests?', '["describe()","test()","expect()","mock()"]'::jsonb, 0, 'describe blocks organize related tests.'),
  ('Jest', 'Testing', 'easy', 'What makes an assertion?', '["expect()","assert()","check()","verify()"]'::jsonb, 0, 'expect(value).matcher() asserts expectations.'),
  ('Jest', 'Testing', 'easy', 'What runs setup before each test?', '["beforeEach()","afterAll()","describe()","setup()"]'::jsonb, 0, 'beforeEach runs prior to every test in scope.'),
  ('Jest', 'Testing', 'mid', 'What is a mock?', '["A stand-in that records calls and returns controlled values","A real dependency","A snapshot file","A coverage report"]'::jsonb, 0, 'Mocks replace dependencies to isolate the unit under test.'),
  ('Jest', 'Testing', 'mid', 'What does jest.fn() create?', '["A mock function","A test suite","A timer","A snapshot"]'::jsonb, 0, 'jest.fn() makes a tracked mock function.'),
  ('Jest', 'Testing', 'mid', 'What is a snapshot test?', '["It compares output against a stored snapshot","It measures performance","It mocks the network","It checks types"]'::jsonb, 0, 'Snapshots record serialized output and flag changes on later runs.'),
  ('Jest', 'Testing', 'mid', 'How do toBe and toEqual differ?', '["toBe checks reference/primitive identity; toEqual checks deep equality","They are identical","toEqual is for numbers only","toBe does deep equality"]'::jsonb, 0, 'Use toEqual for objects/arrays; toBe uses Object.is.'),
  ('Jest', 'Testing', 'mid', 'What does jest.mock() do?', '["Replaces a module with a mock implementation","Runs tests in parallel","Generates coverage","Creates snapshots"]'::jsonb, 0, 'jest.mock intercepts a module so tests control its behavior.'),
  ('Jest', 'Testing', 'high', 'Why prefer toEqual over toBe for objects?', '["toBe compares references; objects need deep structural equality","toBe is deprecated","toEqual is faster","toBe ignores nulls"]'::jsonb, 0, 'Two distinct objects with equal contents fail toBe but pass toEqual.'),
  ('Jest', 'Testing', 'high', 'What do fake timers enable?', '["Controlling setTimeout/Date in tests","Faster CPUs","Network mocking","Parallel runs"]'::jsonb, 0, 'Fake timers let you advance time deterministically without real delays.'),
  ('Jest', 'Testing', 'high', 'How do you test async code in Jest?', '["async/await with resolves/rejects matchers","Only with setTimeout","By disabling promises","It can''t be tested"]'::jsonb, 0, 'Await the promise or use expect(...).resolves/.rejects.'),
  ('Jest', 'Testing', 'high', 'What does code coverage measure?', '["Which lines/branches executed during tests","Whether assertions are meaningful","Performance","Bundle size"]'::jsonb, 0, 'Coverage reports executed code, not the quality of assertions.'),
  ('Jest', 'Testing', 'high', 'What is a risk of snapshot tests?', '["Large or blindly-updated snapshots hide real regressions","They are too strict","They can''t fail","They run slowly always"]'::jsonb, 0, 'Auto-updating big snapshots can mask meaningful changes.'),
  ('Jest', 'Testing', 'ultra', 'Why can high coverage still miss bugs?', '["It measures execution, not assertion quality or untested edge cases","It always finds bugs","Coverage equals correctness","It only counts comments"]'::jsonb, 0, 'Running a line doesn''t mean its behavior was meaningfully asserted.'),
  ('Jest', 'Testing', 'ultra', 'What is the danger of over-mocking?', '["Tests pass while real integration breaks","Tests run slower","Coverage drops","Mocks can''t return values"]'::jsonb, 0, 'Mocking too much tests the mocks, not the actual interactions.'),
  ('Jest', 'Testing', 'ultra', 'How do you avoid flaky time-based tests?', '["Use fake timers and deterministic clocks","Add longer real sleeps","Retry until green","Disable the tests"]'::jsonb, 0, 'Controlling time removes nondeterminism from timeouts/intervals.'),
  ('Jest', 'Testing', 'ultra', 'Why isolate tests from shared state?', '["To avoid order-dependent failures and false passes","To run slower","To reduce coverage","To share mocks"]'::jsonb, 0, 'Leaked state causes tests to pass/fail based on execution order.'),
  ('Jest', 'Testing', 'ultra', 'What does module mocking risk over time?', '["Drift from the real module''s actual behavior","Faster builds","Better coverage","Fewer tests"]'::jsonb, 0, 'Mocks can grow stale versus the real implementation, masking breakage.'),
  ('React Testing Library', 'Testing', 'easy', 'What is React Testing Library (RTL)?', '["A library to test React components from the user''s perspective","A state manager","A bundler","A router"]'::jsonb, 0, 'RTL encourages testing rendered behavior rather than internals.'),
  ('React Testing Library', 'Testing', 'easy', 'What does RTL query against?', '["The rendered DOM","Component source code","Redux state","The network"]'::jsonb, 0, 'Queries find elements in the DOM the user would see.'),
  ('React Testing Library', 'Testing', 'easy', 'What does render() do?', '["Mounts a component for testing","Builds the app","Starts a server","Creates a snapshot"]'::jsonb, 0, 'render mounts the component into a test container.'),
  ('React Testing Library', 'Testing', 'easy', 'What does screen.getByText do?', '["Finds an element by its visible text","Logs to console","Mocks a module","Sets state"]'::jsonb, 0, 'getByText locates an element containing the given text.'),
  ('React Testing Library', 'Testing', 'easy', 'What do fireEvent/userEvent do?', '["Simulate user interactions","Render components","Mock fetch","Assert values"]'::jsonb, 0, 'They dispatch events like clicks and typing.'),
  ('React Testing Library', 'Testing', 'mid', 'What is RTL''s guiding principle?', '["Test behavior as users experience it, not implementation","Test private methods","Maximize snapshots","Mock everything"]'::jsonb, 0, 'The more tests resemble real usage, the more confidence they give.'),
  ('React Testing Library', 'Testing', 'mid', 'Why prefer getByRole?', '["It uses accessible, resilient queries","It is the only option","It is fastest","It ignores text"]'::jsonb, 0, 'Role queries align with accessibility and survive markup changes.'),
  ('React Testing Library', 'Testing', 'mid', 'What does findBy* return?', '["A promise that waits for the element (async)","A synchronous element always","Null if missing","An array always"]'::jsonb, 0, 'findBy queries retry until the element appears, for async UI.'),
  ('React Testing Library', 'Testing', 'mid', 'How do getBy and queryBy differ?', '["getBy throws if missing; queryBy returns null","They are identical","queryBy throws; getBy returns null","Both return arrays"]'::jsonb, 0, 'Use queryBy to assert absence without throwing.'),
  ('React Testing Library', 'Testing', 'mid', 'Why avoid testing internal component state directly?', '["It couples tests to implementation details","It''s impossible","It''s slower","It needs mocks"]'::jsonb, 0, 'Testing state ties tests to internals, breaking on refactors.'),
  ('React Testing Library', 'Testing', 'high', 'Why prefer userEvent over fireEvent?', '["It simulates realistic interaction sequences (focus, key events)","It is synchronous only","It mocks the DOM","It is deprecated"]'::jsonb, 0, 'userEvent mimics real user behavior more faithfully than raw events.'),
  ('React Testing Library', 'Testing', 'high', 'What does waitFor do?', '["Retries an assertion until it passes or times out","Adds a fixed delay","Mocks timers","Renders twice"]'::jsonb, 0, 'waitFor polls for async UI changes to settle.'),
  ('React Testing Library', 'Testing', 'high', 'Why is querying by test-id a last resort?', '["Accessible/text queries are preferred; test-id is a fallback","It is forbidden","It is slowest","It can''t be used in CI"]'::jsonb, 0, 'Prefer queries users/AT rely on; use test-id only when needed.'),
  ('React Testing Library', 'Testing', 'high', 'What is the anti-pattern of testing implementation details?', '["Brittle tests that break on refactors despite stable behavior","Faster tests","Higher coverage","Fewer mocks"]'::jsonb, 0, 'Coupling to internals makes safe refactors fail tests.'),
  ('React Testing Library', 'Testing', 'high', 'What does RTL discourage you from accessing?', '["Component instances and internal state","The DOM","Button text","ARIA roles"]'::jsonb, 0, 'RTL has no API for instance internals on purpose.'),
  ('React Testing Library', 'Testing', 'ultra', 'Why does RTL favor accessible queries philosophically?', '["Tests double as accessibility checks and resist refactor breakage","They are the fastest","They need no setup","They mock the DOM"]'::jsonb, 0, 'Querying like assistive tech improves both a11y and test resilience.'),
  ('React Testing Library', 'Testing', 'ultra', 'What causes act() warnings, and how do you fix them?', '["State updates outside React''s batching; await async updates (findBy/waitFor)","Too many renders; reduce components","Missing snapshots; add them","Slow CPUs; upgrade hardware"]'::jsonb, 0, 'Unwrapped async state changes trigger act warnings; await the UI to settle.'),
  ('React Testing Library', 'Testing', 'ultra', 'How do you assert something does NOT appear?', '["queryBy with expect(...).toBeNull or waitForElementToBeRemoved","getBy and catch the throw","render twice","snapshot it"]'::jsonb, 0, 'queryBy returns null for absent elements without throwing.'),
  ('React Testing Library', 'Testing', 'ultra', 'Why does testing implementation make refactors painful?', '["Tests fail on internal changes even when behavior is unchanged","Refactors are impossible","It improves coverage","Tests run slower"]'::jsonb, 0, 'Behavior-focused tests stay green through refactors; internal-focused ones don''t.'),
  ('React Testing Library', 'Testing', 'ultra', 'What is the tradeoff of integration-style component tests?', '["More confidence but slower with more setup than pure unit tests","Less confidence","No setup needed","They can''t fail"]'::jsonb, 0, 'Rendering real component trees catches more but costs more than isolated units.'),
  ('TDD', 'Testing', 'easy', 'What does TDD stand for?', '["Test-Driven Development","Type-Driven Design","Total Defect Detection","Test Data Definition"]'::jsonb, 0, 'TDD = Test-Driven Development.'),
  ('TDD', 'Testing', 'easy', 'What is the TDD cycle?', '["Red, green, refactor","Plan, build, ship","Write, deploy, test","Mock, run, assert"]'::jsonb, 0, 'Write a failing test (red), make it pass (green), then refactor.'),
  ('TDD', 'Testing', 'easy', 'What comes first in TDD?', '["Writing a failing test","Writing the implementation","Refactoring","Deploying"]'::jsonb, 0, 'You write a failing test before the code that satisfies it.'),
  ('TDD', 'Testing', 'easy', 'What does the ''green'' step mean?', '["Make the failing test pass","Delete the test","Refactor everything","Write docs"]'::jsonb, 0, 'Green means implementing just enough to pass the test.'),
  ('TDD', 'Testing', 'easy', 'What does the ''refactor'' step do?', '["Improve the code while keeping tests passing","Add new features","Remove tests","Rewrite from scratch"]'::jsonb, 0, 'Refactoring cleans up design under a passing test safety net.'),
  ('TDD', 'Testing', 'mid', 'Why write the test first?', '["It clarifies requirements and ensures the code is testable","It is faster to type","It avoids refactoring","It skips design"]'::jsonb, 0, 'Specifying behavior first drives a clear, testable interface.'),
  ('TDD', 'Testing', 'mid', 'What does the red step verify?', '["That the test actually fails before implementation","That coverage is high","That the build passes","That the code is fast"]'::jsonb, 0, 'Seeing it fail confirms the test is meaningful and wired correctly.'),
  ('TDD', 'Testing', 'mid', 'What design qualities does TDD encourage?', '["Small, decoupled, testable units","Large monolithic functions","Global state","Tight coupling"]'::jsonb, 0, 'Writing tests first nudges code toward modular, injectable designs.'),
  ('TDD', 'Testing', 'mid', 'What is the smallest-step principle?', '["Write just enough code to pass the current test","Implement the whole feature at once","Skip tests for small changes","Refactor before passing"]'::jsonb, 0, 'Tiny increments keep feedback tight and changes safe.'),
  ('TDD', 'Testing', 'mid', 'What does a regression test prevent?', '["Reintroducing a previously fixed bug","Slow builds","Merge conflicts","Type errors"]'::jsonb, 0, 'A test for the bug ensures it can''t silently return.'),
  ('TDD', 'Testing', 'high', 'How does TDD guide design?', '["Writing tests first surfaces awkward APIs and coupling early","It replaces architecture","It removes the need for review","It enforces a framework"]'::jsonb, 0, 'Hard-to-test code signals design problems before they harden.'),
  ('TDD', 'Testing', 'high', 'How does BDD differ from TDD?', '["BDD frames tests as behavior/specs in domain language","BDD skips tests","BDD is only for UI","They are unrelated"]'::jsonb, 0, 'BDD emphasizes behavior described in business-readable scenarios.'),
  ('TDD', 'Testing', 'high', 'Why refactor only when tests are green?', '["A passing suite is a safety net for changing structure","Red tests are faster","It avoids writing code","Green hides bugs"]'::jsonb, 0, 'Refactoring under green ensures behavior stays correct.'),
  ('TDD', 'Testing', 'high', 'What is a risk of testing implementation in TDD?', '["Brittle tests; test behavior/contracts instead","Too much coverage","Slow CI","Fewer commits"]'::jsonb, 0, 'Tests tied to internals break on refactors; assert observable behavior.'),
  ('TDD', 'Testing', 'high', 'What does TDD trade in the short term?', '["Slower initial coding for faster, safer change later","Correctness for speed","Tests for docs","Design for features"]'::jsonb, 0, 'Upfront test effort pays off in maintainability and confidence.'),
  ('TDD', 'Testing', 'ultra', 'Why does TDD reduce debugging time long-term?', '["Defects are caught immediately via a tight feedback loop","It eliminates all bugs","It removes the debugger","It skips edge cases"]'::jsonb, 0, 'Failing fast on small changes localizes problems early.'),
  ('TDD', 'Testing', 'ultra', 'What is the danger of over-specifying mocks in TDD?', '["Tests couple to implementation and resist refactoring","Tests run faster","Coverage drops","Mocks can''t return values"]'::jsonb, 0, 'Strict mock expectations turn into brittle, implementation-bound tests.'),
  ('TDD', 'Testing', 'ultra', 'How does TDD apply to legacy code?', '["Add characterization tests before changing behavior","Rewrite everything first","Skip tests for old code","Delete the legacy module"]'::jsonb, 0, 'Characterization tests pin current behavior so you can refactor safely.'),
  ('TDD', 'Testing', 'ultra', 'Why can TDD fail to prevent design problems?', '["It guides units but doesn''t replace system-level architecture thinking","It tests nothing","It only works for UIs","It forbids refactoring"]'::jsonb, 0, 'Good unit tests don''t guarantee sound overall architecture.'),
  ('TDD', 'Testing', 'ultra', 'What is the core tradeoff of strict TDD?', '["Upfront discipline/cost versus sustained confidence and regression safety","Speed versus color","Coverage versus types","There is none"]'::jsonb, 0, 'It demands rigor early but yields a durable safety net and cleaner design.');
